+codeunit 134919 "ERM Purch. Journal Doc. Amt."
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Purchase Journal] [Document Amount] [Currency]
+    end;
+
+    var
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        Assert: Codeunit Assert;
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure PurchaseJournalDocumentAmountAcceptsThreeDecimalPlaces()
+    var
+        Currency: Record Currency;
+        PurchaseJournal: TestPage "Purchase Journal";
+        AmountWith3Decimals: Decimal;
+    begin
+        // [SCENARIO] Document Amount field in Purchase Journal should accept amounts with 3 decimal places
+        // when a currency with 3 decimal places is selected (e.g., TND currency).
+        // Bug: Document Amount field only allowed 2 decimal places regardless of currency settings.
+        // Fix: Added DecimalPlaces = 0 : 3 property to the Document Amount field.
+
+        // [GIVEN] A currency with 3 decimal places (like TND - Tunisian Dinar)
+        Initialize();
+        CreateCurrencyWithThreeDecimalPlaces(Currency);
+        AmountWith3Decimals := 1.234;
+
+        // [WHEN] Open Purchase Journal and set Currency Code and Document Amount with 3 decimals
+        PurchaseJournal.OpenEdit();
+        PurchaseJournal.New();
+        PurchaseJournal."Currency Code".SetValue(Currency.Code);
+        PurchaseJournal.DocumentAmount.SetValue(AmountWith3Decimals);
+
+        // [THEN] The Document Amount field should accept the value without error
+        // and the Amount field should be set to the negative of Document Amount (for Invoice)
+        Assert.AreEqual(
+            Format(AmountWith3Decimals, 0, '<Precision,3:3><Standard Format,0>'),
+            PurchaseJournal.DocumentAmount.Value,
+            'Document Amount should accept 3 decimal places');
+        
+        PurchaseJournal.Close();
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"ERM Purch. Journal Doc. Amt.");
+
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"ERM Purch. Journal Doc. Amt.");
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateLocalData();
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"ERM Purch. Journal Doc. Amt.");
+    end;
+
+    local procedure CreateCurrencyWithThreeDecimalPlaces(var Currency: Record Currency)
+    begin
+        // Create a currency with 3 decimal places (like TND - Tunisian Dinar)
+        LibraryERM.CreateCurrency(Currency);
+        Currency.Validate("Amount Decimal Places", '3:3');
+        Currency.Validate("Amount Rounding Precision", 0.001);
+        Currency.Modify(true);
+        LibraryERM.CreateRandomExchangeRate(Currency.Code);
+    end;
+}

