+codeunit 148185 "Sustainability Calc Mgt Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        Assert: Codeunit Assert;
+        LibrarySustainability: Codeunit "Library - Sustainability";
+        LibraryERM: Codeunit "Library - ERM";
+
+    [Test]
+    procedure GetCollectableGLAmountReturnsPositiveValueForNegativeGLEntry()
+    var
+        GLAccount: Record "G/L Account";
+        GLEntry: Record "G/L Entry";
+        SustainAccountCategory: Record "Sustain. Account Category";
+        SustainabilityCalcMgt: Codeunit "Sustainability Calc. Mgt.";
+        NegativeAmount: Decimal;
+        CollectedAmount: Decimal;
+    begin
+        // [SCENARIO] GetCollectableGLAmount returns positive (absolute) value even when G/L entries have negative amounts
+        // This is a bug fix test: negative G/L amounts should be converted to positive for sustainability calculations
+
+        // [GIVEN] Clean up before testing
+        LibrarySustainability.CleanUpBeforeTesting();
+
+        // [GIVEN] A G/L Account with a negative balance (like expense accounts with credits)
+        LibraryERM.CreateGLAccount(GLAccount);
+        NegativeAmount := -52818.18; // Negative amount as per the bug report
+
+        // [GIVEN] A G/L Entry with a negative amount
+        CreateGLEntry(GLEntry, GLAccount."No.", NegativeAmount);
+
+        // [GIVEN] A Sustainability Account Category with G/L Account Filter configured to collect from this account
+        SustainAccountCategory := CreateSustainAccountCategoryWithGLFilter(GLAccount."No.");
+
+        // [WHEN] GetCollectableGLAmount is called
+        CollectedAmount := SustainabilityCalcMgt.GetCollectableGLAmount(SustainAccountCategory, 0D, 0D);
+
+        // [THEN] The collected amount should be positive (absolute value of the negative amount)
+        Assert.AreEqual(Abs(NegativeAmount), CollectedAmount, 'Custom Amount from Collect Amount from G/L Entries should always be positive');
+        Assert.IsTrue(CollectedAmount > 0, 'Collected amount must be positive for proper emission calculations');
+    end;
+
+    [Test]
+    procedure GetCollectableGLAmountReturnsPositiveValueForPositiveGLEntry()
+    var
+        GLAccount: Record "G/L Account";
+        GLEntry: Record "G/L Entry";
+        SustainAccountCategory: Record "Sustain. Account Category";
+        SustainabilityCalcMgt: Codeunit "Sustainability Calc. Mgt.";
+        PositiveAmount: Decimal;
+        CollectedAmount: Decimal;
+    begin
+        // [SCENARIO] GetCollectableGLAmount returns positive value for positive G/L entries (no change expected)
+
+        // [GIVEN] Clean up before testing
+        LibrarySustainability.CleanUpBeforeTesting();
+
+        // [GIVEN] A G/L Account with a positive balance
+        LibraryERM.CreateGLAccount(GLAccount);
+        PositiveAmount := 52818.18;
+
+        // [GIVEN] A G/L Entry with a positive amount
+        CreateGLEntry(GLEntry, GLAccount."No.", PositiveAmount);
+
+        // [GIVEN] A Sustainability Account Category with G/L Account Filter configured
+        SustainAccountCategory := CreateSustainAccountCategoryWithGLFilter(GLAccount."No.");
+
+        // [WHEN] GetCollectableGLAmount is called
+        CollectedAmount := SustainabilityCalcMgt.GetCollectableGLAmount(SustainAccountCategory, 0D, 0D);
+
+        // [THEN] The collected amount should still be positive
+        Assert.AreEqual(PositiveAmount, CollectedAmount, 'Positive G/L amounts should remain positive');
+        Assert.IsTrue(CollectedAmount > 0, 'Collected amount must be positive');
+    end;
+
+    local procedure CreateGLEntry(var GLEntry: Record "G/L Entry"; GLAccountNo: Code[20]; Amount: Decimal)
+    var
+        LastEntryNo: Integer;
+    begin
+        GLEntry.Reset();
+        if GLEntry.FindLast() then
+            LastEntryNo := GLEntry."Entry No."
+        else
+            LastEntryNo := 0;
+
+        GLEntry.Init();
+        GLEntry."Entry No." := LastEntryNo + 1;
+        GLEntry."G/L Account No." := GLAccountNo;
+        GLEntry.Amount := Amount;
+        GLEntry."Posting Date" := WorkDate();
+        GLEntry.Insert();
+    end;
+
+    local procedure CreateSustainAccountCategoryWithGLFilter(GLAccountNo: Code[20]): Record "Sustain. Account Category"
+    var
+        SustainAccountCategory: Record "Sustain. Account Category";
+        CategoryCode: Code[20];
+    begin
+        CategoryCode := 'TESTCAT';
+        SustainAccountCategory.Init();
+        SustainAccountCategory.Validate(Code, CategoryCode);
+        SustainAccountCategory.Validate("Emission Scope", Enum::"Emission Scope"::"Scope 3");
+        SustainAccountCategory.Validate("Calculation Foundation", Enum::"Calculation Foundation"::Custom);
+        SustainAccountCategory.Validate("Custom Value", 'Test');
+        SustainAccountCategory.Validate(CO2, true);
+        SustainAccountCategory.Validate("Calculate from General Ledger", true);
+        SustainAccountCategory.Validate("G/L Account Filter", GLAccountNo);
+        SustainAccountCategory.Insert(true);
+        exit(SustainAccountCategory);
+    end;
+}

