+/// <summary>
+/// Tests for Shopify Copy Document functionality.
+/// </summary>
+codeunit 139614 "Shpfy Copy Document Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryRandom: Codeunit "Library - Random";
+        Assert: Codeunit Assert;
+
+    [Test]
+    procedure CopyPostedInvoiceClearsShopifyFields()
+    var
+        SalesInvoiceHeader: Record "Sales Invoice Header";
+        ToSalesHeader: Record "Sales Header";
+        Customer: Record Customer;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        CopyDocumentMgt: Codeunit "Copy Document Mgt.";
+        PostedInvoiceNo: Code[20];
+        ShpfyOrderId: BigInteger;
+        ShpfyOrderNo: Code[50];
+        ShpfyRefundId: BigInteger;
+    begin
+        // [SCENARIO] When copying a posted sales invoice with Shopify fields to a new sales invoice, 
+        // the Shopify Order Id, Shopify Order No., and Shopify Refund Id fields should be cleared.
+
+        // [GIVEN] A posted sales invoice with Shopify fields populated
+        LibrarySales.CreateCustomer(Customer);
+        LibrarySales.CreateSalesInvoiceForCustomerNo(SalesHeader, Customer."No.");
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, LibrarySales.CreateItemNo(), LibraryRandom.RandInt(10));
+
+        ShpfyOrderId := LibraryRandom.RandIntInRange(1000000000, 2000000000);
+        ShpfyOrderNo := CopyStr(LibraryRandom.RandText(50), 1, MaxStrLen(ShpfyOrderNo));
+        ShpfyRefundId := LibraryRandom.RandIntInRange(1000000000, 2000000000);
+
+        SalesHeader."Shpfy Order Id" := ShpfyOrderId;
+        SalesHeader."Shpfy Order No." := ShpfyOrderNo;
+        SalesHeader."Shpfy Refund Id" := ShpfyRefundId;
+        SalesHeader.Modify();
+
+        PostedInvoiceNo := LibrarySales.PostSalesDocument(SalesHeader, false, true);
+
+        // Verify the posted invoice has the Shopify fields
+        SalesInvoiceHeader.Get(PostedInvoiceNo);
+        Assert.AreEqual(ShpfyOrderId, SalesInvoiceHeader."Shpfy Order Id", 'Posted invoice should have Shopify Order Id');
+        Assert.AreEqual(ShpfyOrderNo, SalesInvoiceHeader."Shpfy Order No.", 'Posted invoice should have Shopify Order No.');
+
+        // [WHEN] Copy the posted sales invoice to a new sales invoice with IncludeHeader = true
+        ToSalesHeader.Init();
+        ToSalesHeader."Document Type" := ToSalesHeader."Document Type"::Invoice;
+        ToSalesHeader.Insert(true);
+
+        CopyDocumentMgt.SetProperties(true, false, false, false, false, false, false);
+        CopyDocumentMgt.CopySalesDoc("Sales Document Type From"::"Posted Invoice", PostedInvoiceNo, ToSalesHeader);
+
+        // [THEN] The Shopify fields on the new sales header should be cleared
+        ToSalesHeader.Find();
+        Assert.AreEqual(0, ToSalesHeader."Shpfy Order Id", 'Copied invoice should have Shpfy Order Id cleared');
+        Assert.AreEqual('', ToSalesHeader."Shpfy Order No.", 'Copied invoice should have Shpfy Order No. cleared');
+        Assert.AreEqual(0, ToSalesHeader."Shpfy Refund Id", 'Copied invoice should have Shpfy Refund Id cleared');
+    end;
+}

diff --git a/App/Layers/W1/Tests/VAT/BillToWithShipToAltVATRegTests.Codeunit.al b/App/Layers/W1/Tests/VAT/BillToWithShipToAltVATRegTests.Codeunit.al
