@@ -0,0 +1,132 @@
+codeunit 134239 "BillToWithShipToAltVATRegTests"
+{
+    Subtype = Test;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Alternative Customer VAT Registration] [Bill-to Customer] [Ship-to Address]
+    end;
+
+    var
+        LibraryAltCustVATReg: Codeunit "Library - Alt. Cust. VAT Reg.";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryERM: Codeunit "Library - ERM";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        LibraryLowerPermissions: Codeunit "Library - Lower Permissions";
+        Assert: Codeunit "Assert";
+        IsInitialized: Boolean;
+        ChangeQst: Label 'Do you want to change %1?', Comment = '%1 = change what';
+
+    [Test]
+    [HandlerFunctions('ConfirmHandler,NoNotificationOtherThanShipToAddressSendNotificationHandler')]
+    procedure AltCustVATRegAppliedFromBillToCustomerBasedOnShipToCountry()
+    var
+        GeneralLedgerSetup: Record "General Ledger Setup";
+        SellToCustomer: Record Customer;
+        BillToCustomer: Record Customer;
+        ShipToAddress: Record "Ship-to Address";
+        AltCustVATReg: Record "Alt. Cust. VAT Reg.";
+        SalesHeader: Record "Sales Header";
+        ShipToCountryCode: Code[10];
+    begin
+        // [SCENARIO] When Bill-to Customer has Alternative VAT Registration for the Ship-to Country,
+        // [SCENARIO] changing Bill-to Customer should apply the Alternative VAT Registration.
+
+        Initialize();
+        // [GIVEN] "Bill-to/Sell-to VAT Calc." = "Bill-to/Pay-to No." in the General Ledger Setup
+        GeneralLedgerSetup.Get();
+        GeneralLedgerSetup.Validate("Bill-to/Sell-to VAT Calc.", GeneralLedgerSetup."Bill-to/Sell-to VAT Calc."::"Bill-to/Pay-to No.");
+        GeneralLedgerSetup.Modify(true);
+
+        // [GIVEN] Sell-to Customer "A" with country "NL"
+        LibrarySales.CreateCustomerWithCountryCodeAndVATRegNo(SellToCustomer);
+        LibraryLowerPermissions.SetO365Setup();
+        LibraryLowerPermissions.AddSalesDocsCreate();
+
+        // [GIVEN] Ship-to Address for Customer "A" with country "DE"
+        ShipToCountryCode := LibraryERM.CreateCountryRegion();
+        LibrarySales.CreateShipToAddressWithCountryCode(ShipToAddress, SellToCustomer."No.", ShipToCountryCode);
+        SellToCustomer.Validate("Ship-to Code", ShipToAddress.Code);
+        SellToCustomer.Modify(true);
+
+        // [GIVEN] Bill-to Customer "B" with country "NL"
+        LibrarySales.CreateCustomerWithCountryCodeAndVATRegNo(BillToCustomer);
+
+        // [GIVEN] Alternative Customer VAT Reg. for Bill-to Customer "B" with country "DE"
+        LibraryAltCustVATReg.CreateAlternativeCustVATReg(AltCustVATReg, BillToCustomer."No.", ShipToCountryCode);
+
+        // [GIVEN] Sales order for Sell-to Customer "A" - this should create with default ship-to address from customer
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, SellToCustomer."No.");
+
+        // [GIVEN] Verify that Ship-to Country is "DE"
+        Assert.AreEqual(ShipToCountryCode, SalesHeader."Ship-to Country/Region Code", 'Ship-to Country should be from the Ship-to Address');
+
+        // [WHEN] Set "Bill-to Customer No." to "B"
+        LibraryVariableStorage.Enqueue(ChangeQst);
+        LibraryVariableStorage.Enqueue(true); // ConfirmHandler reply
+        SalesHeader.Validate("Bill-to Customer No.", BillToCustomer."No.");
+
+        // [THEN] Sales order has "VAT Country/Region Code" = "DE" (from Alternative Customer VAT Reg.)
+        Assert.AreEqual(
+            AltCustVATReg."VAT Country/Region Code",
+            SalesHeader."VAT Country/Region Code",
+            'VAT Country/Region Code should be from Alternative Customer VAT Reg. based on Ship-to Country');
+
+        // [THEN] Sales order has "VAT Registration No." from Alternative Customer VAT Reg.
+        Assert.AreEqual(
+            AltCustVATReg."VAT Registration No.",
+            SalesHeader."VAT Registration No.",
+            'VAT Registration No. should be from Alternative Customer VAT Reg.');
+
+        // [THEN] Sales order has "VAT Bus. Posting Group" from Alternative Customer VAT Reg.
+        Assert.AreEqual(
+            AltCustVATReg."VAT Bus. Posting Group",
+            SalesHeader."VAT Bus. Posting Group",
+            'VAT Bus. Posting Group should be from Alternative Customer VAT Reg.');
+
+        // [THEN] Sales order has "Gen. Bus. Posting Group" from Alternative Customer VAT Reg.
+        Assert.AreEqual(
+            AltCustVATReg."Gen. Bus. Posting Group",
+            SalesHeader."Gen. Bus. Posting Group",
+            'Gen. Bus. Posting Group should be from Alternative Customer VAT Reg.');
+
+        // [THEN] Sales order has Alt. VAT Registration No., Alt. Gen. Bus Posting Group, Alt. VAT Bus Posting Group options
+        LibraryAltCustVATReg.VerifySalesDocAltVATReg(SalesHeader, true);
+
+        LibraryVariableStorage.AssertEmpty();
+        LibraryLowerPermissions.SetOutsideO365Scope();
+    end;
+
+    local procedure Initialize()
+    begin
+        LibrarySetupStorage.Restore();
+        LibraryAltCustVATReg.UpdateConfirmAltCustVATReg(false);
+        LibraryTestInitialize.OnTestInitialize(Codeunit::BillToWithShipToAltVATRegTests);
+        if IsInitialized then
+            exit;
+
+        LibrarySetupStorage.SaveGeneralLedgerSetup();
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::BillToWithShipToAltVATRegTests);
+        IsInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::BillToWithShipToAltVATRegTests);
+    end;
+
+    [ConfirmHandler]
+    procedure ConfirmHandler(Question: Text; var Reply: Boolean)
+    begin
+        Assert.ExpectedMessage(LibraryVariableStorage.DequeueText(), Question);
+        Reply := LibraryVariableStorage.DequeueBoolean();
+    end;
+
+    [SendNotificationHandler(true)]
+    procedure NoNotificationOtherThanShipToAddressSendNotificationHandler(var Notification: Notification): Boolean;
+    var
+        ShipToAddAlternativeCustVATRegQst: Label 'The country for the address is different than the customer''s. Do you want to add an alternative VAT registration for the customer?';
+    begin
+        Assert.ExpectedMessage(ShipToAddAlternativeCustVATRegQst, Notification.Message);
+    end;
+}

