@@ -0,0 +1,111 @@
+codeunit 134779 "SCM Whse. Shpt. Post Preview"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Post Preview] [Warehouse Shipment]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        IsInitialized: Boolean;
+        WrongPostPreviewErr: Label 'Expected empty error from Preview. Actual error: ';
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure WhseShipmentLineExistsAfterPreviewPostTransferOrder()
+    var
+        LocationFrom: Record Location;
+        LocationTo: Record Location;
+        LocationInTransit: Record Location;
+        Item: Record Item;
+        ItemJournalLine: Record "Item Journal Line";
+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+        WarehouseShipmentHeader: Record "Warehouse Shipment Header";
+        WarehouseShipmentLine: Record "Warehouse Shipment Line";
+        WhsePostShipmentYesNo: Codeunit "Whse.-Post Shipment (Yes/No)";
+        GLPostingPreview: TestPage "G/L Posting Preview";
+        Qty: Decimal;
+    begin
+        // [FEATURE] [Transfer Order] [Warehouse Shipment] [Preview Posting]
+        // [SCENARIO] Warehouse shipment line linked to a Transfer Order should remain after preview posting operation
+
+        Initialize();
+
+        // [GIVEN] Create LocationFrom with Require Shipment, LocationTo and LocationInTransit
+        CreateLocationWMSWithWhseEmployee(LocationFrom, false, false, false, false, true);
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(LocationTo);
+        LibraryWarehouse.CreateInTransitLocation(LocationInTransit);
+
+        // [GIVEN] Create Item with stock at LocationFrom
+        LibraryInventory.CreateItem(Item);
+        Qty := LibraryRandom.RandIntInRange(5, 10);
+        LibraryInventory.CreateItemJournalLineInItemTemplate(
+            ItemJournalLine, Item."No.", LocationFrom.Code, '', Qty);
+        LibraryInventory.PostItemJournalLine(
+            ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+
+        // [GIVEN] Create and release Transfer Order from LocationFrom to LocationTo
+        LibraryInventory.CreateTransferHeader(TransferHeader, LocationFrom.Code, LocationTo.Code, LocationInTransit.Code);
+        LibraryInventory.CreateTransferLine(TransferHeader, TransferLine, Item."No.", Qty);
+        LibraryWarehouse.ReleaseTransferOrder(TransferHeader);
+
+        // [GIVEN] Create Warehouse Shipment from Transfer Order
+        LibraryWarehouse.CreateWhseShipmentFromTO(TransferHeader);
+        WarehouseShipmentLine.SetRange("Source Type", Database::"Transfer Line");
+        WarehouseShipmentLine.SetRange("Source No.", TransferHeader."No.");
+        WarehouseShipmentLine.FindFirst();
+        WarehouseShipmentHeader.Get(WarehouseShipmentLine."No.");
+
+        Commit();
+
+        // [WHEN] Preview Posting of Warehouse Shipment is invoked
+        GLPostingPreview.Trap();
+        asserterror WhsePostShipmentYesNo.Preview(WarehouseShipmentLine);
+        Assert.AreEqual('', GetLastErrorText, WrongPostPreviewErr + GetLastErrorText);
+        GLPostingPreview.OK().Invoke();
+
+        // [THEN] Warehouse Shipment Header still exists
+        Assert.IsTrue(WarehouseShipmentHeader.Get(WarehouseShipmentHeader."No."), 'Warehouse Shipment Header should still exist after preview posting');
+
+        // [THEN] Warehouse Shipment Line still exists
+        WarehouseShipmentLine.SetRange("Source Type", Database::"Transfer Line");
+        WarehouseShipmentLine.SetRange("Source No.", TransferHeader."No.");
+        Assert.IsTrue(WarehouseShipmentLine.FindFirst(), 'Warehouse Shipment Line should still exist after preview posting');
+    end;
+
+    local procedure Initialize()
+    var
+        WarehouseEmployee: Record "Warehouse Employee";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Whse. Shpt. Post Preview");
+        WarehouseEmployee.DeleteAll();
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Whse. Shpt. Post Preview");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateLocalData();
+
+        IsInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Whse. Shpt. Post Preview");
+    end;
+
+    local procedure CreateLocationWMSWithWhseEmployee(var Location: Record Location; BinMandatory: Boolean; RequirePutAway: Boolean; RequirePick: Boolean; RequireReceive: Boolean; RequireShipment: Boolean)
+    var
+        WarehouseEmployee: Record "Warehouse Employee";
+    begin
+        LibraryWarehouse.CreateLocationWMS(Location, BinMandatory, RequirePutAway, RequirePick, RequireReceive, RequireShipment);
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, Location.Code, true);
+    end;
+}

