+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure IssuedReminderEmailIncludesCustomerAsRelatedSource()
+    var
+        Customer: Record Customer;
+        IssuedReminderHeader: Record "Issued Reminder Header";
+        ReportSelections: Record "Report Selections";
+        ERMIssuedReminderEmailSrc: Codeunit "ERM Issued Reminder Email Src";
+        ReminderNo: Code[20];
+        DueDate: Date;
+        DocumentDate: Date;
+    begin
+        // [SCENARIO] When sending an email for an Issued Reminder, the Customer should be added as a related source
+        // so that the email appears in the customer's sent email history.
+        Initialize();
+
+        // [GIVEN] A Customer with Reminder Terms
+        CreateCustomerWithReminderTerms(Customer);
+
+        // [GIVEN] A posted Sales Invoice for the Customer
+        DueDate := CreateAndPostSalesInvoice(Customer."No.");
+
+        // [GIVEN] A Reminder is created and issued for the Customer
+        DocumentDate := CalcDate('<1D>', CalcDate('<5D>', DueDate)); // After grace period
+        CreateReminder(Customer."No.", DocumentDate);
+        ReminderNo := IssueReminder(Customer."No.", DocumentDate);
+
+        // [GIVEN] The issued reminder exists
+        IssuedReminderHeader.Get(ReminderNo);
+
+        // [WHEN] SendEmailDirectly is called for the Issued Reminder (simulated by subscribing to the event)
+        // Store expected customer SystemId in variable storage for the event subscriber
+        ERMIssuedReminderEmailSrc.SetExpectedCustomerSystemId(Customer.SystemId);
+        BindSubscription(ERMIssuedReminderEmailSrc);
+
+        // Trigger the email send path - this will call our subscriber
+        ReportSelections.SendEmailToCust(
+            ReportSelections.Usage::Reminder.AsInteger(),
+            IssuedReminderHeader,
+            IssuedReminderHeader."No.",
+            'Reminder',
+            true, // ShowDialog - we'll handle this in the event
+            Customer."No.");
+
+        UnbindSubscription(ERMIssuedReminderEmailSrc);
+
+        // [THEN] The Customer should be included in the SourceTableIDs as a related entity
+        Assert.IsTrue(ERMIssuedReminderEmailSrc.GetCustomerFoundInSourceIDs(), 'Customer should be included in email source records for issued reminder');
+    end;
+
+    procedure SetExpectedCustomerSystemId(CustomerSystemId: Guid)
+    begin
+        LibraryVariableStorage.Clear();
+        LibraryVariableStorage.Enqueue(CustomerSystemId);
+    end;
+
+    procedure GetCustomerFoundInSourceIDs(): Boolean
+    begin
+        exit(LibraryVariableStorage.DequeueBoolean());
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"ERM Issued Reminder Email Src");
+
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"ERM Issued Reminder Email Src");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.CreateGeneralPostingSetupData();
+        IsInitialized := true;
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"ERM Issued Reminder Email Src");
+    end;
+
+    local procedure CreateCustomerWithReminderTerms(var Customer: Record Customer)
+    begin
+        LibrarySales.CreateCustomer(Customer);
+        Customer.Validate("Reminder Terms Code", CreateReminderTerms());
+        Customer.Modify(true);
+    end;
+
+    local procedure CreateReminderTerms(): Code[10]
+    var
+        ReminderTerms: Record "Reminder Terms";
+        ReminderLevel: Record "Reminder Level";
+    begin
+        LibraryERM.CreateReminderTerms(ReminderTerms);
+        LibraryERM.CreateReminderLevel(ReminderLevel, ReminderTerms.Code);
+        Evaluate(ReminderLevel."Grace Period", '<5D>');
+        ReminderLevel.Validate("Additional Fee (LCY)", LibraryRandom.RandDec(10, 2));
+        ReminderLevel.Modify(true);
+        exit(ReminderTerms.Code);
+    end;
+
+    local procedure CreateAndPostSalesInvoice(CustomerNo: Code[20]): Date
+    var
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+    begin
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Invoice, CustomerNo);
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, CreateItem(), LibraryRandom.RandInt(10));
+        LibrarySales.PostSalesDocument(SalesHeader, true, true);
+        exit(SalesHeader."Due Date");
+    end;
+
+    local procedure CreateItem(): Code[20]
+    var
+        Item: Record Item;
+    begin
+        LibraryInventory.CreateItemWithUnitPriceAndUnitCost(
+            Item, LibraryRandom.RandDec(1000, 2), LibraryRandom.RandDec(1000, 2));
+        exit(Item."No.");
+    end;
+
+    local procedure CreateReminder(CustomerNo: Code[20]; DocumentDate: Date)
+    var
+        Customer: Record Customer;
+        CreateReminders: Report "Create Reminders";
+    begin
+        Clear(CreateReminders);
+        Customer.SetRange("No.", CustomerNo);
+        CreateReminders.SetTableView(Customer);
+        CreateReminders.InitializeRequest(DocumentDate, DocumentDate, true, false, false);
+        CreateReminders.UseRequestPage(false);
+        CreateReminders.Run();
+    end;
+
+    local procedure IssueReminder(CustomerNo: Code[20]; DocumentDate: Date): Code[20]
+    var
+        ReminderHeader: Record "Reminder Header";
+        ReminderIssue: Codeunit "Reminder-Issue";
+        NoSeries: Codeunit "No. Series";
+        IssuedReminderNo: Code[20];
+    begin
+        ReminderHeader.SetRange("Customer No.", CustomerNo);
+        ReminderHeader.FindFirst();
+        IssuedReminderNo := NoSeries.PeekNextNo(ReminderHeader."Issuing No. Series");
+        ReminderIssue.Set(ReminderHeader, false, DocumentDate);
+        LibraryERM.RunReminderIssue(ReminderIssue);
+        exit(IssuedReminderNo);
+    end;
+
+    [EventSubscriber(ObjectType::Table, Database::"Report Selections", 'OnSendEmailDirectlyOnBeforeSend', '', false, false)]
+    local procedure OnSendEmailDirectlyOnBeforeSend(var ReportSelections: Record "Report Selections"; ReportUsage: Enum "Report Selection Usage"; RecordVariant: Variant; var DocNo: Code[20]; var DocName: Text[150]; FoundBody: Boolean; FoundAttachment: Boolean; var EmailBody: Codeunit "Temp Blob"; var DefaultEmailAddress: Text[250]; ShowDialog: Boolean; var TempAttachReportSelections: Record "Report Selections" temporary; var CustomReportSelection: Record "Custom Report Selection"; var AllEmailsWereSuccessful: Boolean; var IsHandled: Boolean; var SourceTableIDs: List of [Integer]; var SourceIDs: List of [Guid]; var SourceRelationTypes: List of [Integer])
+    var
+        ExpectedCustomerId: Guid;
+        CustomerFound: Boolean;
+        i: Integer;
+    begin
+        // Get expected customer SystemId from variable storage
+        ExpectedCustomerId := LibraryVariableStorage.DequeueGuid();
+        CustomerFound := false;
+
+        // Check if Customer table is in the SourceTableIDs list with matching SystemId
+        for i := 1 to SourceTableIDs.Count() do
+            if SourceTableIDs.Get(i) = Database::Customer then
+                if SourceIDs.Get(i) = ExpectedCustomerId then begin
+                    CustomerFound := true;
+                    break;
+                end;
+
+        // Store result back in variable storage for the test to verify
+        LibraryVariableStorage.Enqueue(CustomerFound);
+
+        // Set IsHandled to true to prevent actual email sending during test
+        IsHandled := true;
+        AllEmailsWereSuccessful := true;
+    end;
+}

diff --git a/App/Layers/W1/Tests/SCM/SCMSKULowLevelCodePlanning.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMSKULowLevelCodePlanning.Codeunit.al
new file mode 100644
index 00000000..dbd237c8
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM/SCMSKULowLevelCodePlanning.Codeunit.al
@@ -0,0 +1,140 @@
+codeunit 137095 "SCM SKU Low-Level Code Planning"
+{
+    // Tests that validate the fix for regenerative planning with Stockkeeping Units.
+    // When a Production BOM is assigned to a SKU with Dynamic Low-Level Code enabled,
+    // the component items should be planned in a single run of Calculate Regenerative Plan.
+
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Planning] [Stockkeeping Unit] [Low-Level Code]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        LibraryPlanning: Codeunit "Library - Planning";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryRandom: Codeunit "Library - Random";
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure RegenPlanPlansComponentWithSKUInSingleRun()
+    var
+        ComponentItem: Record Item;
+        ParentItem: Record Item;
+        ComponentSKU: Record "Stockkeeping Unit";
+        ParentSKU: Record "Stockkeeping Unit";
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        Location: Record Location;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        RequisitionLine: Record "Requisition Line";
+        ManufacturingSetup: Record "Manufacturing Setup";
+        OriginalDynamicLowLevelCode: Boolean;
+        PlanningEndDate: Date;
+    begin
+        // [SCENARIO] When Calculate Regenerative Plan is run with SKUs that have Production BOM assignments,
+        // both the parent item and component items should be planned in a single run when Dynamic Low-Level Code is enabled.
+
+        // [GIVEN] Manufacturing Setup with Dynamic Low-Level Code enabled
+        Initialize();
+        ManufacturingSetup.Get();
+        OriginalDynamicLowLevelCode := ManufacturingSetup."Dynamic Low-Level Code";
+        if not ManufacturingSetup."Dynamic Low-Level Code" then begin
+            ManufacturingSetup.Validate("Dynamic Low-Level Code", true);
+            ManufacturingSetup.Modify(true);
+        end;
+
+        // [GIVEN] A location
+        LibraryWarehouse.CreateLocation(Location);
+
+        // [GIVEN] A component item with a SKU (Replenishment System = Purchase, Reorder Policy = Order)
+        LibraryInventory.CreateItem(ComponentItem);
+        LibraryInventory.CreateStockkeepingUnitForLocationAndVariant(ComponentSKU, Location.Code, ComponentItem."No.", '');
+        ComponentSKU.Validate("Replenishment System", ComponentSKU."Replenishment System"::Purchase);
+        ComponentSKU.Validate("Reordering Policy", ComponentSKU."Reordering Policy"::Order);
+        ComponentSKU.Modify(true);
+
+        // [GIVEN] A production BOM with the component item
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ComponentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItem."No.", 1);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+
+        // [GIVEN] A parent item with a SKU (Replenishment System = Prod. Order, Reorder Policy = Lot-for-Lot, with Production BOM)
+        LibraryInventory.CreateItem(ParentItem);
+        LibraryInventory.CreateStockkeepingUnitForLocationAndVariant(ParentSKU, Location.Code, ParentItem."No.", '');
+        ParentSKU.Validate("Replenishment System", ParentSKU."Replenishment System"::"Prod. Order");
+        ParentSKU.Validate("Reordering Policy", ParentSKU."Reordering Policy"::"Lot-for-Lot");
+        // This is where the fix is tested - assigning Production BOM to SKU should trigger low-level code calculation
+        ParentSKU.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ParentSKU.Modify(true);
+
+        // [GIVEN] A sales order for the parent item at the location
+        LibrarySales.CreateSalesDocumentWithItem(
+            SalesHeader, SalesLine, SalesHeader."Document Type"::Order, LibrarySales.CreateCustomerNo(),
+            ParentItem."No.", LibraryRandom.RandIntInRange(5, 10), Location.Code, WorkDate());
+
+        // [WHEN] Calculate Regenerative Plan is run once
+        ClearRequisitionLines();
+        ParentItem.SetFilter("No.", '%1|%2', ParentItem."No.", ComponentItem."No.");
+        ParentItem.SetFilter("Location Filter", Location.Code);
+        PlanningEndDate := CalcDate('<+30D>', WorkDate());
+        LibraryPlanning.CalcRegenPlanForPlanWksh(ParentItem, WorkDate(), PlanningEndDate);
+
+        // [THEN] Both the parent item and the component item should have requisition lines
+        RequisitionLine.SetRange(Type, RequisitionLine.Type::Item);
+        RequisitionLine.SetRange("Location Code", Location.Code);
+
+        // Verify parent item is planned
+        RequisitionLine.SetRange("No.", ParentItem."No.");
+        Assert.RecordIsNotEmpty(RequisitionLine);
+
+        // Verify component item is planned in the same single run
+        RequisitionLine.SetRange("No.", ComponentItem."No.");
+        Assert.RecordIsNotEmpty(RequisitionLine);
+
+        // [CLEANUP] Restore original setting
+        if ManufacturingSetup."Dynamic Low-Level Code" <> OriginalDynamicLowLevelCode then begin
+            ManufacturingSetup.Validate("Dynamic Low-Level Code", OriginalDynamicLowLevelCode);
+            ManufacturingSetup.Modify(true);
+        end;
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM SKU Low-Level Code Planning");
+
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM SKU Low-Level Code Planning");
+
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateSalesReceivablesSetup();
+        LibraryERMCountryData.UpdatePurchasesPayablesSetup();
+
+        IsInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM SKU Low-Level Code Planning");
+    end;
+
+    local procedure ClearRequisitionLines()
+    var
+        RequisitionLine: Record "Requisition Line";
+    begin
+        RequisitionLine.Reset();
+        RequisitionLine.DeleteAll();
+    end;
+}

diff --git a/App/Layers/W1/Tests/SCM/SCMConsumptionLotReservation.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMConsumptionLotReservation.Codeunit.al
new file mode 100644
index 00000000..d1c82c20
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM/SCMConsumptionLotReservation.Codeunit.al
@@ -0,0 +1,231 @@
+codeunit 137299 "SCM Consumption Lot Reservation"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Production] [Consumption] [Item Tracking] [Reservation]
+        isInitialized := false;
+    end;
+
+    var
+        ConsumptionItemJournalTemplate: Record "Item Journal Template";
+        ConsumptionItemJournalBatch: Record "Item Journal Batch";
+        ItemJournalTemplate: Record "Item Journal Template";
+        ItemJournalBatch: Record "Item Journal Batch";
+        LocationBlue: Record Location;
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryItemTracking: Codeunit "Library - Item Tracking";
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        isInitialized: Boolean;
+        ItemTrackingMode: Option " ","Assign Lot No.","Select Entries","Verify Entries","Set Lot No.","Set Quantity & Lot No.","Get Lot Quantity";
+
+    [Test]
+    [HandlerFunctions('LotItemTrackingPageHandler')]
+    [Scope('OnPrem')]
+    procedure PostConsumptionForLotTrackedItemReservedToMultipleILEs()
+    var
+        ItemTrackingCode: Record "Item Tracking Code";
+        CompItem: Record Item;
+        ParentItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ProductionOrder: Record "Production Order";
+        ProdOrderComponent: Record "Prod. Order Component";
+        ItemLedgerEntry: Record "Item Ledger Entry";
+        ReservationEntry: Record "Reservation Entry";
+        ItemJournalLine: Record "Item Journal Line";
+        LotNo: Code[50];
+        TotalQty: Decimal;
+        Qty1: Decimal;
+        Qty2: Decimal;
+        Qty3: Decimal;
+    begin
+        // [FEATURE] [Consumption] [Item Tracking] [Reservation]
+        // [SCENARIO] Post consumption for a lot-tracked item that is reserved to multiple Item Ledger Entries (ILEs) with the same lot number.
+        // This scenario reproduces the issue where posting consumption fails with "You have insufficient quantity of Item xxx on Inventory."
+        // when the component is reserved against multiple ILEs with the same lot number.
+
+        // [GIVEN] A lot-tracked component item with "Reserve" = Always
+        Initialize();
+        Qty1 := 5;
+        Qty2 := 10;
+        Qty3 := 20;
+        TotalQty := Qty1 + Qty2 + Qty3;
+
+        LibraryItemTracking.CreateItemTrackingCode(ItemTrackingCode, false, true);
+        LibraryInventory.CreateItem(CompItem);
+        CompItem.Validate("Item Tracking Code", ItemTrackingCode.Code);
+        CompItem.Validate(Reserve, CompItem.Reserve::Always);
+        CompItem.Validate("Flushing Method", CompItem."Flushing Method"::Manual);
+        CompItem.Modify(true);
+
+        // [GIVEN] A parent item with a production BOM that includes the component item
+        LibraryInventory.CreateItem(ParentItem);
+        ParentItem.Validate("Replenishment System", ParentItem."Replenishment System"::"Prod. Order");
+        ParentItem.Modify(true);
+
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ParentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, CompItem."No.", 1);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+        ParentItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ParentItem.Modify(true);
+
+        // [GIVEN] 3 Item Journal lines for component item with positive adjustment for 5, 10, 20 qty, all with the same Lot Number at BLUE location
+        LotNo := LibraryUtility.GenerateGUID();
+        CreateAndPostItemJournalLineWithLotNo(CompItem."No.", LocationBlue.Code, LotNo, Qty1);
+        CreateAndPostItemJournalLineWithLotNo(CompItem."No.", LocationBlue.Code, LotNo, Qty2);
+        CreateAndPostItemJournalLineWithLotNo(CompItem."No.", LocationBlue.Code, LotNo, Qty3);
+
+        // Verify that we have 3 ILEs with the same lot number
+        ItemLedgerEntry.SetRange("Item No.", CompItem."No.");
+        ItemLedgerEntry.SetRange("Lot No.", LotNo);
+        Assert.AreEqual(3, ItemLedgerEntry.Count(), 'Expected 3 Item Ledger Entries with the same lot number');
+
+        // [GIVEN] A Released Production Order for 35 qty of parent item at BLUE location
+        LibraryManufacturing.CreateProductionOrder(
+            ProductionOrder, ProductionOrder.Status::Released, ProductionOrder."Source Type"::Item, ParentItem."No.", TotalQty);
+        ProductionOrder.Validate("Location Code", LocationBlue.Code);
+        ProductionOrder.Modify(true);
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, true, true, true, false);
+
+        // [GIVEN] The component is reserved to the 3 ILEs (35 total reserved)
+        FindProdOrderComponent(ProdOrderComponent, ProductionOrder.Status, ProductionOrder."No.", CompItem."No.");
+        ProdOrderComponent.AutoReserve();
+        ProdOrderComponent.CalcFields("Reserved Quantity");
+        Assert.AreEqual(TotalQty, ProdOrderComponent."Reserved Quantity", 'Component should be fully reserved');
+
+        // Verify reservations exist against multiple ILEs
+        ReservationEntry.SetRange("Source Type", Database::"Prod. Order Component");
+        ReservationEntry.SetRange("Source ID", ProductionOrder."No.");
+        ReservationEntry.SetRange("Item No.", CompItem."No.");
+        Assert.IsTrue(ReservationEntry.Count() >= 1, 'Reservation entries should exist for the component');
+
+        // [WHEN] Create consumption journal with item tracking for the full 35 qty with the same lot number
+        LibraryInventory.ClearItemJournal(ConsumptionItemJournalTemplate, ConsumptionItemJournalBatch);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ConsumptionItemJournalTemplate.Name, ConsumptionItemJournalBatch.Name,
+            ItemJournalLine."Entry Type"::Consumption, CompItem."No.", TotalQty);
+        ItemJournalLine.Validate("Order No.", ProductionOrder."No.");
+        ItemJournalLine.Validate("Location Code", LocationBlue.Code);
+        ItemJournalLine.Modify(true);
+
+        LibraryVariableStorage.Enqueue(ItemTrackingMode::"Set Quantity & Lot No.");
+        LibraryVariableStorage.Enqueue(LotNo);
+        LibraryVariableStorage.Enqueue(TotalQty);
+        ItemJournalLine.OpenItemTrackingLines(false);
+
+        // [THEN] The consumption journal posts successfully without "You have insufficient quantity" error
+        LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+
+        // [THEN] Verify 35 quantity was consumed
+        ItemLedgerEntry.Reset();
+        ItemLedgerEntry.SetRange("Item No.", CompItem."No.");
+        ItemLedgerEntry.SetRange("Entry Type", ItemLedgerEntry."Entry Type"::Consumption);
+        ItemLedgerEntry.SetRange("Order No.", ProductionOrder."No.");
+        ItemLedgerEntry.FindFirst();
+        Assert.AreEqual(-TotalQty, ItemLedgerEntry.Quantity, 'Consumption quantity should be -35');
+
+        LibraryVariableStorage.AssertEmpty();
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Consumption Lot Reservation");
+        LibraryVariableStorage.Clear();
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Consumption Lot Reservation");
+
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.CreateVATData();
+        CreateLocationSetup();
+        ItemJournalSetup();
+        ConsumptionJournalSetup();
+        Commit();
+
+        isInitialized := true;
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Consumption Lot Reservation");
+    end;
+
+    local procedure CreateLocationSetup()
+    begin
+        LibraryWarehouse.CreateLocation(LocationBlue);
+    end;
+
+    local procedure ItemJournalSetup()
+    begin
+        LibraryInventory.ItemJournalSetup(ItemJournalTemplate, ItemJournalBatch);
+    end;
+
+    local procedure ConsumptionJournalSetup()
+    begin
+        LibraryInventory.ConsumptionJournalSetup(ConsumptionItemJournalTemplate, ConsumptionItemJournalBatch);
+    end;
+
+    local procedure CreateAndPostItemJournalLineWithLotNo(ItemNo: Code[20]; LocationCode: Code[10]; LotNo: Code[50]; Quantity: Decimal)
+    var
+        ItemJournalLine: Record "Item Journal Line";
+        ReservationEntry: Record "Reservation Entry";
+    begin
+        LibraryInventory.ClearItemJournal(ItemJournalTemplate, ItemJournalBatch);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalTemplate.Name, ItemJournalBatch.Name,
+            ItemJournalLine."Entry Type"::"Positive Adjmt.", ItemNo, Quantity);
+        ItemJournalLine.Validate("Location Code", LocationCode);
+        ItemJournalLine.Modify(true);
+
+        LibraryItemTracking.CreateItemJournalLineItemTracking(ReservationEntry, ItemJournalLine, '', LotNo, Quantity);
+
+        LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+    end;
+
+    local procedure FindProdOrderComponent(var ProdOrderComponent: Record "Prod. Order Component"; Status: Enum "Production Order Status"; ProdOrderNo: Code[20]; ItemNo: Code[20])
+    begin
+        ProdOrderComponent.SetRange(Status, Status);
+        ProdOrderComponent.SetRange("Prod. Order No.", ProdOrderNo);
+        ProdOrderComponent.SetRange("Item No.", ItemNo);
+        ProdOrderComponent.FindFirst();
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure LotItemTrackingPageHandler(var ItemTrackingLines: TestPage "Item Tracking Lines")
+    begin
+        case LibraryVariableStorage.DequeueInteger() of
+            ItemTrackingMode::"Assign Lot No.":
+                ItemTrackingLines."Assign Lot No.".Invoke();
+            ItemTrackingMode::"Select Entries":
+                ItemTrackingLines."Select Entries".Invoke();
+            ItemTrackingMode::"Verify Entries":
+                begin
+                    ItemTrackingLines."Lot No.".AssertEquals(LibraryVariableStorage.DequeueText());
+                    ItemTrackingLines."Quantity (Base)".AssertEquals(LibraryVariableStorage.DequeueDecimal());
+                end;
+            ItemTrackingMode::"Set Lot No.":
+                ItemTrackingLines."Lot No.".SetValue(LibraryVariableStorage.DequeueText());
+            ItemTrackingMode::"Set Quantity & Lot No.":
+                begin
+                    ItemTrackingLines."Lot No.".SetValue(LibraryVariableStorage.DequeueText());
+                    ItemTrackingLines."Quantity (Base)".SetValue(LibraryVariableStorage.DequeueDecimal());
+                end;
+            ItemTrackingMode::"Get Lot Quantity":
+                begin
+                    ItemTrackingLines.FILTER.SetFilter("Lot No.", LibraryVariableStorage.DequeueText());
+                    LibraryVariableStorage.Enqueue(ItemTrackingLines."Quantity (Base)".AsDecimal());
+                end;
+        end;
+        ItemTrackingLines.OK().Invoke();
+    end;
+}

diff --git a/App/Apps/W1/ExcelReports/test/src/FixedAssetAnalysisExcelTests.Codeunit.al b/App/Apps/W1/ExcelReports/test/src/FixedAssetAnalysisExcelTests.Codeunit.al
