+namespace Microsoft.Finance.ExcelReports.Test;
+
+using Microsoft.Finance.ExcelReports;
+using Microsoft.FixedAssets.FixedAsset;
+using Microsoft.FixedAssets.Depreciation;
+using Microsoft.FixedAssets.Posting;
+using Microsoft.FixedAssets.Setup;
+
+codeunit 139545 "Fixed Asset Analysis Excel Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        LibraryFixedAsset: Codeunit "Library - Fixed Asset";
+        LibraryReportDataset: Codeunit "Library - Report Dataset";
+        Assert: Codeunit Assert;
+
+    [Test]
+    [HandlerFunctions('EXRFixedAssetAnalysisExcelHandler')]
+    procedure AcquisitionDateIsExportedForAcquiredFixedAsset()
+    var
+        FixedAsset: Record "Fixed Asset";
+        DepreciationBook: Record "Depreciation Book";
+        FADepreciationBook: Record "FA Depreciation Book";
+        FAPostingType: Record "FA Posting Type";
+        FASetup: Record "FA Setup";
+        ExpectedAcquisitionDate: Date;
+        Variant: Variant;
+        ReportDateValue: Text;
+        RequestPageXml: Text;
+    begin
+        // [SCENARIO] Acquisition date is exported in the Fixed Asset Analysis Excel report
+        // [GIVEN] FA Posting Type table is empty (simulating fresh database)
+        FAPostingType.DeleteAll();
+        // [GIVEN] A Fixed Asset with an Acquisition Date
+        LibraryFixedAsset.CreateDepreciationBook(DepreciationBook);
+        FASetup.Get();
+        FASetup."Default Depr. Book" := DepreciationBook.Code;
+        FASetup.Modify();
+        LibraryFixedAsset.CreateFixedAsset(FixedAsset);
+        LibraryFixedAsset.CreateFADepreciationBook(FADepreciationBook, FixedAsset."No.", DepreciationBook.Code);
+        ExpectedAcquisitionDate := WorkDate() - 30;
+        FADepreciationBook."Acquisition Date" := ExpectedAcquisitionDate;
+        FADepreciationBook.Modify();
+        Commit();
+
+        // [WHEN] Running the Fixed Asset Analysis Excel report
+        RequestPageXml := Report.RunRequestPage(Report::"EXR Fixed Asset Analysis Excel", RequestPageXml);
+        LibraryReportDataset.RunReportAndLoad(Report::"EXR Fixed Asset Analysis Excel", Variant, RequestPageXml);
+
+        // [THEN] The Acquisition Date should be exported for the Fixed Asset
+        LibraryReportDataset.SetXmlNodeList('DataItem[@name="FAPostingType"]');
+        Assert.IsTrue(LibraryReportDataset.RowCount() > 0, 'FA Posting Types should be exported');
+        LibraryReportDataset.GetNextRow();
+        LibraryReportDataset.FindCurrentRowValue('AcquisitionDateField', Variant);
+        ReportDateValue := Variant;
+        Assert.AreNotEqual('', ReportDateValue, 'Acquisition Date should not be empty');
+    end;
+
+    [RequestPageHandler]
+    procedure EXRFixedAssetAnalysisExcelHandler(var EXRFixedAssetAnalysisExcel: TestRequestPage "EXR Fixed Asset Analysis Excel")
+    begin
+        EXRFixedAssetAnalysisExcel.StartingDateField.Value := Format(CalcDate('<-1Y>', WorkDate()));
+        EXRFixedAssetAnalysisExcel.EndingDateField.Value := Format(WorkDate());
+        EXRFixedAssetAnalysisExcel.OK().Invoke();
+    end;
+}

