+    begin
+        // [SCENARIO] When setting Net Change from positive to negative, Debit field should be cleared
+        // [GIVEN] A Trial Balance Buffer record with a positive Net Change (shows in Debit column)
+        TrialBalanceBuffer.Init();
+        TrialBalanceBuffer."G/L Account No." := 'TEST-ACC-001';
+        TrialBalanceBuffer.Validate("Net Change", 1000);
+        // [THEN] The debit amount should be set and credit should be zero
+        Assert.AreEqual(1000, TrialBalanceBuffer."Net Change (Debit)", 'Initial Net Change (Debit) should be 1000');
+        Assert.AreEqual(0, TrialBalanceBuffer."Net Change (Credit)", 'Initial Net Change (Credit) should be 0');
+
+        // [WHEN] Setting Net Change to a negative value (shows in Credit column)
+        TrialBalanceBuffer.Validate("Net Change", -500);
+
+        // [THEN] The credit amount should be set and debit should be cleared to zero
+        Assert.AreEqual(0, TrialBalanceBuffer."Net Change (Debit)", 'Net Change (Debit) should be cleared to 0 when balance becomes negative');
+        Assert.AreEqual(500, TrialBalanceBuffer."Net Change (Credit)", 'Net Change (Credit) should be 500');
