+        Assert.AreEqual(0, TrialBalanceBuffer."Net Change (Debit)", 'Initial Net Change (Debit) should be 0');
+        Assert.AreEqual(800, TrialBalanceBuffer."Net Change (Credit)", 'Initial Net Change (Credit) should be 800');
+
+        // [WHEN] Setting Net Change to a positive value (shows in Debit column)
+        TrialBalanceBuffer.Validate("Net Change", 300);
+
+        // [THEN] The debit amount should be set and credit should be cleared to zero
+        Assert.AreEqual(300, TrialBalanceBuffer."Net Change (Debit)", 'Net Change (Debit) should be 300');
+        Assert.AreEqual(0, TrialBalanceBuffer."Net Change (Credit)", 'Net Change (Credit) should be cleared to 0 when balance becomes positive');
