+        Assert.AreEqual(0, TrialBalanceBuffer."Balance (Debit)", 'Balance (Debit) should be cleared to 0 when balance becomes negative');
+        Assert.AreEqual(750, TrialBalanceBuffer."Balance (Credit)", 'Balance (Credit) should be 750');
