@@ -0,0 +1,185 @@
+codeunit 137802 "SCM Carry Out Action Msg Filter"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Planning] [Carry Out Action Message] [SCM]
+        isInitialized := false;
+    end;
+
+    var
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryPlanning: Codeunit "Library - Planning";
+        LibraryPurchase: Codeunit "Library - Purchase";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        LibraryUtility: Codeunit "Library - Utility";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryApplicationArea: Codeunit "Library - Application Area";
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure CarryOutActionMsgRespectsActionMessageFilter()
+    var
+        Item: Record Item;
+        Vendor: Record Vendor;
+        PurchaseHeader: Record "Purchase Header";
+        PurchaseLine: Record "Purchase Line";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        PurchaseOrderDate: Date;
+        SalesShipmentDate: Date;
+        Quantity: Decimal;
+    begin
+        // [SCENARIO] When filtering by Action Message in the Planning Worksheet and carrying out action message, only lines matching the filter should be processed.
+        // [GIVEN] An item with reordering policy "Order"
+        // [GIVEN] A purchase order for the item (supply to be cancelled)
+        // [GIVEN] A sales order for the same item with a future date (demand that creates a "New" action)
+        // [WHEN] Calculate regenerative plan
+        // [WHEN] Filter to Action Message "Cancel" and carry out action message
+        // [THEN] Only the "Cancel" line is processed; the "New" line remains in the worksheet
+
+        Initialize();
+
+        // Setup: Create Item with "Order" reordering policy
+        CreateOrderReorderingPolicyItem(Item);
+
+        // Setup: Create Vendor and assign to Item
+        LibraryPurchase.CreateVendor(Vendor);
+        Item.Validate("Vendor No.", Vendor."No.");
+        Item.Modify(true);
+
+        // Setup: Create a Purchase Order (supply) - this will generate a "Cancel" action message
+        PurchaseOrderDate := WorkDate();
+        Quantity := LibraryRandom.RandIntInRange(5, 10);
+        LibraryPurchase.CreatePurchHeader(PurchaseHeader, PurchaseHeader."Document Type"::Order, Vendor."No.");
+        PurchaseHeader.Validate("Order Date", PurchaseOrderDate);
+        PurchaseHeader.Modify(true);
+        LibraryPurchase.CreatePurchaseLine(PurchaseLine, PurchaseHeader, PurchaseLine.Type::Item, Item."No.", Quantity);
+        PurchaseLine.Validate("Expected Receipt Date", PurchaseOrderDate);
+        PurchaseLine.Modify(true);
+
+        // Setup: Create a Sales Order (demand) with future shipment date - this will generate a "New" action message
+        SalesShipmentDate := CalcDate('<+10D>', WorkDate());
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, LibrarySales.CreateCustomerNo());
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", Quantity);
+        SalesLine.Validate("Shipment Date", SalesShipmentDate);
+        SalesLine.Modify(true);
+
+        // Exercise: Calculate Regenerative Plan
+        LibraryPlanning.CalcRegenPlanForPlanWksh(Item, WorkDate() - 1, SalesShipmentDate + 10);
+
+        // Verify: Both "Cancel" and "New" action message lines should exist
+        VerifyRequisitionLineExists(Item."No.", "Action Message Type"::Cancel);
+        VerifyRequisitionLineExists(Item."No.", "Action Message Type"::New);
+
+        // Exercise: Accept action messages for all lines
+        AcceptAllActionMessages(Item."No.");
+
+        // Exercise: Filter to "Cancel" action message only and carry out
+        CarryOutActionMessageWithActionMessageFilter(Item."No.", "Action Message Type"::Cancel);
+
+        // Verify: "Cancel" line should be removed (carried out)
+        VerifyRequisitionLineNotExists(Item."No.", "Action Message Type"::Cancel);
+
+        // Verify: "New" line should still exist (not carried out because of the filter)
+        VerifyRequisitionLineExists(Item."No.", "Action Message Type"::New);
+    end;
+
+    local procedure Initialize()
+    var
+        UntrackedPlanningElement: Record "Untracked Planning Element";
+        RequisitionLine: Record "Requisition Line";
+        ReservationEntry: Record "Reservation Entry";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Carry Out Action Msg Filter");
+        LibrarySetupStorage.Restore();
+        UntrackedPlanningElement.DeleteAll();
+        RequisitionLine.DeleteAll();
+        ReservationEntry.DeleteAll();
+
+        LibraryApplicationArea.EnableEssentialSetup();
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Carry Out Action Msg Filter");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        NoSeriesSetup();
+
+        isInitialized := true;
+        Commit();
+
+        LibrarySetupStorage.Save(DATABASE::"Inventory Setup");
+        LibrarySetupStorage.Save(DATABASE::"Manufacturing Setup");
+        LibrarySetupStorage.Save(DATABASE::"Sales & Receivables Setup");
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Carry Out Action Msg Filter");
+    end;
+
+    local procedure NoSeriesSetup()
+    var
+        SalesReceivablesSetup: Record "Sales & Receivables Setup";
+        PurchasesPayablesSetup: Record "Purchases & Payables Setup";
+    begin
+        SalesReceivablesSetup.Get();
+        SalesReceivablesSetup.Validate("Order Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        SalesReceivablesSetup.Validate("Customer Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        SalesReceivablesSetup.Modify(true);
+
+        PurchasesPayablesSetup.Get();
+        PurchasesPayablesSetup.Validate("Order Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        PurchasesPayablesSetup.Validate("Vendor Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        PurchasesPayablesSetup.Modify(true);
+    end;
+
+    local procedure CreateOrderReorderingPolicyItem(var Item: Record Item)
+    begin
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Replenishment System", Item."Replenishment System"::Purchase);
+        Item.Validate("Reordering Policy", Item."Reordering Policy"::Order);
+        Item.Modify(true);
+    end;
+
+    local procedure AcceptAllActionMessages(ItemNo: Code[20])
+    var
+        RequisitionLine: Record "Requisition Line";
+    begin
+        RequisitionLine.SetRange("No.", ItemNo);
+        RequisitionLine.ModifyAll("Accept Action Message", true, true);
+    end;
+
+    local procedure CarryOutActionMessageWithActionMessageFilter(ItemNo: Code[20]; ActionMessage: Enum "Action Message Type")
+    var
+        RequisitionLine: Record "Requisition Line";
+    begin
+        RequisitionLine.SetRange("No.", ItemNo);
+        RequisitionLine.SetRange("Action Message", ActionMessage);
+        RequisitionLine.FindFirst();
+        LibraryPlanning.CarryOutActionMsgPlanWksh(RequisitionLine);
+    end;
+
+    local procedure VerifyRequisitionLineExists(ItemNo: Code[20]; ActionMessage: Enum "Action Message Type")
+    var
+        RequisitionLine: Record "Requisition Line";
+    begin
+        RequisitionLine.SetRange("No.", ItemNo);
+        RequisitionLine.SetRange("Action Message", ActionMessage);
+        Assert.IsFalse(RequisitionLine.IsEmpty, StrSubstNo('Requisition Line with Action Message %1 should exist for Item %2.', ActionMessage, ItemNo));
+    end;
+
+    local procedure VerifyRequisitionLineNotExists(ItemNo: Code[20]; ActionMessage: Enum "Action Message Type")
+    var
+        RequisitionLine: Record "Requisition Line";
+    begin
+        RequisitionLine.SetRange("No.", ItemNo);
+        RequisitionLine.SetRange("Action Message", ActionMessage);
+        Assert.IsTrue(RequisitionLine.IsEmpty, StrSubstNo('Requisition Line with Action Message %1 should not exist for Item %2.', ActionMessage, ItemNo));
+    end;
+}

