+    [Test]
+    procedure ProdOrderComponentWithPartialQtyPerWhenItemUOMHasQtyRoundingPrecision1()
+    var
+        CompItem: Record Item;
+        ProdItem: Record Item;
+        CompItemUnitOfMeasure: Record "Item Unit of Measure";
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ProductionOrder: Record "Production Order";
+        ProdOrderComponent: Record "Prod. Order Component";
+        QtyPer: Decimal;
+    begin
+        // [SCENARIO] When a component Item UOM has 'Qty. Rounding Precision' = 1 and the Production BOM has a partial 'Quantity Per' (e.g., 0.09),
+        // the Prod. Order Component should still have correct 'Quantity per' and 'Expected Quantity' values (not rounded to 0).
+        Initialize();
+
+        // [GIVEN] A Component Item with Replenishment System = Purchase, Rounding Precision = 0.01
