+        // [GIVEN] Assign the Production BOM to the Finished Good Item
+        ProdItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ProdItem.Modify(true);
+
+        // [WHEN] Create and refresh a Released Production Order for the Finished Good Item with Quantity = 1
+        CreateAndRefreshProductionOrder(ProductionOrder, ProductionOrder.Status::Released, ProdItem."No.", 1, '', '');
+
+        // [THEN] The Prod. Order Component has 'Quantity per' = 0.09 (not rounded to 0)
+        FindProdOrderComponentByOrderNoAndItem(ProdOrderComponent, ProductionOrder."No.", CompItem."No.");
+        ProdOrderComponent.TestField("Quantity per", QtyPer);
+
+        // [THEN] The Prod. Order Component has 'Expected Quantity' = 0.09 (not rounded to 0)
+        ProdOrderComponent.TestField("Expected Quantity", QtyPer);
+    end;
