+        // [GIVEN] Digital voucher entry setup for general journal is "Attachment" and "Generate Automatically" option is disabled
+        InitSetupCheckOnly("Digital Voucher Entry Type"::"General Journal", "Digital Voucher Check Type"::Attachment);
+        // [GIVEN] General journal lines with the same template, batch, posting date and document no. are created
