+codeunit 137959 "SCM Replan Production Order"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Replan Production Order] [Manufacturing]
+        IsInitialized := false;
+    end;
+
+    var
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryRandom: Codeunit "Library - Random";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure InputQuantityIsRecalculatedOnReplanAfterPartialOutput()
+    var
+        Item: Record Item;
+        ComponentItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionOrder: Record "Production Order";
+        ProdOrderRoutingLine: Record "Prod. Order Routing Line";
+        Direction: Option Forward,Backward;
+        CalcMethod: Option "No Levels","One Level","All Levels";
+        Qty: Decimal;
+        OutputQty: Decimal;
+    begin
+        // [SCENARIO] When replanning a released production order after partial output, Input Quantity is recalculated based on remaining quantity.
+        // [GIVEN] Production item with routing. Setup Time = 10, Run Time = 10.
+        // [GIVEN] Released production order for 50 pcs. Refresh.
+        // [GIVEN] Post output for 20 pcs.
+        // [WHEN] Run Replan Production Order with Direction = Backward and CalcMethod = No Levels.
+        // [THEN] Input Quantity on the prod. order routing line = 30 (Remaining Quantity).
+        Initialize();
+        Qty := 50;
+        OutputQty := 20;
+
+        // Create production item with routing
+        CreateProductionItemWithRoutingAndBOM(Item, ComponentItem, ProductionBOMHeader, 10, 10);
+
+        // Create and refresh released production order
+        CreateAndRefreshReleasedProductionOrder(ProductionOrder, Item."No.", Qty);
+
+        // Find routing line
+        FindFirstProdOrderRoutingLine(ProdOrderRoutingLine, ProductionOrder."No.");
+
+        // Verify initial Input Quantity equals full quantity
+        Assert.AreEqual(Qty, ProdOrderRoutingLine."Input Quantity", 'Initial Input Quantity should equal full quantity');
+
+        // Post partial output
+        CreateAndPostOutputJnlLine(ProdOrderRoutingLine, Item."No.", OutputQty);
+
+        // Run Replan Production Order
+        LibraryManufacturing.RunReplanProductionOrder(ProductionOrder, Direction::Backward, CalcMethod::"No Levels");
+
+        // Verify Input Quantity is recalculated to remaining quantity
+        FindFirstProdOrderRoutingLine(ProdOrderRoutingLine, ProductionOrder."No.");
+        Assert.AreEqual(Qty - OutputQty, ProdOrderRoutingLine."Input Quantity", 'Input Quantity should be recalculated to remaining quantity after Replan');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure InputQuantityIsZeroOnReplanAfterFullOutput()
+    var
+        Item: Record Item;
+        ComponentItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionOrder: Record "Production Order";
+        ProdOrderRoutingLine: Record "Prod. Order Routing Line";
+        Direction: Option Forward,Backward;
+        CalcMethod: Option "No Levels","One Level","All Levels";
+        Qty: Decimal;
+    begin
+        // [SCENARIO] When replanning a released production order after full output, Input Quantity is recalculated to zero.
+        // [GIVEN] Production item with routing.
+        // [GIVEN] Released production order for 50 pcs. Refresh.
+        // [GIVEN] Post output for 50 pcs (full quantity).
+        // [WHEN] Run Replan Production Order with Direction = Backward and CalcMethod = No Levels.
+        // [THEN] Input Quantity on the prod. order routing line = 0 (No remaining quantity).
+        Initialize();
+        Qty := 50;
+
+        // Create production item with routing
+        CreateProductionItemWithRoutingAndBOM(Item, ComponentItem, ProductionBOMHeader, 10, 10);
+
+        // Create and refresh released production order
+        CreateAndRefreshReleasedProductionOrder(ProductionOrder, Item."No.", Qty);
+
+        // Find routing line
+        FindFirstProdOrderRoutingLine(ProdOrderRoutingLine, ProductionOrder."No.");
+
+        // Post full output
+        CreateAndPostOutputJnlLine(ProdOrderRoutingLine, Item."No.", Qty);
+
+        // Run Replan Production Order
+        LibraryManufacturing.RunReplanProductionOrder(ProductionOrder, Direction::Backward, CalcMethod::"No Levels");
+
+        // Verify Input Quantity is recalculated to zero
+        FindFirstProdOrderRoutingLine(ProdOrderRoutingLine, ProductionOrder."No.");
+        Assert.AreEqual(0, ProdOrderRoutingLine."Input Quantity", 'Input Quantity should be zero after full output and Replan');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure InputQuantityIsRecalculatedOnReplanForwardAfterPartialOutput()
+    var
+        Item: Record Item;
+        ComponentItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionOrder: Record "Production Order";
+        ProdOrderRoutingLine: Record "Prod. Order Routing Line";
+        Direction: Option Forward,Backward;
+        CalcMethod: Option "No Levels","One Level","All Levels";
+        Qty: Decimal;
+        OutputQty: Decimal;
+    begin
+        // [SCENARIO] When replanning a released production order forward after partial output, Input Quantity is recalculated based on remaining quantity.
+        // [GIVEN] Production item with routing. Setup Time = 10, Run Time = 10.
+        // [GIVEN] Released production order for 100 pcs. Refresh.
+        // [GIVEN] Post output for 40 pcs.
+        // [WHEN] Run Replan Production Order with Direction = Forward and CalcMethod = No Levels.
+        // [THEN] Input Quantity on the prod. order routing line = 60 (Remaining Quantity).
+        Initialize();
+        Qty := 100;
+        OutputQty := 40;
+
+        // Create production item with routing
+        CreateProductionItemWithRoutingAndBOM(Item, ComponentItem, ProductionBOMHeader, 10, 10);
+
+        // Create and refresh released production order
+        CreateAndRefreshReleasedProductionOrder(ProductionOrder, Item."No.", Qty);
+
+        // Find routing line
+        FindFirstProdOrderRoutingLine(ProdOrderRoutingLine, ProductionOrder."No.");
+
+        // Post partial output
+        CreateAndPostOutputJnlLine(ProdOrderRoutingLine, Item."No.", OutputQty);
+
+        // Run Replan Production Order with Forward direction
+        LibraryManufacturing.RunReplanProductionOrder(ProductionOrder, Direction::Forward, CalcMethod::"No Levels");
+
+        // Verify Input Quantity is recalculated to remaining quantity
+        FindFirstProdOrderRoutingLine(ProdOrderRoutingLine, ProductionOrder."No.");
+        Assert.AreEqual(Qty - OutputQty, ProdOrderRoutingLine."Input Quantity", 'Input Quantity should be recalculated to remaining quantity after Forward Replan');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Replan Production Order");
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Replan Production Order");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        NoSeriesSetup();
+        Commit();
+
+        IsInitialized := true;
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Replan Production Order");
+    end;
+
+    local procedure NoSeriesSetup()
+    var
+        SalesReceivablesSetup: Record "Sales & Receivables Setup";
+    begin
+        SalesReceivablesSetup.Get();
+        SalesReceivablesSetup.Validate("Order Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        SalesReceivablesSetup.Modify(true);
+    end;
+
+    local procedure CreateProductionItemWithRoutingAndBOM(var Item: Record Item; var ComponentItem: Record Item; var ProductionBOMHeader: Record "Production BOM Header"; SetupTime: Decimal; RunTime: Decimal)
+    var
+        RoutingHeader: Record "Routing Header";
+        RoutingLine: Record "Routing Line";
+        ProductionBOMLine: Record "Production BOM Line";
+        WorkCenter: Record "Work Center";
+        CapacityUnitOfMeasure: Record "Capacity Unit of Measure";
+    begin
+        // Create work center with calendar
+        LibraryManufacturing.CreateWorkCenter(WorkCenter);
+        LibraryManufacturing.CalculateWorkCenterCalendar(WorkCenter, CalcDate('<-1M>', WorkDate()), CalcDate('<1M>', WorkDate()));
+
+        // Create capacity unit of measure for minutes
+        CapacityUnitOfMeasure.SetRange(Type, CapacityUnitOfMeasure.Type::Minutes);
+        if not CapacityUnitOfMeasure.FindFirst() then
+            LibraryManufacturing.CreateCapacityUnitOfMeasure(CapacityUnitOfMeasure, CapacityUnitOfMeasure.Type::Minutes);
+
+        // Create routing
+        LibraryManufacturing.CreateRoutingHeader(RoutingHeader, RoutingHeader.Type::Serial);
+        LibraryManufacturing.CreateRoutingLine(RoutingHeader, RoutingLine, '', '10', RoutingLine.Type::"Work Center", WorkCenter."No.");
+        RoutingLine.Validate("Setup Time", SetupTime);
+        RoutingLine.Validate("Run Time", RunTime);
+        RoutingLine.Validate("Setup Time Unit of Meas. Code", CapacityUnitOfMeasure.Code);
+        RoutingLine.Validate("Run Time Unit of Meas. Code", CapacityUnitOfMeasure.Code);
+        RoutingLine.Modify(true);
+        RoutingHeader.Validate(Status, RoutingHeader.Status::Certified);
+        RoutingHeader.Modify(true);
+
+        // Create component item
+        LibraryInventory.CreateItem(ComponentItem);
+        ComponentItem.Validate("Replenishment System", ComponentItem."Replenishment System"::Purchase);
+        ComponentItem.Modify(true);
+
+        // Create production item
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Replenishment System", Item."Replenishment System"::"Prod. Order");
+        Item.Modify(true);
+
+        // Create production BOM
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, Item."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItem."No.", 10);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+
+        // Assign routing and BOM to item
+        Item.Validate("Routing No.", RoutingHeader."No.");
+        Item.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        Item.Modify(true);
+    end;
+
+    local procedure CreateAndRefreshReleasedProductionOrder(var ProductionOrder: Record "Production Order"; ItemNo: Code[20]; Qty: Decimal)
+    begin
+        LibraryManufacturing.CreateProductionOrder(
+          ProductionOrder, ProductionOrder.Status::Released, ProductionOrder."Source Type"::Item, ItemNo, Qty);
+        ProductionOrder.SetUpdateEndDate();
+        ProductionOrder.Validate("Due Date", CalcDate('<+1M>', WorkDate()));
+        ProductionOrder.Modify(true);
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, true, true, true, false);
+    end;
+
+    local procedure FindFirstProdOrderRoutingLine(var ProdOrderRoutingLine: Record "Prod. Order Routing Line"; ProductionOrderNo: Code[20])
+    begin
+        ProdOrderRoutingLine.SetRange("Prod. Order No.", ProductionOrderNo);
+        ProdOrderRoutingLine.FindFirst();
+    end;
+
+    local procedure CreateAndPostOutputJnlLine(ProdOrderRoutingLine: Record "Prod. Order Routing Line"; ItemNo: Code[20]; Qty: Decimal)
+    var
+        ItemJournalLine: Record "Item Journal Line";
+        ItemJournalTemplate: Record "Item Journal Template";
+        ItemJournalBatch: Record "Item Journal Batch";
+    begin
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Output);
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalTemplate.Type::Output, ItemJournalTemplate.Name);
+        LibraryInventory.ClearItemJournal(ItemJournalTemplate, ItemJournalBatch);
+        LibraryManufacturing.CreateOutputJournal(
+          ItemJournalLine, ItemJournalTemplate, ItemJournalBatch, ItemNo, ProdOrderRoutingLine."Prod. Order No.");
+
+        ItemJournalLine.Validate("Operation No.", ProdOrderRoutingLine."Operation No.");
+        ItemJournalLine.Validate("Output Quantity", Qty);
+        ItemJournalLine.Modify(true);
+        LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+    end;
+}

