+    [Test]
+    [HandlerFunctions('WhseSourceCreateDocPageHandler,MessageHandlerNoText')]
+    procedure ChangeQtyOnLastTakeLineUpdatesCorrespondingPlaceLineNotFirstPlaceLine()
+    var
+        Bin: array[3] of Record Bin;
+        ComponentItem: Record Item;
+        ParentItem: Record Item;
+        Location: Record Location;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ProductionOrder: Record "Production Order";
+        ProdOrderComponent: Record "Prod. Order Component";
+        WarehouseActivityLine: Record "Warehouse Activity Line";
+        WarehouseEmployee: Record "Warehouse Employee";
+        ReleasedProductionOrder: TestPage "Released Production Order";
+        QuantityPerBin: Decimal;
+        TotalRequiredQty: Decimal;
+        NewQty: Decimal;
+        FirstPlaceLineNo: Integer;
+        LastTakeLineNo: Integer;
+        LastPlaceLineNo: Integer;
+        i: Integer;
+    begin
+        // [SCENARIO] When changing quantity on the last Take line in Warehouse Pick,
+        // the corresponding Place line (immediately after the Take line) should be updated,
+        // not the first Place line.
+        Initialize();
+
+        // [GIVEN] Create a Location with Require Pick and multiple Bins.
+        WarehouseEmployee.DeleteAll();
+        LibraryWarehouse.CreateLocationWMS(Location, true, false, true, false, true);
+        Location.Validate("Prod. Consump. Whse. Handling", Location."Prod. Consump. Whse. Handling"::"Warehouse Pick (optional)");
+        Location.Modify(true);
+
+        // [GIVEN] Create three Bins.
+        for i := 1 to 3 do
+            LibraryWarehouse.CreateBin(Bin[i], Location.Code, '', '', '');
+
+        // [GIVEN] Validate From-Production Bin Code and To-Production Bin Code in Location.
+        Location.Validate("From-Production Bin Code", Bin[1].Code);
+        Location.Validate("To-Production Bin Code", Bin[1].Code);
+        Location.Modify(true);
+
+        // [GIVEN] Create Warehouse Employee.
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, Location.Code, true);
+
+        // [GIVEN] Create Component Item with Allow Whse. Overpick enabled.
+        LibraryInventory.CreateItem(ComponentItem);
+        ComponentItem.Validate("Costing Method", ComponentItem."Costing Method"::FIFO);
+        ComponentItem.Validate("Replenishment System", ComponentItem."Replenishment System"::Purchase);
+        ComponentItem.Validate("Allow Whse. Overpick", true);
+        ComponentItem.Modify(true);
+
+        // [GIVEN] Create inventory in 3 different bins (forces multiple Take/Place line pairs).
+        QuantityPerBin := LibraryRandom.RandIntInRange(100, 200);
+        for i := 1 to 3 do
+            CreateAndPostItemJournalLine(ComponentItem."No.", QuantityPerBin, Bin[i].Code, Location.Code);
+
+        // [GIVEN] Create a Production BOM with the component item.
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ComponentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItem."No.", 1);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+
+        // [GIVEN] Create Parent Item with the Production BOM.
+        LibraryInventory.CreateItem(ParentItem);
+        ParentItem.Validate("Costing Method", ParentItem."Costing Method"::FIFO);
+        ParentItem.Validate("Replenishment System", ParentItem."Replenishment System"::"Prod. Order");
+        ParentItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ParentItem.Modify(true);
+
+        // [GIVEN] Create a Production Order that requires picking from all 3 bins.
+        TotalRequiredQty := QuantityPerBin * 3; // Total quantity across all bins
+        CreateAndRefreshProductionOrder(
+            ProductionOrder, ProductionOrder.Status::Released, ParentItem."No.",
+            TotalRequiredQty, Location.Code, '');
+
+        // [GIVEN] Find and update Prod. Order Component with the from-production bin.
+        ProdOrderComponent.SetRange("Item No.", ComponentItem."No.");
+        ProdOrderComponent.FindFirst();
+        ProdOrderComponent.Validate("Bin Code", Bin[1].Code);
+        ProdOrderComponent.Modify(true);
+
+        // [GIVEN] Create Warehouse Pick from Released Production Order.
+        ReleasedProductionOrder.OpenEdit();
+        ReleasedProductionOrder.GoToRecord(ProductionOrder);
+        ReleasedProductionOrder."Create Warehouse Pick".Invoke();
+        ReleasedProductionOrder.Close();
+
+        // [GIVEN] Find all warehouse activity lines for this item.
+        WarehouseActivityLine.SetRange("Item No.", ComponentItem."No.");
+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityLine."Activity Type"::Pick);
+
+        // [GIVEN] Find the first Place line number (should not be affected by changing last Take line).
+        WarehouseActivityLine.SetRange("Action Type", WarehouseActivityLine."Action Type"::Place);
+        WarehouseActivityLine.FindFirst();
+        FirstPlaceLineNo := WarehouseActivityLine."Line No.";
+
+        // [GIVEN] Find the last Take line.
+        WarehouseActivityLine.SetRange("Action Type", WarehouseActivityLine."Action Type"::Take);
+        WarehouseActivityLine.FindLast();
+        LastTakeLineNo := WarehouseActivityLine."Line No.";
+
+        // [GIVEN] Find the Place line that corresponds to the last Take line (should be the line after the Take line).
+        WarehouseActivityLine.SetRange("Action Type", WarehouseActivityLine."Action Type"::Place);
+        WarehouseActivityLine.SetFilter("Line No.", '>%1', LastTakeLineNo);
+        WarehouseActivityLine.FindFirst();
+        LastPlaceLineNo := WarehouseActivityLine."Line No.";
+
+        // [WHEN] Change quantity on the last Take line.
+        NewQty := LibraryRandom.RandIntInRange(50, 80);
+        WarehouseActivityLine.SetRange("Action Type", WarehouseActivityLine."Action Type"::Take);
+        WarehouseActivityLine.SetRange("Line No.", LastTakeLineNo);
+        WarehouseActivityLine.FindFirst();
+        WarehouseActivityLine.Validate(Quantity, NewQty);
+        WarehouseActivityLine.Modify(true);
+
+        // [THEN] The Place line corresponding to the last Take line should be updated.
+        WarehouseActivityLine.SetRange("Action Type", WarehouseActivityLine."Action Type"::Place);
+        WarehouseActivityLine.SetRange("Line No.", LastPlaceLineNo);
+        WarehouseActivityLine.FindFirst();
+        Assert.AreEqual(
+            NewQty,
+            WarehouseActivityLine.Quantity,
+            'The Place line corresponding to the last Take line should be updated to the new quantity.');
+
+        // [THEN] The first Place line should NOT be updated (remains at original quantity).
+        WarehouseActivityLine.SetRange("Line No.", FirstPlaceLineNo);
+        WarehouseActivityLine.FindFirst();
+        Assert.AreEqual(
+            QuantityPerBin,
+            WarehouseActivityLine.Quantity,
+            'The first Place line should NOT be updated when changing quantity on the last Take line.');
+    end;
+
