diff --git a/App/Layers/W1/Tests/SCM/ItemRenameWithVariants.Codeunit.al b/App/Layers/W1/Tests/SCM/ItemRenameWithVariants.Codeunit.al
new file mode 100644
index 00000000..79c3df60
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM/ItemRenameWithVariants.Codeunit.al
@@ -0,0 +1,110 @@
+codeunit 139500 "Item Rename With Variants"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Item] [Item Variant] [Rename]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryUtility: Codeunit "Library - Utility";
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure RenameItemWithVariantAndValueEntriesSucceeds()
+    var
+        Item: Record Item;
+        ItemVariant: Record "Item Variant";
+        ValueEntry: Record "Value Entry";
+        OldItemNo: Code[20];
+        NewItemNo: Code[20];
+        VariantCode: Code[10];
+    begin
+        // [SCENARIO 26.0] Renaming an Item should succeed when Item Variants have Value Entries with Variant Code
+        // This tests the fix for the issue where Item renaming failed with error:
+        // "You cannot rename Item No. in a Item Variant, because it is used in Value Entry."
+        Initialize();
+
+        // [GIVEN] An Item with an Item Variant
+        LibraryInventory.CreateItem(Item);
+        OldItemNo := Item."No.";
+        LibraryInventory.CreateItemVariant(ItemVariant, Item."No.");
+        VariantCode := ItemVariant.Code;
+
+        // [GIVEN] Item Journal entries are posted for the Item with Variant Code, creating Value Entries
+        CreateAndPostItemJournalLine(Item."No.", VariantCode, LibraryRandom.RandIntInRange(10, 100));
+
+        // [GIVEN] Item Journal entries are posted for the Item without Variant Code (blank variant)
+        CreateAndPostItemJournalLine(Item."No.", '', LibraryRandom.RandIntInRange(10, 100));
+
+        // [GIVEN] Value Entries exist for both the variant and blank variant
+        ValueEntry.SetRange("Item No.", OldItemNo);
+        ValueEntry.SetRange("Variant Code", VariantCode);
+        Assert.RecordIsNotEmpty(ValueEntry);
+
+        ValueEntry.SetRange("Variant Code", '');
+        Assert.RecordIsNotEmpty(ValueEntry);
+
+        // [WHEN] The Item is renamed to a new Item No.
+        NewItemNo := LibraryUtility.GenerateGUID();
+        Item.Get(OldItemNo);
+        Item.Rename(NewItemNo);
+
+        // [THEN] The Item is successfully renamed
+        Assert.IsFalse(Item.Get(OldItemNo), 'Old Item No. should not exist after rename');
+        Assert.IsTrue(Item.Get(NewItemNo), 'New Item No. should exist after rename');
+
+        // [THEN] The Item Variant is updated with the new Item No.
+        ItemVariant.SetRange("Item No.", NewItemNo);
+        ItemVariant.SetRange(Code, VariantCode);
+        Assert.RecordIsNotEmpty(ItemVariant);
+
+        // [THEN] Value Entries are updated with the new Item No.
+        ValueEntry.Reset();
+        ValueEntry.SetRange("Item No.", NewItemNo);
+        ValueEntry.SetFilter("Variant Code", '%1|%2', VariantCode, '');
+        Assert.RecordIsNotEmpty(ValueEntry);
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"Item Rename With Variants");
+
+        if isInitialized then
+            exit;
+
+        isInitialized := true;
+        Commit();
+    end;
+
+    local procedure CreateAndPostItemJournalLine(ItemNo: Code[20]; VariantCode: Code[10]; Qty: Decimal)
+    var
+        ItemJournalTemplate: Record "Item Journal Template";
+        ItemJournalBatch: Record "Item Journal Batch";
+        ItemJournalLine: Record "Item Journal Line";
+    begin
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Item);
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalTemplate.Type::Item, ItemJournalTemplate.Name);
+        LibraryInventory.ClearItemJournal(ItemJournalTemplate, ItemJournalBatch);
+
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine,
+            ItemJournalTemplate.Name,
+            ItemJournalBatch.Name,
+            ItemJournalLine."Entry Type"::"Positive Adjmt.",
+            ItemNo,
+            Qty);
+        ItemJournalLine.Validate("Variant Code", VariantCode);
+        ItemJournalLine.Validate("Unit Amount", LibraryRandom.RandDec(100, 2));
+        ItemJournalLine.Modify(true);
+
+        LibraryInventory.PostItemJournalLine(ItemJournalTemplate.Name, ItemJournalBatch.Name);
+    end;
+}

diff --git a/App/Apps/W1/AutomaticAccountCodes/test/src/AACAutoAccGroupPosting.Codeunit.al b/App/Apps/W1/AutomaticAccountCodes/test/src/AACAutoAccGroupPosting.Codeunit.al
