+
+codeunit 137084 "SCM Production Order VI"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Manufacturing] [Production Order] [SCM]
+        IsInitialized := false;
+    end;
+
+    var
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryRandom: Codeunit "Library - Random";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure ProdOrderCompQtyPerIsNotZeroWhenCompItemUOMHasQtyRoundingPrecisionOne()
+    var
+        ComponentItem: Record Item;
+        FinishedGoodItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ProductionOrder: Record "Production Order";
+        ProdOrderLine: Record "Prod. Order Line";
+        ProdOrderComponent: Record "Prod. Order Component";
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        QuantityPer: Decimal;
+    begin
+        // [FEATURE] [Production Order] [Component] [Qty. Rounding Precision]
+        // [SCENARIO] When a component's Item UOM has 'Qty. Rounding Precision' = 1, and Production BOM has partial 'Quantity Per', 
+        // the Prod. Order Component should show correct 'Quantity per' and 'Expected Quantity' instead of 0.
+        Initialize();
+
+        // [GIVEN] Component Item "COMP" with Replenishment System = Purchase, Rounding Precision = 0.01
+        // [GIVEN] Base Unit of Measure "PCS" with "Qty. Rounding Precision" = 1
+        LibraryInventory.CreateItem(ComponentItem);
+        ComponentItem.Validate("Replenishment System", ComponentItem."Replenishment System"::Purchase);
+        ComponentItem.Validate("Rounding Precision", 0.01);
+        ComponentItem.Modify(true);
+
+        ItemUnitOfMeasure.Get(ComponentItem."No.", ComponentItem."Base Unit of Measure");
+        ItemUnitOfMeasure."Qty. Rounding Precision" := 1;
+        ItemUnitOfMeasure.Modify(true);
+
+        // [GIVEN] Production BOM with Component Item "COMP" with Quantity Per = 0.09
+        QuantityPer := 0.09;
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ComponentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItem."No.", QuantityPer);
+        LibraryManufacturing.UpdateProductionBOMStatus(ProductionBOMHeader, ProductionBOMHeader.Status::Certified);
+
+        // [GIVEN] Finished Good Item "FG" with Replenishment System = Prod. Order, Rounding Precision = 1
+        LibraryInventory.CreateItem(FinishedGoodItem);
+        FinishedGoodItem.Validate("Replenishment System", FinishedGoodItem."Replenishment System"::"Prod. Order");
+        FinishedGoodItem.Validate("Rounding Precision", 1);
+        FinishedGoodItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        FinishedGoodItem.Modify(true);
+
+        // [WHEN] Create and refresh Released Production Order for 1 qty of "FG"
+        LibraryManufacturing.CreateProductionOrder(
+            ProductionOrder, ProductionOrder.Status::Released, 
+            ProductionOrder."Source Type"::Item, FinishedGoodItem."No.", 1);
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, true, true, true, false);
+
+        // [THEN] Prod. Order Component for "COMP" has "Quantity per" = 0.09 (not 0)
+        ProdOrderLine.SetRange(Status, ProductionOrder.Status);
+        ProdOrderLine.SetRange("Prod. Order No.", ProductionOrder."No.");
+        ProdOrderLine.FindFirst();
+
+        ProdOrderComponent.SetRange(Status, ProdOrderLine.Status);
+        ProdOrderComponent.SetRange("Prod. Order No.", ProdOrderLine."Prod. Order No.");
+        ProdOrderComponent.SetRange("Prod. Order Line No.", ProdOrderLine."Line No.");
+        ProdOrderComponent.SetRange("Item No.", ComponentItem."No.");
+        ProdOrderComponent.FindFirst();
+
+        Assert.AreEqual(QuantityPer, ProdOrderComponent."Quantity per", 
+            'Quantity per should be ' + Format(QuantityPer) + ' and not 0 when component Item UOM has Qty. Rounding Precision = 1');
+        Assert.AreEqual(QuantityPer, ProdOrderComponent."Expected Quantity", 
+            'Expected Quantity should be ' + Format(QuantityPer) + ' and not 0 when component Item UOM has Qty. Rounding Precision = 1');
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Production Order VI");
+
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM Production Order VI");
+
+        IsInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM Production Order VI");
+    end;
+}

