+        JobJnlPostBatch: Codeunit "Job Jnl.-Post Batch";
+        RecurringFrequency: DateFormula;
+        ExpectedUnitCost: Decimal;
+        ExpectedUnitPrice: Decimal;
+    begin
+        // [FEATURE] [Recurring Job Journal] [Variable Method]
+        // [SCENARIO] When posting a recurring job journal with Variable method, Unit Cost and Unit Price should be preserved for next period
+
+        // [GIVEN] Initialize test data
+        Initialize();
+
+        // [GIVEN] Create a recurring job journal template
+        CreateRecurringJobJournalTemplate(JobJournalTemplate);
+        CreateJobJournalBatch(JobJournalBatch, JobJournalTemplate.Name);
