+        // [GIVEN] Create a Resource with Unit Cost and Unit Price
+        LibraryResource.CreateResource(Resource, '');
+        Resource.Validate("Unit Cost", LibraryRandom.RandDecInRange(50, 100, 2));
+        Resource.Validate("Unit Price", LibraryRandom.RandDecInRange(100, 200, 2));
+        Resource.Modify(true);
