+        // [THEN] All values should be preserved (Fixed method)
+        Assert.AreEqual(ExpectedQuantity, JobJournalLine.Quantity, 'Quantity should be preserved with Fixed method');
+        Assert.AreEqual(ExpectedUnitCost, JobJournalLine."Unit Cost", 'Unit Cost should be preserved with Fixed method');
