+        GenJnlManagement: Codeunit GenJnlManagement;
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure VendorNameEmptyWhenAccountTypeIsGLAccount()
+    var
+        GenJournalTemplate: Record "Gen. Journal Template";
+        GenJournalBatch: Record "Gen. Journal Batch";
+        GLAccount: Record "G/L Account";
+        GeneralJournalBatches: TestPage "General Journal Batches";
+        PurchaseJournal: TestPage "Purchase Journal";
+    begin
+        // [SCENARIO] When Account Type is G/L Account in Purchase Journal, the Vendor Name column should be empty
+        // [GIVEN] A Purchase Journal template and batch
+        Initialize();
+
+        // Set the Purchase Journal to "Show More Columns" mode
+        GenJnlManagement.SetJournalSimplePageModePreference(false, PAGE::"Purchase Journal");
+
+        // Create Purchase Journal template and batch
+        CreatePurchaseJournalTemplateBatch(GenJournalTemplate, GenJournalBatch);
+        LibraryERM.CreateGLAccount(GLAccount);
+        GLAccount.Name := CopyStr(LibraryUtility.GenerateGUID(), 1, MaxStrLen(GLAccount.Name));
+        GLAccount.Modify();
+
+        // [WHEN] A new line is created with Account Type = G/L Account
+        PrepareGeneralJournalBatchesPage(GeneralJournalBatches, GenJournalBatch);
+        PurchaseJournal.Trap();
+        GeneralJournalBatches.EditJournal.Invoke();
+
+        PurchaseJournal.New();
+        PurchaseJournal."Account Type".SetValue("Gen. Journal Account Type"::"G/L Account");
+        PurchaseJournal."Account No.".SetValue(GLAccount."No.");
+
+        // [THEN] The Vendor Name field should be empty
+        Assert.AreEqual('', PurchaseJournal."<Vendor Name>".Value, 'Vendor Name should be empty when Account Type is G/L Account');
+
+        // [THEN] The Description field should contain the G/L Account Name
+        Assert.AreEqual(GLAccount.Name, PurchaseJournal.Description.Value, 'Description should contain the G/L Account Name');
+
+        PurchaseJournal.Close();
+        GeneralJournalBatches.Close();
+
+        // Reset to default mode
+        GenJnlManagement.SetJournalSimplePageModePreference(true, PAGE::"Purchase Journal");
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure VendorNameShowsVendorWhenAccountTypeIsVendor()
+    var
+        GenJournalTemplate: Record "Gen. Journal Template";
+        GenJournalBatch: Record "Gen. Journal Batch";
+        Vendor: Record Vendor;
+        GeneralJournalBatches: TestPage "General Journal Batches";
+        PurchaseJournal: TestPage "Purchase Journal";
+    begin
+        // [SCENARIO] When Account Type is Vendor in Purchase Journal, the Vendor Name column should show the vendor name
+        // [GIVEN] A Purchase Journal template and batch
+        Initialize();
+
+        // Set the Purchase Journal to "Show More Columns" mode
+        GenJnlManagement.SetJournalSimplePageModePreference(false, PAGE::"Purchase Journal");
+
+        // Create Purchase Journal template and batch
+        CreatePurchaseJournalTemplateBatch(GenJournalTemplate, GenJournalBatch);
+        LibraryPurchase.CreateVendor(Vendor);
+        Vendor.Name := CopyStr(LibraryUtility.GenerateGUID(), 1, MaxStrLen(Vendor.Name));
+        Vendor.Modify();
+
+        // [WHEN] A new line is created with Account Type = Vendor
+        PrepareGeneralJournalBatchesPage(GeneralJournalBatches, GenJournalBatch);
+        PurchaseJournal.Trap();
+        GeneralJournalBatches.EditJournal.Invoke();
+
+        PurchaseJournal.New();
+        PurchaseJournal."Account Type".SetValue("Gen. Journal Account Type"::Vendor);
+        PurchaseJournal."Account No.".SetValue(Vendor."No.");
+
+        // [THEN] The Vendor Name field should show the vendor's name
+        Assert.AreEqual(Vendor.Name, PurchaseJournal."<Vendor Name>".Value, 'Vendor Name should display the vendor name when Account Type is Vendor');
+
+        PurchaseJournal.Close();
+        GeneralJournalBatches.Close();
+
+        // Reset to default mode
+        GenJnlManagement.SetJournalSimplePageModePreference(true, PAGE::"Purchase Journal");
+    end;
+
+    local procedure Initialize()
+    begin
+        if IsInitialized then
+            exit;
+
+        LibraryERMCountryData.UpdateLocalData();
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        IsInitialized := true;
+    end;
+
+    local procedure CreatePurchaseJournalTemplateBatch(var GenJournalTemplate: Record "Gen. Journal Template"; var GenJournalBatch: Record "Gen. Journal Batch")
+    begin
+        LibraryERM.CreateGenJournalTemplate(GenJournalTemplate);
+        GenJournalTemplate.Validate(Type, GenJournalTemplate.Type::Purchases);
+        GenJournalTemplate.Modify(true);
+        LibraryERM.CreateGenJournalBatch(GenJournalBatch, GenJournalTemplate.Name);
+    end;
+
+    local procedure PrepareGeneralJournalBatchesPage(var GeneralJournalBatches: TestPage "General Journal Batches"; GenJournalBatch: Record "Gen. Journal Batch")
+    begin
+        GeneralJournalBatches.OpenEdit();
+        GeneralJournalBatches.FILTER.SetFilter("Journal Template Name", GenJournalBatch."Journal Template Name");
+        GeneralJournalBatches.GotoRecord(GenJournalBatch);
+    end;
+}

