+// ------------------------------------------------------------------------------------------------
+namespace Microsoft.Manufacturing.Test;
+
+using Microsoft.Inventory.Item;
+using Microsoft.Inventory.Requisition;
+using Microsoft.Manufacturing.Document;
+using Microsoft.Manufacturing.ProductionBOM;
+using Microsoft.Purchases.Setup;
+using Microsoft.Sales.Setup;
+using System.TestLibraries.Utilities;
+
+codeunit 137098 "SCM Planning Multi-Level BOM"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Planning] [Production BOM] [Multi-Level]
+        isInitialized := false;
+    end;
+
+    var
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        LibraryPlanning: Codeunit "Library - Planning";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        Assert: Codeunit Assert;
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure RegenPlanForSharedComponentInMultipleSubassemblies()
+    var
+        Item1: Record Item;
+        Item2A: Record Item;
+        Item2B: Record Item;
+        Item3: Record Item;
+        ProductionBOMHeaderL1: Record "Production BOM Header";
+        ProductionBOMHeaderL2: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ProductionOrder: Record "Production Order";
+        ProdOrderComponent: Record "Prod. Order Component";
+        RequisitionLine: Record "Requisition Line";
+    begin
+        // [SCENARIO] For an item that is consumed in multiple subassemblies, running planning worksheet
+        // should not suggest unnecessary changes when supply equals demand.
+        // 
+        // BOM Structure:
+        // Item1 (top-level)
+        //   ├── Item2A (subassembly)
+        //   │     └── Item3 (shared component)
+        //   └── Item2B (subassembly)
+        //         └── Item3 (shared component)
+        //
+        // When Item1 Qty=1 is produced, Item3 needs Qty=2 (1 for Item2A + 1 for Item2B).
+        // Planning should NOT create any lines since supply already equals demand.
+        Initialize();
+
+        // [GIVEN] Create Item3 (lowest level component) with Make-to-Order, Lot-for-Lot
+        CreateMakeToOrderItem(Item3);
+
+        // [GIVEN] Create Production BOM Level 2 with Item3 (used by both Item2A and Item2B)
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeaderL2, Item3."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeaderL2, ProductionBOMLine, '', ProductionBOMLine.Type::Item, Item3."No.", 1);
+        LibraryManufacturing.UpdateProductionBOMStatus(ProductionBOMHeaderL2, ProductionBOMHeaderL2.Status::Certified);
+
+        // [GIVEN] Create Item2A (subassembly) with Make-to-Order, Lot-for-Lot, using Level 2 BOM
+        CreateMakeToOrderItem(Item2A);
+        Item2A.Validate("Production BOM No.", ProductionBOMHeaderL2."No.");
+        Item2A.Modify(true);
+
+        // [GIVEN] Create Item2B (subassembly) with Make-to-Order, Lot-for-Lot, using Level 2 BOM
+        CreateMakeToOrderItem(Item2B);
+        Item2B.Validate("Production BOM No.", ProductionBOMHeaderL2."No.");
+        Item2B.Modify(true);
+
+        // [GIVEN] Create Production BOM Level 1 with Item2A and Item2B
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeaderL1, Item2A."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeaderL1, ProductionBOMLine, '', ProductionBOMLine.Type::Item, Item2A."No.", 1);
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeaderL1, ProductionBOMLine, '', ProductionBOMLine.Type::Item, Item2B."No.", 1);
+        LibraryManufacturing.UpdateProductionBOMStatus(ProductionBOMHeaderL1, ProductionBOMHeaderL1.Status::Certified);
+
+        // [GIVEN] Create Item1 (top-level) with Make-to-Order, Lot-for-Lot, using Level 1 BOM
+        CreateMakeToOrderItem(Item1);
+        Item1.Validate("Production BOM No.", ProductionBOMHeaderL1."No.");
+        Item1.Modify(true);
+
+        // [GIVEN] Calculate Low Level Code to ensure proper planning hierarchy
+        LibraryPlanning.CalculateLowLevelCode();
+
+        // [GIVEN] Create Released Production Order for Item1 with Quantity = 1
+        LibraryManufacturing.CreateAndRefreshProductionOrder(
+            ProductionOrder,
+            ProductionOrder.Status::Released,
+            ProductionOrder."Source Type"::Item,
+            Item1."No.",
+            1);
+
+        // [GIVEN] Verify that Item3 component quantity is 2 (used in both Item2A and Item2B)
+        ProdOrderComponent.SetRange(Status, ProductionOrder.Status);
+        ProdOrderComponent.SetRange("Prod. Order No.", ProductionOrder."No.");
+        ProdOrderComponent.SetRange("Item No.", Item3."No.");
+        ProdOrderComponent.CalcSums(Quantity);
+        Assert.AreEqual(2, ProdOrderComponent.Quantity, 'Item3 should have total quantity of 2 as it is used in both Item2A and Item2B');
+
+        // [WHEN] Calculate Regenerative Plan for Item3 only
+        Item3.SetRecFilter();
+        LibraryPlanning.CalcRegenPlanForPlanWksh(Item3, WorkDate(), CalcDate('<+1M>', WorkDate()));
+
+        // [THEN] No planning lines should be created for Item3 because supply equals demand
+        RequisitionLine.SetRange(Type, RequisitionLine.Type::Item);
+        RequisitionLine.SetRange("No.", Item3."No.");
+        Assert.RecordIsEmpty(RequisitionLine);
+    end;
+
+    local procedure Initialize()
+    var
+        RequisitionLine: Record "Requisition Line";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Planning Multi-Level BOM");
+
+        RequisitionLine.DeleteAll();
+
+        // Lazy Setup.
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Planning Multi-Level BOM");
+
+        NoSeriesSetup();
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Planning Multi-Level BOM");
+    end;
+
+    local procedure NoSeriesSetup()
+    var
+        PurchasesPayablesSetup: Record "Purchases & Payables Setup";
+        SalesReceivablesSetup: Record "Sales & Receivables Setup";
+    begin
+        PurchasesPayablesSetup.Get();
+        PurchasesPayablesSetup.Validate("Order Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        PurchasesPayablesSetup.Modify(true);
+
+        SalesReceivablesSetup.Get();
+        SalesReceivablesSetup.Validate("Order Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        SalesReceivablesSetup.Modify(true);
+    end;
+
+    local procedure CreateMakeToOrderItem(var Item: Record Item)
+    begin
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Replenishment System", Item."Replenishment System"::"Prod. Order");
+        Item.Validate("Manufacturing Policy", Item."Manufacturing Policy"::"Make-to-Order");
+        Item.Validate("Reordering Policy", Item."Reordering Policy"::"Lot-for-Lot");
+        Item.Modify(true);
+    end;
+}

