+codeunit 137950 "SCM BOM Cost Shares Blank BOM"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [BOM Tree] [Cost Shares] [SCM]
+        isInitialized := false;
+    end;
+
+    var
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryAssembly: Codeunit "Library - Assembly";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure RolledUpCapCostSameForBlankBOMAndNoBOM()
+    var
+        ParentItem: Record Item;
+        ChildItemWithBlankBOM: Record Item;
+        ChildItemWithNoBOM: Record Item;
+        ComponentItem: Record Item;
+        ParentProdBOMHeaderForBlank: Record "Production BOM Header";
+        ParentProdBOMLineForBlank: Record "Production BOM Line";
+        ParentProdBOMHeaderForNoBOM: Record "Production BOM Header";
+        ParentProdBOMLineForNoBOM: Record "Production BOM Line";
+        EmptyProdBOMHeader: Record "Production BOM Header";
+        BOMBufferBlank: Record "BOM Buffer";
+        BOMBufferNoBOM: Record "BOM Buffer";
+        CalculateBOMTree: Codeunit "Calculate BOM Tree";
+        ItemFilter: Record Item;
+        TreeType: Option " ",Availability,Cost;
+        QtyPer: Decimal;
+        ChildUnitCost: Decimal;
+        RolledUpCapCostBlankBOM: Decimal;
+        RolledUpCapCostNoBOM: Decimal;
+    begin
+        // [SCENARIO] Rolled-up Capacity Cost should be the same when a manufactured child item has
+        // an empty Production BOM (no lines) vs no Production BOM No. at all.
+        // This ensures consistency in BOM Cost Shares calculation.
+
+        // [GIVEN] Setup test data
+        Initialize();
+        QtyPer := LibraryRandom.RandIntInRange(2, 10);
+        ChildUnitCost := LibraryRandom.RandDecInRange(10, 100, 2);
+
+        // [GIVEN] Create a component item (leaf item with purchase replenishment)
+        LibraryInventory.CreateItem(ComponentItem);
+        ComponentItem.Validate("Unit Cost", ChildUnitCost);
+        ComponentItem.Modify(true);
+
+        // [GIVEN] Create child item with Replenishment System = Prod. Order and assign an EMPTY (blank) Production BOM
+        CreateManufacturedItemWithEmptyBOM(ChildItemWithBlankBOM, EmptyProdBOMHeader, ChildUnitCost);
+
+        // [GIVEN] Create parent item with Production BOM containing the child item with blank BOM
+        LibraryAssembly.CreateItem(ParentItem, ParentItem."Costing Method"::Standard, ParentItem."Replenishment System"::"Prod. Order", '', '');
+        LibraryManufacturing.CreateProductionBOMHeader(ParentProdBOMHeaderForBlank, ParentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ParentProdBOMHeaderForBlank, ParentProdBOMLineForBlank, '', ParentProdBOMLineForBlank.Type::Item, ChildItemWithBlankBOM."No.", QtyPer);
+        LibraryManufacturing.UpdateProductionBOMStatus(ParentProdBOMHeaderForBlank, ParentProdBOMHeaderForBlank.Status::Certified);
+        ParentItem.Validate("Production BOM No.", ParentProdBOMHeaderForBlank."No.");
+        ParentItem.Modify(true);
+
+        // [WHEN] Calculate BOM Tree for the parent item with child having blank BOM
+        ItemFilter.SetRange("No.", ParentItem."No.");
+        CalculateBOMTree.GenerateTreeForItems(ItemFilter, BOMBufferBlank, TreeType::Cost);
+
+        // [THEN] Get Rolled-up Capacity Cost for the child item with blank BOM
+        BOMBufferBlank.SetRange(Type, BOMBufferBlank.Type::Item);
+        BOMBufferBlank.SetRange("No.", ChildItemWithBlankBOM."No.");
+        BOMBufferBlank.FindFirst();
+        RolledUpCapCostBlankBOM := BOMBufferBlank."Rolled-up Capacity Cost";
+
+        // [GIVEN] Create child item with Replenishment System = Prod. Order but NO Production BOM No.
+        CreateManufacturedItemWithNoBOM(ChildItemWithNoBOM, ChildUnitCost);
+
+        // [GIVEN] Create another parent item with Production BOM containing the child item with no BOM
+        Clear(ParentItem);
+        LibraryAssembly.CreateItem(ParentItem, ParentItem."Costing Method"::Standard, ParentItem."Replenishment System"::"Prod. Order", '', '');
+        LibraryManufacturing.CreateProductionBOMHeader(ParentProdBOMHeaderForNoBOM, ParentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ParentProdBOMHeaderForNoBOM, ParentProdBOMLineForNoBOM, '', ParentProdBOMLineForNoBOM.Type::Item, ChildItemWithNoBOM."No.", QtyPer);
+        LibraryManufacturing.UpdateProductionBOMStatus(ParentProdBOMHeaderForNoBOM, ParentProdBOMHeaderForNoBOM.Status::Certified);
+        ParentItem.Validate("Production BOM No.", ParentProdBOMHeaderForNoBOM."No.");
+        ParentItem.Modify(true);
+
+        // [WHEN] Calculate BOM Tree for the parent item with child having no BOM
+        Clear(BOMBufferNoBOM);
+        Clear(ItemFilter);
+        ItemFilter.SetRange("No.", ParentItem."No.");
+        CalculateBOMTree.GenerateTreeForItems(ItemFilter, BOMBufferNoBOM, TreeType::Cost);
+
+        // [THEN] Get Rolled-up Capacity Cost for the child item with no BOM
+        BOMBufferNoBOM.SetRange(Type, BOMBufferNoBOM.Type::Item);
+        BOMBufferNoBOM.SetRange("No.", ChildItemWithNoBOM."No.");
+        BOMBufferNoBOM.FindFirst();
+        RolledUpCapCostNoBOM := BOMBufferNoBOM."Rolled-up Capacity Cost";
+
+        // [THEN] Rolled-up Capacity Cost should be the same for both scenarios
+        // (blank BOM = no BOM, so both should result in identical cost calculation)
+        Assert.AreEqual(
+            RolledUpCapCostBlankBOM,
+            RolledUpCapCostNoBOM,
+            'Rolled-up Capacity Cost should be equal for child items with empty BOM vs no BOM');
+
+        // [THEN] Both Rolled-up Capacity Costs should be zero since neither child has actual capacity costs
+        Assert.AreEqual(
+            0,
+            RolledUpCapCostBlankBOM,
+            'Rolled-up Capacity Cost should be zero for manufactured item with no BOM structure');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure RolledUpMaterialCostSameForBlankBOMAndNoBOM()
+    var
+        ParentItem: Record Item;
+        ChildItemWithBlankBOM: Record Item;
+        ChildItemWithNoBOM: Record Item;
+        ParentProdBOMHeaderForBlank: Record "Production BOM Header";
+        ParentProdBOMLineForBlank: Record "Production BOM Line";
+        ParentProdBOMHeaderForNoBOM: Record "Production BOM Header";
+        ParentProdBOMLineForNoBOM: Record "Production BOM Line";
+        EmptyProdBOMHeader: Record "Production BOM Header";
+        BOMBufferBlank: Record "BOM Buffer";
+        BOMBufferNoBOM: Record "BOM Buffer";
+        CalculateBOMTree: Codeunit "Calculate BOM Tree";
+        ItemFilter: Record Item;
+        TreeType: Option " ",Availability,Cost;
+        QtyPer: Decimal;
+        ChildUnitCost: Decimal;
+        RolledUpMaterialCostBlankBOM: Decimal;
+        RolledUpMaterialCostNoBOM: Decimal;
+    begin
+        // [SCENARIO] Rolled-up Material Cost should be the same when a manufactured child item has
+        // an empty Production BOM (no lines) vs no Production BOM No. at all.
+
+        // [GIVEN] Setup test data
+        Initialize();
+        QtyPer := LibraryRandom.RandIntInRange(2, 10);
+        ChildUnitCost := LibraryRandom.RandDecInRange(10, 100, 2);
+
+        // [GIVEN] Create child item with Replenishment System = Prod. Order and assign an EMPTY (blank) Production BOM
+        CreateManufacturedItemWithEmptyBOM(ChildItemWithBlankBOM, EmptyProdBOMHeader, ChildUnitCost);
+
+        // [GIVEN] Create parent item with Production BOM containing the child item with blank BOM
+        LibraryAssembly.CreateItem(ParentItem, ParentItem."Costing Method"::Standard, ParentItem."Replenishment System"::"Prod. Order", '', '');
+        LibraryManufacturing.CreateProductionBOMHeader(ParentProdBOMHeaderForBlank, ParentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ParentProdBOMHeaderForBlank, ParentProdBOMLineForBlank, '', ParentProdBOMLineForBlank.Type::Item, ChildItemWithBlankBOM."No.", QtyPer);
+        LibraryManufacturing.UpdateProductionBOMStatus(ParentProdBOMHeaderForBlank, ParentProdBOMHeaderForBlank.Status::Certified);
+        ParentItem.Validate("Production BOM No.", ParentProdBOMHeaderForBlank."No.");
+        ParentItem.Modify(true);
+
+        // [WHEN] Calculate BOM Tree for the parent item with child having blank BOM
+        ItemFilter.SetRange("No.", ParentItem."No.");
+        CalculateBOMTree.GenerateTreeForItems(ItemFilter, BOMBufferBlank, TreeType::Cost);
+
+        // [THEN] Get Rolled-up Material Cost for the child item with blank BOM
+        BOMBufferBlank.SetRange(Type, BOMBufferBlank.Type::Item);
+        BOMBufferBlank.SetRange("No.", ChildItemWithBlankBOM."No.");
+        BOMBufferBlank.FindFirst();
+        RolledUpMaterialCostBlankBOM := BOMBufferBlank."Rolled-up Material Cost";
+
+        // [GIVEN] Create child item with Replenishment System = Prod. Order but NO Production BOM No.
+        CreateManufacturedItemWithNoBOM(ChildItemWithNoBOM, ChildUnitCost);
+
+        // [GIVEN] Create another parent item with Production BOM containing the child item with no BOM
+        Clear(ParentItem);
+        LibraryAssembly.CreateItem(ParentItem, ParentItem."Costing Method"::Standard, ParentItem."Replenishment System"::"Prod. Order", '', '');
+        LibraryManufacturing.CreateProductionBOMHeader(ParentProdBOMHeaderForNoBOM, ParentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ParentProdBOMHeaderForNoBOM, ParentProdBOMLineForNoBOM, '', ParentProdBOMLineForNoBOM.Type::Item, ChildItemWithNoBOM."No.", QtyPer);
+        LibraryManufacturing.UpdateProductionBOMStatus(ParentProdBOMHeaderForNoBOM, ParentProdBOMHeaderForNoBOM.Status::Certified);
+        ParentItem.Validate("Production BOM No.", ParentProdBOMHeaderForNoBOM."No.");
+        ParentItem.Modify(true);
+
+        // [WHEN] Calculate BOM Tree for the parent item with child having no BOM
+        Clear(BOMBufferNoBOM);
+        Clear(ItemFilter);
+        ItemFilter.SetRange("No.", ParentItem."No.");
+        CalculateBOMTree.GenerateTreeForItems(ItemFilter, BOMBufferNoBOM, TreeType::Cost);
+
+        // [THEN] Get Rolled-up Material Cost for the child item with no BOM
+        BOMBufferNoBOM.SetRange(Type, BOMBufferNoBOM.Type::Item);
+        BOMBufferNoBOM.SetRange("No.", ChildItemWithNoBOM."No.");
+        BOMBufferNoBOM.FindFirst();
+        RolledUpMaterialCostNoBOM := BOMBufferNoBOM."Rolled-up Material Cost";
+
+        // [THEN] Rolled-up Material Cost should be the same for both scenarios
+        Assert.AreEqual(
+            RolledUpMaterialCostBlankBOM,
+            RolledUpMaterialCostNoBOM,
+            'Rolled-up Material Cost should be equal for child items with empty BOM vs no BOM');
+
+        // [THEN] Both should reflect the item's unit cost multiplied by quantity
+        Assert.AreNearlyEqual(
+            ChildUnitCost * QtyPer,
+            RolledUpMaterialCostBlankBOM,
+            LibraryERM.GetUnitAmountRoundingPrecision(),
+            'Rolled-up Material Cost should equal Unit Cost * Qty Per for manufactured item with no BOM structure');
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM BOM Cost Shares Blank BOM");
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM BOM Cost Shares Blank BOM");
+
+        // Setup Demonstration data.
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM BOM Cost Shares Blank BOM");
+    end;
+
+    local procedure CreateManufacturedItemWithEmptyBOM(var Item: Record Item; var EmptyProdBOMHeader: Record "Production BOM Header"; UnitCost: Decimal)
+    begin
+        // Create item with Replenishment System = Prod. Order
+        LibraryAssembly.CreateItem(Item, Item."Costing Method"::Standard, Item."Replenishment System"::"Prod. Order", '', '');
+        Item.Validate("Unit Cost", UnitCost);
+        Item.Validate("Standard Cost", UnitCost);
+        Item.Modify(true);
+
+        // Create an empty Production BOM (no lines) and certify it
+        LibraryManufacturing.CreateProductionBOMHeader(EmptyProdBOMHeader, Item."Base Unit of Measure");
+        // Do NOT add any lines - this is intentionally an empty BOM
+        LibraryManufacturing.UpdateProductionBOMStatus(EmptyProdBOMHeader, EmptyProdBOMHeader.Status::Certified);
+
+        // Assign the empty BOM to the item
+        Item.Validate("Production BOM No.", EmptyProdBOMHeader."No.");
+        Item.Modify(true);
+    end;
+
+    local procedure CreateManufacturedItemWithNoBOM(var Item: Record Item; UnitCost: Decimal)
+    begin
+        // Create item with Replenishment System = Prod. Order but NO Production BOM No.
+        LibraryAssembly.CreateItem(Item, Item."Costing Method"::Standard, Item."Replenishment System"::"Prod. Order", '', '');
+        Item.Validate("Unit Cost", UnitCost);
+        Item.Validate("Standard Cost", UnitCost);
+        // Leave Production BOM No. empty
+        Item.Validate("Production BOM No.", '');
+        Item.Modify(true);
+    end;
+}

