+codeunit 137933 "SCM Inv Tracking Shipment Line"
+{
+    // [FEATURE] [Item Tracking] [Sales Invoice] [Get Shipment Lines]
+    // Tests for preserving item tracking lines when quantity is reduced on sales invoice lines
+    // created via Get Shipment Lines function.
+
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        isInitialized := false;
+    end;
+
+    var
+        ItemJournalTemplate: Record "Item Journal Template";
+        ItemJournalBatch: Record "Item Journal Batch";
+        LocationBlue: Record Location;
+        ItemTrackingCodeLotSpecific: Record "Item Tracking Code";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryItemTracking: Codeunit "Library - Item Tracking";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        isInitialized: Boolean;
+        AssignTracking: Option "None",SerialNo,LotNo;
+        GlobalItemNo: Code[20];
+
+    [Test]
+    [HandlerFunctions('ItemTrackingPageHandler,ItemTrackingSummaryPageHandler,GetShipmentLinesPageHandler')]
+    [Scope('OnPrem')]
+    procedure ItemTrackingPreservedWhenReducingQtyOnInvoiceFromShipment()
+    var
+        Customer: Record Customer;
+        Item: Record Item;
+        ItemJournalLine: Record "Item Journal Line";
+        SalesHeaderOrder: Record "Sales Header";
+        SalesHeaderInvoice: Record "Sales Header";
+        SalesLineOrder: Record "Sales Line";
+        SalesLineInvoice: Record "Sales Line";
+        ReservationEntry: Record "Reservation Entry";
+        OriginalQty: Decimal;
+        ReducedQty: Decimal;
+    begin
+        // [FEATURE] [Item Tracking] [Sales Invoice] [Get Shipment Lines]
+        // [SCENARIO] Item tracking lines are preserved when quantity is reduced on a sales invoice line
+        // that was created from a shipped sales order using Get Shipment Lines function.
+        // This is the fix for the bug where changing quantity from 3 to 2 would clear all tracking lines.
+        Initialize();
+
+        // [GIVEN] Customer
+        LibrarySales.CreateCustomer(Customer);
+
+        // [GIVEN] Item with Lot Tracking Code and Reserve = Always, Costing Method = FIFO
+        CreateItemWithLotTrackingAndReserveAlways(Item);
+
+        // [GIVEN] Post positive inventory adjustment with Lot Item Tracking
+        OriginalQty := LibraryRandom.RandIntInRange(3, 10);
+        CreateAndPostItemJournalLine(
+          ItemJournalLine."Entry Type"::"Positive Adjmt.", Item."No.", LocationBlue.Code,
+          OriginalQty, LibraryRandom.RandIntInRange(10, 20), AssignTracking::LotNo);
+
+        // [GIVEN] Create and ship Sales Order with Lot Item Tracking (ship only, no invoice)
+        SetGlobalValue(Item."No.", AssignTracking::None);
+        CreateAndShipSalesOrderWithTracking(
+          SalesHeaderOrder, SalesLineOrder, Customer."No.", Item."No.", LocationBlue.Code, OriginalQty);
+
+        // [GIVEN] Create Sales Invoice and get lines from the shipped Sales Shipment
+        LibrarySales.CreateSalesHeader(SalesHeaderInvoice, SalesHeaderInvoice."Document Type"::Invoice, Customer."No.");
+        SalesLineInvoice."Document Type" := SalesHeaderInvoice."Document Type";
+        SalesLineInvoice."Document No." := SalesHeaderInvoice."No.";
+        LibrarySales.GetShipmentLines(SalesLineInvoice);
+
+        // [GIVEN] Verify item tracking exists before reducing quantity
+        FindSalesInvoiceLine(SalesLineInvoice, SalesHeaderInvoice."No.", Item."No.");
+        FilterReservationEntryBySource(
+          ReservationEntry, DATABASE::"Sales Line", SalesLineInvoice."Document Type".AsInteger(),
+          SalesLineInvoice."Document No.", SalesLineInvoice."Line No.");
+        Assert.RecordIsNotEmpty(ReservationEntry);
+
+        // [WHEN] Reduce quantity on the sales invoice line (e.g., from 3 to 2)
+        ReducedQty := OriginalQty - 1;
+        SalesLineInvoice.Validate(Quantity, ReducedQty);
+        SalesLineInvoice.Modify(true);
+
+        // [THEN] Item tracking for Sales Invoice line is preserved (not deleted)
+        FilterReservationEntryBySource(
+          ReservationEntry, DATABASE::"Sales Line", SalesLineInvoice."Document Type".AsInteger(),
+          SalesLineInvoice."Document No.", SalesLineInvoice."Line No.");
+        Assert.RecordIsNotEmpty(ReservationEntry);
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Inv Tracking Shipment Line");
+        LibraryVariableStorage.Clear();
+        ClearGlobals();
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM Inv Tracking Shipment Line");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.CreateGeneralPostingSetupData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateGeneralLedgerSetup();
+        LibraryERMCountryData.UpdateSalesReceivablesSetup();
+
+        NoSeriesSetup();
+        CreateLocationSetup();
+        ItemTrackingCodeSetup();
+        ItemJournalSetup();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM Inv Tracking Shipment Line");
+    end;
+
+    local procedure ClearGlobals()
+    begin
+        Clear(GlobalItemNo);
+        Clear(AssignTracking);
+    end;
+
+    local procedure NoSeriesSetup()
+    var
+        SalesReceivablesSetup: Record "Sales & Receivables Setup";
+    begin
+        SalesReceivablesSetup.Get();
+        SalesReceivablesSetup.Validate("Order Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        SalesReceivablesSetup.Validate("Posted Invoice Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        SalesReceivablesSetup.Validate("Posted Shipment Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        SalesReceivablesSetup.Modify(true);
+    end;
+
+    local procedure CreateLocationSetup()
+    begin
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(LocationBlue);
+    end;
+
+    local procedure ItemTrackingCodeSetup()
+    begin
+        LibraryItemTracking.CreateItemTrackingCode(ItemTrackingCodeLotSpecific, false, true);
+    end;
+
+    local procedure ItemJournalSetup()
+    begin
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Item);
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalTemplate.Type::Item, ItemJournalTemplate.Name);
+        LibraryInventory.ClearItemJournal(ItemJournalTemplate, ItemJournalBatch);
+    end;
+
+    local procedure CreateItemWithLotTrackingAndReserveAlways(var Item: Record Item)
+    begin
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Item Tracking Code", ItemTrackingCodeLotSpecific.Code);
+        Item.Validate("Lot Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        Item.Validate("Costing Method", Item."Costing Method"::FIFO);
+        Item.Validate(Reserve, Item.Reserve::Always);
+        Item.Modify(true);
+    end;
+
+    local procedure CreateAndPostItemJournalLine(EntryType: Enum "Item Ledger Entry Type"; ItemNo: Code[20]; LocationCode: Code[10]; Quantity: Decimal; UnitAmount: Decimal; AssignTrackingValue: Option)
+    var
+        ItemJournalLine: Record "Item Journal Line";
+    begin
+        LibraryInventory.ClearItemJournal(ItemJournalTemplate, ItemJournalBatch);
+        LibraryInventory.CreateItemJournalLine(
+          ItemJournalLine, ItemJournalTemplate.Name, ItemJournalBatch.Name, EntryType, ItemNo, Quantity);
+        ItemJournalLine.Validate("Location Code", LocationCode);
+        ItemJournalLine.Validate("Unit Amount", UnitAmount);
+        ItemJournalLine.Modify(true);
+
+        SetGlobalValue(ItemNo, AssignTrackingValue);
+        ItemJournalLine.OpenItemTrackingLines(false);
+
+        LibraryInventory.PostItemJournalLine(ItemJournalTemplate.Name, ItemJournalBatch.Name);
+    end;
+
+    local procedure CreateAndShipSalesOrderWithTracking(var SalesHeader: Record "Sales Header"; var SalesLine: Record "Sales Line"; CustomerNo: Code[20]; ItemNo: Code[20]; LocationCode: Code[10]; Quantity: Decimal)
+    begin
+        CreateSalesDocument(SalesHeader, SalesLine, SalesHeader."Document Type"::Order, ItemNo, LocationCode, Quantity, CustomerNo);
+        SalesLine.OpenItemTrackingLines();
+        LibrarySales.PostSalesDocument(SalesHeader, true, false);
+    end;
+
+    local procedure CreateSalesDocument(var SalesHeader: Record "Sales Header"; var SalesLine: Record "Sales Line"; DocumentType: Enum "Sales Document Type"; ItemNo: Code[20]; LocationCode: Code[10]; Quantity: Decimal; CustomerNo: Code[20])
+    begin
+        LibrarySales.CreateSalesHeader(SalesHeader, DocumentType, CustomerNo);
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, ItemNo, Quantity);
+        SalesLine.Validate("Location Code", LocationCode);
+        SalesLine.Modify(true);
+    end;
+
+    local procedure FindSalesInvoiceLine(var SalesLine: Record "Sales Line"; DocumentNo: Code[20]; ItemNo: Code[20])
+    begin
+        SalesLine.SetRange("Document Type", SalesLine."Document Type"::Invoice);
+        SalesLine.SetRange("Document No.", DocumentNo);
+        SalesLine.SetRange("No.", ItemNo);
+        SalesLine.FindFirst();
+    end;
+
+    local procedure FilterReservationEntryBySource(var ReservationEntry: Record "Reservation Entry"; SourceType: Integer; SourceSubtype: Option; SourceID: Code[20]; SourceRefNo: Integer)
+    begin
+        ReservationEntry.SetRange("Source Type", SourceType);
+        ReservationEntry.SetRange("Source Subtype", SourceSubtype);
+        ReservationEntry.SetRange("Source ID", SourceID);
+        ReservationEntry.SetRange("Source Ref. No.", SourceRefNo);
+    end;
+
+    local procedure SetGlobalValue(ItemNo: Code[20]; AssignTrackingValue: Option)
+    begin
+        GlobalItemNo := ItemNo;
+        AssignTracking := AssignTrackingValue;
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure ItemTrackingPageHandler(var ItemTrackingLines: TestPage "Item Tracking Lines")
+    begin
+        case AssignTracking of
+            AssignTracking::LotNo:
+                ItemTrackingLines."Assign Lot No.".Invoke();
+        end;
+        ItemTrackingLines.OK().Invoke();
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure ItemTrackingSummaryPageHandler(var ItemTrackingSummary: TestPage "Item Tracking Summary")
+    begin
+        ItemTrackingSummary.OK().Invoke();
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure GetShipmentLinesPageHandler(var GetShipmentLines: TestPage "Get Shipment Lines")
+    begin
+        GetShipmentLines.OK().Invoke();
+    end;
+}

