diff --git a/App/Layers/W1/Tests/Marketing/ContactNextTaskDate.Codeunit.al b/App/Layers/W1/Tests/Marketing/ContactNextTaskDate.Codeunit.al
new file mode 100644
index 00000000..c631ffcd
--- /dev/null
+++ b/App/Layers/W1/Tests/Marketing/ContactNextTaskDate.Codeunit.al
@@ -0,0 +1,127 @@
+codeunit 136299 "Contact Next Task Date"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Contact] [Task] [Marketing]
+    end;
+
+    var
+        LibraryMarketing: Codeunit "Library - Marketing";
+        LibrarySales: Codeunit "Library - Sales";
+        Assert: Codeunit Assert;
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure NextTaskDateShowsOrganizerTypeTask()
+    var
+        PersonContact: Record Contact;
+        Task: Record "To-do";
+        SalespersonPurchaser: Record "Salesperson/Purchaser";
+        TaskDate: Date;
+    begin
+        // [SCENARIO] Next Task Date on Contact Card should show tasks with System To-do Type = Organizer
+        // [GIVEN] A Person Contact with Company No.
+        Initialize();
+        LibraryMarketing.CreatePersonContactWithCompanyNo(PersonContact);
+        LibrarySales.CreateSalesperson(SalespersonPurchaser);
+
+        // [GIVEN] A Phone Call task linked to the Contact with System To-do Type = Organizer
+        TaskDate := WorkDate() + 5;
+        CreateOrganizerTask(Task, PersonContact."No.", SalespersonPurchaser.Code, TaskDate);
+
+        // [WHEN] Next Task Date is calculated on the Contact
+        PersonContact.Get(PersonContact."No.");
+        PersonContact.CalcFields("Next Task Date");
+
+        // [THEN] Next Task Date equals the task's Date
+        Assert.AreEqual(TaskDate, PersonContact."Next Task Date", 'Next Task Date should show the Organizer type task date.');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure NextTaskDateShowsMinimumOfOrganizerAndContactAttendeeTasks()
+    var
+        PersonContact: Record Contact;
+        OrganizerTask: Record "To-do";
+        ContactAttendeeTask: Record "To-do";
+        SalespersonPurchaser: Record "Salesperson/Purchaser";
+        OrganizerTaskDate: Date;
+        ContactAttendeeTaskDate: Date;
+    begin
+        // [SCENARIO] Next Task Date should show the minimum date from both Organizer and Contact Attendee type tasks
+        // [GIVEN] A Person Contact with Company No.
+        Initialize();
+        LibraryMarketing.CreatePersonContactWithCompanyNo(PersonContact);
+        LibrarySales.CreateSalesperson(SalespersonPurchaser);
+
+        // [GIVEN] An Organizer type task with a later date
+        OrganizerTaskDate := WorkDate() + 10;
+        CreateOrganizerTask(OrganizerTask, PersonContact."No.", SalespersonPurchaser.Code, OrganizerTaskDate);
+
+        // [GIVEN] A Contact Attendee type task with an earlier date
+        ContactAttendeeTaskDate := WorkDate() + 5;
+        CreateContactAttendeeTask(ContactAttendeeTask, PersonContact, SalespersonPurchaser.Code, ContactAttendeeTaskDate);
+
+        // [WHEN] Next Task Date is calculated on the Contact
+        PersonContact.Get(PersonContact."No.");
+        PersonContact.CalcFields("Next Task Date");
+
+        // [THEN] Next Task Date shows the minimum date (Contact Attendee task date)
+        Assert.AreEqual(ContactAttendeeTaskDate, PersonContact."Next Task Date", 'Next Task Date should show the minimum of both task types.');
+    end;
+
+    local procedure Initialize()
+    var
+        MarketingSetup: Record "Marketing Setup";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Contact Next Task Date");
+
+        if IsInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Contact Next Task Date");
+
+        if not MarketingSetup.Get() then begin
+            MarketingSetup.Init();
+            MarketingSetup.Insert();
+        end;
+
+        IsInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Contact Next Task Date");
+    end;
+
+    local procedure CreateOrganizerTask(var Task: Record "To-do"; ContactNo: Code[20]; SalespersonCode: Code[20]; TaskDate: Date)
+    begin
+        // Create a task with System To-do Type = Organizer (default for non-Meeting, non-Team tasks)
+        Task.Init();
+        Task.Insert(true);
+        Task.Validate(Type, Task.Type::"Phone Call");
+        Task.Validate("Contact No.", ContactNo);
+        Task.Validate("Salesperson Code", SalespersonCode);
+        Task.Validate(Date, TaskDate);
+        Task.Modify(true);
+
+        // Verify the task has the correct System To-do Type
+        Assert.AreEqual(Task."System To-do Type"::Organizer, Task."System To-do Type", 'Task should have System To-do Type = Organizer');
+    end;
+
+    local procedure CreateContactAttendeeTask(var Task: Record "To-do"; PersonContact: Record Contact; SalespersonCode: Code[20]; TaskDate: Date)
+    begin
+        // Create a task and manually set System To-do Type to Contact Attendee
+        Task.Init();
+        Task.Insert(true);
+        Task.Validate(Type, Task.Type::"Phone Call");
+        Task.Validate("Contact No.", PersonContact."No.");
+        Task.Validate("Salesperson Code", SalespersonCode);
+        Task.Validate(Date, TaskDate);
+        Task."System To-do Type" := Task."System To-do Type"::"Contact Attendee";
+        Task.Modify(true);
+    end;
+}

