@@ -1527,6 +1527,123 @@ codeunit 137049 "SCM Reservation"
         RoundingIssuesRunScenario(DATABASE::"Sales Line", DATABASE::"Job Planning Line");
     end;

+    [Test]
+    [Scope('OnPrem')]
+    procedure CalcReservationQuantityIncludesTrackingEntries()
+    var
+        ReservationEntry: Record "Reservation Entry";
+        ReservationEntry2: Record "Reservation Entry";
+        ReservationEntry3: Record "Reservation Entry";
+        Item: Record Item;
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        LastEntryNo: Integer;
+        QtyPerUOM: Decimal;
+        QtyBase1: Decimal;
+        QtyBase2: Decimal;
+        QtyBase3: Decimal;
+        ExpectedTotalQty: Decimal;
+    begin
+        // [FEATURE] [Reservation Entry] [Order Tracking]
+        // [SCENARIO 330787] When calculating reservation quantity with non-base UOM, tracking entries are included
+        // in the calculation to prevent rounding errors when demand is split across multiple tracking lines.
+
+        // [GIVEN] An item with a non-base Unit of Measure CASE = 24 PCS
+        Initialize();
+        LibraryInventory.CreateItem(Item);
+        QtyPerUOM := 24;
+        LibraryInventory.CreateItemUnitOfMeasureCode(ItemUnitOfMeasure, Item."No.", QtyPerUOM);
+        Item.Validate("Sales Unit of Measure", ItemUnitOfMeasure.Code);
+        Item.Modify(true);
+
+        // [GIVEN] A Sales Order for 12 CASES (288 PCS base quantity)
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, LibrarySales.CreateCustomerNo());
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", 12);
+        SalesLine.Validate("Unit of Measure Code", ItemUnitOfMeasure.Code);
+        SalesLine.Modify(true);
+
+        // [GIVEN] Three tracking entries that split 288 PCS with quantities that cause rounding issues
+        // Using quantities that when divided by 24 and rounded individually will not sum to exactly 12
+        // but when the total base (288) is divided by 24, it equals exactly 12.
+        // Without the fix: Third entry ignores first two (Tracking status), causing rounding error
+        // With the fix: Third entry includes first two in calculation, giving correct result
+        QtyBase1 := -13;   // 13 / 24 = 0.54167
+        QtyBase2 := -137;  // 137 / 24 = 5.70833
+        QtyBase3 := -138;  // 138 / 24 = 5.75000
+        // Sum of individual rounded: 0.54167 + 5.70833 + 5.75000 = 12.00000
+        // But if calculated incorrectly: individual rounding may give 12.00001
+
+        // [GIVEN] First entry has Tracking status (from Order Tracking Policy)
+        if not ReservationEntry.FindLast() then
+            LastEntryNo := 0
+        else
+            LastEntryNo := ReservationEntry."Entry No.";
+
+        Clear(ReservationEntry);
+        ReservationEntry.Init();
+        ReservationEntry."Entry No." := LastEntryNo + 1;
+        ReservationEntry.Positive := false;
+        ReservationEntry."Reservation Status" := ReservationEntry."Reservation Status"::Tracking;
+        ReservationEntry."Item No." := Item."No.";
+        ReservationEntry."Source Type" := DATABASE::"Sales Line";
+        ReservationEntry."Source Subtype" := SalesLine."Document Type".AsInteger();
+        ReservationEntry."Source ID" := SalesLine."Document No.";
+        ReservationEntry."Source Ref. No." := SalesLine."Line No.";
+        ReservationEntry."Qty. per Unit of Measure" := QtyPerUOM;
+        ReservationEntry."Quantity (Base)" := QtyBase1;
+        ReservationEntry.Quantity := Round(QtyBase1 / QtyPerUOM, 0.00001);
+        ReservationEntry."Shipment Date" := WorkDate();
+        ReservationEntry.Insert();
+
+        // [GIVEN] Second entry has Tracking status
+        ReservationEntry2.Init();
+        ReservationEntry2."Entry No." := LastEntryNo + 2;
+        ReservationEntry2.Positive := false;
+        ReservationEntry2."Reservation Status" := ReservationEntry2."Reservation Status"::Tracking;
+        ReservationEntry2."Item No." := Item."No.";
+        ReservationEntry2."Source Type" := DATABASE::"Sales Line";
+        ReservationEntry2."Source Subtype" := SalesLine."Document Type".AsInteger();
+        ReservationEntry2."Source ID" := SalesLine."Document No.";
+        ReservationEntry2."Source Ref. No." := SalesLine."Line No.";
+        ReservationEntry2."Qty. per Unit of Measure" := QtyPerUOM;
+        ReservationEntry2."Quantity (Base)" := QtyBase2;
+        ReservationEntry2.Quantity := Round(QtyBase2 / QtyPerUOM, 0.00001);
+        ReservationEntry2."Shipment Date" := WorkDate();
+        ReservationEntry2.Insert();
+
+        // [WHEN] Third entry is created and its Quantity (Base) is validated
+        // This triggers CalcReservationQuantity which should include the other Tracking entries
+        ReservationEntry3.Init();
+        ReservationEntry3."Entry No." := LastEntryNo + 3;
+        ReservationEntry3.Positive := false;
+        ReservationEntry3."Reservation Status" := ReservationEntry3."Reservation Status"::Tracking;
+        ReservationEntry3."Item No." := Item."No.";
+        ReservationEntry3."Source Type" := DATABASE::"Sales Line";
+        ReservationEntry3."Source Subtype" := SalesLine."Document Type".AsInteger();
+        ReservationEntry3."Source ID" := SalesLine."Document No.";
+        ReservationEntry3."Source Ref. No." := SalesLine."Line No.";
+        ReservationEntry3."Qty. per Unit of Measure" := QtyPerUOM;
+        ReservationEntry3."Shipment Date" := WorkDate();
+        ReservationEntry3.Validate("Quantity (Base)", QtyBase3);
+        ReservationEntry3.Insert();
+
+        // [THEN] The calculated quantity should properly account for all entries
+        // Total base = 13 + 137 + 138 = 288
+        // Total in CASE UOM = 288 / 24 = 12 exactly (no rounding error)
+        ExpectedTotalQty := Round((QtyBase1 + QtyBase2 + QtyBase3) / QtyPerUOM, 0.00001);
+
+        ReservationEntry.Get(LastEntryNo + 1);
+        ReservationEntry2.Get(LastEntryNo + 2);
+        ReservationEntry3.Get(LastEntryNo + 3);
+
+        // [THEN] The sum of individual Quantity fields should equal the expected quantity (-12)
+        Assert.AreEqual(
+            ExpectedTotalQty,
+            ReservationEntry.Quantity + ReservationEntry2.Quantity + ReservationEntry3.Quantity,
+            'The sum of Quantity across tracking entries should equal expected value without rounding error.');
+    end;
+
     local procedure RoundingIssuesRunScenario(SupplySourceType: Option; DemandSourceType: Option)
     begin
         RoundingIssuesScenario(false, false, SupplySourceType, DemandSourceType);

