@@ -0,0 +1,316 @@
+codeunit 137950 "SCM Plan-Req. Wksht Surplus"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Planning] [Requisition Worksheet] [Item Tracking] [Reservation] [SCM]
+        isInitialized := false;
+    end;
+
+    var
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryPlanning: Codeunit "Library - Planning";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryPurchase: Codeunit "Library - Purchase";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        LibraryItemTracking: Codeunit "Library - Item Tracking";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        isInitialized: Boolean;
+        WrongSurplusEntryCountErr: Label 'Wrong number of Surplus reservation entries. Expected %1 but found %2.';
+        WrongSurplusQtyErr: Label 'Wrong Surplus quantity. Expected %1 but found %2.';
+
+    [Test]
+    [HandlerFunctions('ItemTrackingLinesLotAssignPageHandler')]
+    [Scope('OnPrem')]
+    procedure ReplanItemWithPlanningFlexibilityNoneDoesNotCreateDuplicateSurplusEntries()
+    var
+        Item: Record Item;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        RequisitionWkshName: Record "Requisition Wksh. Name";
+        RequisitionLine: Record "Requisition Line";
+        PurchaseLine: Record "Purchase Line";
+        ReservationEntry: Record "Reservation Entry";
+        SalesOrderQuantity: Decimal;
+        RequisitionQuantity: Decimal;
+        SurplusQuantity: Decimal;
+        PlanningEndDate: Date;
+    begin
+        // [SCENARIO] When recalculating an item in a requisition worksheet with Planning Flexibility = None after creating a purchase order
+        // with item tracking, no duplicate surplus entries should be created in the reservation table.
+
+        // [GIVEN] Create Lot-for-Lot item with item tracking (Lot No.)
+        Initialize();
+        SalesOrderQuantity := LibraryRandom.RandIntInRange(50, 100);
+        RequisitionQuantity := SalesOrderQuantity + LibraryRandom.RandIntInRange(30, 50); // More than sales order quantity
+        SurplusQuantity := RequisitionQuantity - SalesOrderQuantity;
+
+        CreateLotForLotItemWithLotTracking(Item);
+
+        // [GIVEN] Create Sales Order
+        LibrarySales.CreateSalesDocumentWithItem(
+            SalesHeader, SalesLine, SalesHeader."Document Type"::Order, '',
+            Item."No.", SalesOrderQuantity, '', WorkDate() + 30);
+
+        // [GIVEN] Calculate Plan in Requisition Worksheet
+        PlanningEndDate := WorkDate() + 60;
+        CalculatePlanForRequisitionWorksheet(RequisitionWkshName, Item, WorkDate(), PlanningEndDate);
+
+        // [GIVEN] Update requisition line: increase quantity, set Planning Flexibility = None, set Vendor No.
+        SelectRequisitionLine(RequisitionLine, Item."No.");
+        RequisitionLine.Validate(Quantity, RequisitionQuantity);
+        RequisitionLine.Validate("Vendor No.", LibraryPurchase.CreateVendorNo());
+        RequisitionLine.Validate("Planning Flexibility", RequisitionLine."Planning Flexibility"::None);
+        RequisitionLine.Modify(true);
+
+        // [GIVEN] Assign Lot No. item tracking
+        RequisitionLine.OpenItemTrackingLines();
+
+        // [GIVEN] Accept action message and carry out
+        AcceptActionMessage(Item."No.");
+        SelectRequisitionLine(RequisitionLine, Item."No.");
+        LibraryPlanning.CarryOutReqWksh(RequisitionLine, WorkDate(), WorkDate(), WorkDate(), WorkDate(), '');
+
+        // [GIVEN] Verify Purchase Order was created with correct quantity
+        SelectPurchaseLine(PurchaseLine, Item."No.");
+        Assert.AreEqual(RequisitionQuantity, PurchaseLine.Quantity, 'Purchase order quantity should match requisition quantity');
+
+        // [GIVEN] Count current surplus entries for the purchase line
+        ReservationEntry.SetSourceFilter(
+            Database::"Purchase Line", PurchaseLine."Document Type".AsInteger(), PurchaseLine."Document No.",
+            PurchaseLine."Line No.", false);
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Surplus);
+        ReservationEntry.SetRange("Item No.", Item."No.");
+        
+        // Calculate expected surplus qty (quantity above tracked demand)
+        ReservationEntry.CalcSums("Quantity (Base)");
+
+        // [WHEN] Calculate Plan again (nothing should be planned due to Planning Flexibility = None)
+        LibraryPlanning.CalculatePlanForReqWksh(
+            Item, RequisitionWkshName."Worksheet Template Name", RequisitionWkshName.Name, WorkDate(), PlanningEndDate);
+
+        // [THEN] Verify no requisition lines exist (since Planning Flexibility = None)
+        FilterOnRequisitionLine(RequisitionLine, Item."No.");
+        Assert.IsTrue(RequisitionLine.IsEmpty, 'No requisition lines should exist due to Planning Flexibility = None');
+
+        // [THEN] Verify that no additional surplus entries were created
+        // The key verification: Count the surplus entries on the purchase line - should not have increased
+        ReservationEntry.Reset();
+        ReservationEntry.SetSourceFilter(
+            Database::"Purchase Line", PurchaseLine."Document Type".AsInteger(), PurchaseLine."Document No.",
+            PurchaseLine."Line No.", false);
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Surplus);
+        ReservationEntry.SetRange("Item No.", Item."No.");
+        
+        // The bug was: Each recalculation added duplicate surplus entries for the extra quantity (50 PCS in the example)
+        // With the fix: Surplus entries should remain stable after recalculation
+        ReservationEntry.CalcSums("Quantity (Base)");
+        Assert.AreEqual(
+            SurplusQuantity, ReservationEntry."Quantity (Base)",
+            StrSubstNo(WrongSurplusQtyErr, SurplusQuantity, ReservationEntry."Quantity (Base)"));
+    end;
+
+    [Test]
+    [HandlerFunctions('ItemTrackingLinesLotAssignPageHandler')]
+    [Scope('OnPrem')]
+    procedure ReplanItemMultipleTimesDoesNotAccumulateSurplusEntries()
+    var
+        Item: Record Item;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        RequisitionWkshName: Record "Requisition Wksh. Name";
+        RequisitionLine: Record "Requisition Line";
+        PurchaseLine: Record "Purchase Line";
+        ReservationEntry: Record "Reservation Entry";
+        SalesOrderQuantity: Decimal;
+        RequisitionQuantity: Decimal;
+        SurplusQuantity: Decimal;
+        InitialSurplusQty: Decimal;
+        PlanningEndDate: Date;
+        i: Integer;
+    begin
+        // [SCENARIO] When recalculating an item multiple times in a requisition worksheet with Planning Flexibility = None,
+        // surplus entries should not accumulate with each recalculation.
+
+        // [GIVEN] Create Lot-for-Lot item with item tracking (Lot No.)
+        Initialize();
+        SalesOrderQuantity := 100;
+        RequisitionQuantity := 150; // 50 more than sales order
+        SurplusQuantity := RequisitionQuantity - SalesOrderQuantity;
+
+        CreateLotForLotItemWithLotTracking(Item);
+
+        // [GIVEN] Create Sales Order
+        LibrarySales.CreateSalesDocumentWithItem(
+            SalesHeader, SalesLine, SalesHeader."Document Type"::Order, '',
+            Item."No.", SalesOrderQuantity, '', WorkDate() + 30);
+
+        // [GIVEN] Calculate Plan in Requisition Worksheet
+        PlanningEndDate := WorkDate() + 60;
+        CalculatePlanForRequisitionWorksheet(RequisitionWkshName, Item, WorkDate(), PlanningEndDate);
+
+        // [GIVEN] Update requisition line: increase quantity to 150, set Planning Flexibility = None
+        SelectRequisitionLine(RequisitionLine, Item."No.");
+        RequisitionLine.Validate(Quantity, RequisitionQuantity);
+        RequisitionLine.Validate("Vendor No.", LibraryPurchase.CreateVendorNo());
+        RequisitionLine.Validate("Planning Flexibility", RequisitionLine."Planning Flexibility"::None);
+        RequisitionLine.Modify(true);
+
+        // [GIVEN] Assign Lot No. item tracking
+        RequisitionLine.OpenItemTrackingLines();
+
+        // [GIVEN] Accept action message and carry out
+        AcceptActionMessage(Item."No.");
+        SelectRequisitionLine(RequisitionLine, Item."No.");
+        LibraryPlanning.CarryOutReqWksh(RequisitionLine, WorkDate(), WorkDate(), WorkDate(), WorkDate(), '');
+
+        // [GIVEN] Get initial surplus quantity after first plan
+        SelectPurchaseLine(PurchaseLine, Item."No.");
+        ReservationEntry.SetSourceFilter(
+            Database::"Purchase Line", PurchaseLine."Document Type".AsInteger(), PurchaseLine."Document No.",
+            PurchaseLine."Line No.", false);
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Surplus);
+        ReservationEntry.SetRange("Item No.", Item."No.");
+        ReservationEntry.CalcSums("Quantity (Base)");
+        InitialSurplusQty := ReservationEntry."Quantity (Base)";
+
+        // [WHEN] Recalculate plan multiple times
+        for i := 1 to 3 do
+            LibraryPlanning.CalculatePlanForReqWksh(
+                Item, RequisitionWkshName."Worksheet Template Name", RequisitionWkshName.Name, WorkDate(), PlanningEndDate);
+
+        // [THEN] Verify surplus quantity has not changed after multiple recalculations
+        ReservationEntry.Reset();
+        ReservationEntry.SetSourceFilter(
+            Database::"Purchase Line", PurchaseLine."Document Type".AsInteger(), PurchaseLine."Document No.",
+            PurchaseLine."Line No.", false);
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Surplus);
+        ReservationEntry.SetRange("Item No.", Item."No.");
+        ReservationEntry.CalcSums("Quantity (Base)");
+
+        // The bug was: Each recalculation would add 50 PCS more surplus entries
+        // After 3 recalculations with the bug: 50 + 50 + 50 + 50 = 200 (instead of 50)
+        // With the fix: surplus should remain at 50
+        Assert.AreEqual(
+            InitialSurplusQty, ReservationEntry."Quantity (Base)",
+            StrSubstNo(WrongSurplusQtyErr, InitialSurplusQty, ReservationEntry."Quantity (Base)"));
+    end;
+
+    local procedure Initialize()
+    var
+        ReservationEntry: Record "Reservation Entry";
+        RequisitionLine: Record "Requisition Line";
+        RequisitionWkshName: Record "Requisition Wksh. Name";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Plan-Req. Wksht Surplus");
+        ReservationEntry.DeleteAll();
+        RequisitionLine.DeleteAll();
+        RequisitionWkshName.DeleteAll();
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Plan-Req. Wksht Surplus");
+
+        LibraryERMCountryData.UpdateGeneralLedgerSetup();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateSalesReceivablesSetup();
+        LibraryERMCountryData.CreateVATData();
+        NoSeriesSetup();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Plan-Req. Wksht Surplus");
+    end;
+
+    local procedure NoSeriesSetup()
+    var
+        PurchasesPayablesSetup: Record "Purchases & Payables Setup";
+        SalesReceivablesSetup: Record "Sales & Receivables Setup";
+    begin
+        SalesReceivablesSetup.Get();
+        SalesReceivablesSetup.Validate("Order Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        SalesReceivablesSetup.Modify(true);
+
+        PurchasesPayablesSetup.Get();
+        PurchasesPayablesSetup.Validate("Order Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        PurchasesPayablesSetup.Modify(true);
+    end;
+
+    local procedure CreateLotForLotItemWithLotTracking(var Item: Record Item)
+    var
+        ItemTrackingCode: Record "Item Tracking Code";
+    begin
+        // Create item with Lot-for-Lot reordering policy and Purchase replenishment
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Replenishment System", Item."Replenishment System"::Purchase);
+        Item.Validate("Reordering Policy", Item."Reordering Policy"::"Lot-for-Lot");
+        Item.Validate("Vendor No.", LibraryPurchase.CreateVendorNo());
+        Item.Validate("Include Inventory", true);
+        Item.Modify(true);
+
+        // Add Lot tracking
+        LibraryItemTracking.CreateItemTrackingCode(ItemTrackingCode, false, true); // LotSpecific = true
+        Item.Validate("Item Tracking Code", ItemTrackingCode.Code);
+        Item.Validate("Lot Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        Item.Modify(true);
+    end;
+
+    local procedure CalculatePlanForRequisitionWorksheet(var RequisitionWkshName: Record "Requisition Wksh. Name"; Item: Record Item; StartDate: Date; EndDate: Date)
+    var
+        ReqWkshTemplate: Record "Req. Wksh. Template";
+    begin
+        SelectRequisitionTemplate(ReqWkshTemplate, ReqWkshTemplate.Type::"Req.");
+        LibraryPlanning.CreateRequisitionWkshName(RequisitionWkshName, ReqWkshTemplate.Name);
+        LibraryPlanning.CalculatePlanForReqWksh(Item, ReqWkshTemplate.Name, RequisitionWkshName.Name, StartDate, EndDate);
+    end;
+
+    local procedure SelectRequisitionTemplate(var ReqWkshTemplate: Record "Req. Wksh. Template"; Type: Enum "Req. Worksheet Template Type")
+    begin
+        ReqWkshTemplate.SetRange(Type, Type);
+        ReqWkshTemplate.SetRange(Recurring, false);
+        ReqWkshTemplate.FindFirst();
+    end;
+
+    local procedure SelectRequisitionLine(var RequisitionLine: Record "Requisition Line"; ItemNo: Code[20])
+    begin
+        FilterOnRequisitionLine(RequisitionLine, ItemNo);
+        RequisitionLine.FindSet();
+    end;
+
+    local procedure FilterOnRequisitionLine(var RequisitionLine: Record "Requisition Line"; ItemNo: Code[20])
+    begin
+        RequisitionLine.SetRange(Type, RequisitionLine.Type::Item);
+        RequisitionLine.SetRange("No.", ItemNo);
+    end;
+
+    local procedure AcceptActionMessage(ItemNo: Code[20])
+    var
+        RequisitionLine: Record "Requisition Line";
+    begin
+        SelectRequisitionLine(RequisitionLine, ItemNo);
+        repeat
+            RequisitionLine.Validate("Accept Action Message", true);
+            RequisitionLine.Modify(true);
+        until RequisitionLine.Next() = 0;
+    end;
+
+    local procedure SelectPurchaseLine(var PurchaseLine: Record "Purchase Line"; ItemNo: Code[20])
+    begin
+        PurchaseLine.SetRange(Type, PurchaseLine.Type::Item);
+        PurchaseLine.SetRange("No.", ItemNo);
+        PurchaseLine.FindFirst();
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure ItemTrackingLinesLotAssignPageHandler(var ItemTrackingLines: TestPage "Item Tracking Lines")
+    begin
+        ItemTrackingLines."Assign &Lot No.".Invoke();
+        ItemTrackingLines.OK().Invoke();
+    end;
+}

diff --git a/App/Layers/W1/Tests/ERM/ReminderEmailFromCustomer.Codeunit.al b/App/Layers/W1/Tests/ERM/ReminderEmailFromCustomer.Codeunit.al
new file mode 100644
index 00000000..5bc02f00
--- /dev/null
+++ b/App/Layers/W1/Tests/ERM/ReminderEmailFromCustomer.Codeunit.al
@@ -0,0 +1,125 @@
+codeunit 134920 "Reminder Email From Customer"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [ERM] [Reminder] [Email]
+        IsInitialized := false;
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryMarketing: Codeunit "Library - Marketing";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryRandom: Codeunit "Library - Random";
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure GetPrimaryContactReturnsContactViaBusinessRelationWhenNoPrimaryContactSet()
+    var
+        Customer: Record Customer;
+        Contact: Record Contact;
+        PrimaryContact: Record Contact;
+        ContactBusinessRelation: Record "Contact Business Relation";
+        TestEmail: Text[80];
+    begin
+        // [SCENARIO] When a customer has no Primary Contact No. set, GetPrimaryContact returns a contact linked via Contact Business Relation
+        Initialize();
+
+        // [GIVEN] A customer with no Primary Contact No. set
+        LibrarySales.CreateCustomer(Customer);
+        Customer."Primary Contact No." := '';
+        Customer.Modify();
+
+        // [GIVEN] A contact with an email address linked to the customer via Contact Business Relation
+        TestEmail := 'test@test.de';
+        LibraryMarketing.CreateCompanyContact(Contact);
+        Contact."E-Mail" := TestEmail;
+        Contact.Modify();
+
+        // [GIVEN] Create Business Relation between Contact and Customer
+        LibraryMarketing.CreateBusinessRelationBetweenContactAndCustomer(ContactBusinessRelation, Contact."No.", Customer."No.");
+
+        // [WHEN] GetPrimaryContact is called for the customer
+        Customer.GetPrimaryContact(Customer."No.", PrimaryContact);
+
+        // [THEN] The contact is found via Contact Business Relation
+        Assert.AreEqual(Contact."No.", PrimaryContact."No.", 'Contact should be found via Contact Business Relation');
+        Assert.AreEqual(TestEmail, PrimaryContact."E-Mail", 'Email from contact should be retrieved');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure GetPrimaryContactReturnsPrimaryContactWhenSet()
+    var
+        Customer: Record Customer;
+        Contact: Record Contact;
+        PrimaryContact: Record Contact;
+        TestEmail: Text[80];
+    begin
+        // [SCENARIO] When a customer has Primary Contact No. set, GetPrimaryContact returns that contact directly
+        Initialize();
+
+        // [GIVEN] A customer with a Primary Contact No. set
+        LibrarySales.CreateCustomer(Customer);
+
+        // [GIVEN] A contact with an email address
+        TestEmail := 'primary@test.de';
+        LibraryMarketing.CreateCompanyContact(Contact);
+        Contact."E-Mail" := TestEmail;
+        Contact.Modify();
+
+        // [GIVEN] Set the contact as primary contact for customer
+        Customer."Primary Contact No." := Contact."No.";
+        Customer.Modify();
+
+        // [WHEN] GetPrimaryContact is called for the customer
+        Customer.GetPrimaryContact(Customer."No.", PrimaryContact);
+
+        // [THEN] The primary contact is returned directly
+        Assert.AreEqual(Contact."No.", PrimaryContact."No.", 'Primary contact should be returned');
+        Assert.AreEqual(TestEmail, PrimaryContact."E-Mail", 'Email from primary contact should be retrieved');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure GetPrimaryContactReturnsEmptyWhenNoContactExists()
+    var
+        Customer: Record Customer;
+        PrimaryContact: Record Contact;
+    begin
+        // [SCENARIO] When a customer has no Primary Contact No. and no Contact Business Relation, GetPrimaryContact returns empty
+        Initialize();
+
+        // [GIVEN] A customer with no Primary Contact No. and no linked contacts
+        LibrarySales.CreateCustomer(Customer);
+        Customer."Primary Contact No." := '';
+        Customer.Modify();
+
+        // [WHEN] GetPrimaryContact is called for the customer
+        Customer.GetPrimaryContact(Customer."No.", PrimaryContact);
+
+        // [THEN] No contact is found
+        Assert.AreEqual('', PrimaryContact."No.", 'No contact should be found when no links exist');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Reminder Email From Customer");
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Reminder Email From Customer");
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        IsInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Reminder Email From Customer");
+    end;
+}

diff --git a/App/Layers/W1/Tests/SCM/SCMTransferGetRcptLines.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMTransferGetRcptLines.Codeunit.al
new file mode 100644
index 00000000..ce82b8bf
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM/SCMTransferGetRcptLines.Codeunit.al
@@ -0,0 +1,199 @@
+codeunit 137900 "SCM Transfer Get Rcpt Lines"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Transfer Order] [Get Receipt Lines] [SCM]
+    end;
+
+    var
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibraryPurchase: Codeunit "Library - Purchase";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        Assert: Codeunit Assert;
+        isInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('PostedPurchaseReceiptsModalPageHandler,PostedPurchaseReceiptLinesModalPageHandler')]
+    [Scope('OnPrem')]
+    procedure GetReceiptLinesFiltersOnLineLocationNotHeader()
+    var
+        LocationFrom: Record Location;
+        LocationTo: Record Location;
+        LocationInTransit: Record Location;
+        LocationOther: Record Location;
+        Item: Record Item;
+        PurchaseHeader: Record "Purchase Header";
+        PurchaseLine: Record "Purchase Line";
+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+        PurchRcptHeader: Record "Purch. Rcpt. Header";
+        PurchRcptLine: Record "Purch. Rcpt. Line";
+    begin
+        // [FEATURE] [Get Receipt Lines]
+        // [SCENARIO] Get Receipt Lines shows purchase receipts based on line location, not header location.
+        // This ensures receipts with line location matching transfer-from code are included
+        // even if the header location is different or blank.
+        Initialize();
+
+        // [GIVEN] Create locations: "BLUE" (from), "RED" (to), "INTRANSIT", "OTHER"
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(LocationFrom);
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(LocationTo);
+        LibraryWarehouse.CreateInTransitLocation(LocationInTransit);
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(LocationOther);
+
+        // [GIVEN] Create item
+        LibraryInventory.CreateItem(Item);
+
+        // [GIVEN] Create purchase order with BLANK header location, but line location = "BLUE" (LocationFrom)
+        LibraryPurchase.CreatePurchHeader(PurchaseHeader, PurchaseHeader."Document Type"::Order, LibraryPurchase.CreateVendorNo());
+        // Note: Header "Location Code" is intentionally left blank or different from line
+        LibraryPurchase.CreatePurchaseLine(
+            PurchaseLine, PurchaseHeader, PurchaseLine.Type::Item, Item."No.", LibraryRandom.RandIntInRange(5, 10));
+        PurchaseLine.Validate("Location Code", LocationFrom.Code);
+        PurchaseLine.Modify(true);
+
+        // [GIVEN] Post purchase receipt
+        LibraryPurchase.PostPurchaseDocument(PurchaseHeader, true, false);
+
+        // [GIVEN] Find posted receipt line
+        PurchRcptLine.SetRange("Buy-from Vendor No.", PurchaseHeader."Buy-from Vendor No.");
+        PurchRcptLine.SetRange("No.", Item."No.");
+        PurchRcptLine.FindFirst();
+
+        // [GIVEN] Create transfer order from "BLUE" to "RED"
+        LibraryWarehouse.CreateTransferHeader(TransferHeader, LocationFrom.Code, LocationTo.Code, LocationInTransit.Code);
+
+        // [WHEN] Run function "Get Receipt Lines" and select the receipt
+        LibraryVariableStorage.Enqueue(PurchRcptLine."Document No."); // Purchase Receipt to select
+        LibraryVariableStorage.Enqueue(Item."No."); // Purchase Receipt Line to select
+        TransferHeader.GetReceiptLines();
+
+        // [THEN] Transfer line is created with the item from the receipt line
+        TransferLine.SetRange("Document No.", TransferHeader."No.");
+        TransferLine.SetRange("Item No.", Item."No.");
+        Assert.RecordIsNotEmpty(TransferLine);
+        TransferLine.FindFirst();
+        TransferLine.TestField(Quantity, PurchaseLine.Quantity);
+
+        LibraryVariableStorage.AssertEmpty();
+    end;
+
+    [Test]
+    [HandlerFunctions('PostedPurchaseReceiptsModalPageHandler,PostedPurchaseReceiptLinesModalPageHandler')]
+    [Scope('OnPrem')]
+    procedure GetReceiptLinesSetsApplToItemEntry()
+    var
+        LocationFrom: Record Location;
+        LocationTo: Record Location;
+        LocationInTransit: Record Location;
+        Item: Record Item;
+        PurchaseHeader: Record "Purchase Header";
+        PurchaseLine: Record "Purchase Line";
+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+        PurchRcptLine: Record "Purch. Rcpt. Line";
+        ItemLedgerEntry: Record "Item Ledger Entry";
+    begin
+        // [FEATURE] [Get Receipt Lines] [Appl.-to Item Entry]
+        // [SCENARIO] Get Receipt Lines sets "Appl.-to Item Entry" on transfer line 
+        // to apply the correct item ledger entry (cost) from the selected receipt.
+        Initialize();
+
+        // [GIVEN] Create locations
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(LocationFrom);
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(LocationTo);
+        LibraryWarehouse.CreateInTransitLocation(LocationInTransit);
+
+        // [GIVEN] Create FIFO item
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Costing Method", Item."Costing Method"::FIFO);
+        Item.Modify(true);
+
+        // [GIVEN] Create and post purchase order receipt with specific cost
+        LibraryPurchase.CreatePurchaseDocumentWithItem(
+            PurchaseHeader, PurchaseLine, PurchaseHeader."Document Type"::Order, '',
+            Item."No.", LibraryRandom.RandIntInRange(5, 10), LocationFrom.Code, WorkDate());
+        PurchaseLine.Validate("Direct Unit Cost", LibraryRandom.RandDecInRange(100, 200, 2));
+        PurchaseLine.Modify(true);
+        LibraryPurchase.PostPurchaseDocument(PurchaseHeader, true, false);
+
+        // [GIVEN] Find the posted receipt line and corresponding item ledger entry
+        PurchRcptLine.SetRange("Buy-from Vendor No.", PurchaseHeader."Buy-from Vendor No.");
+        PurchRcptLine.SetRange("No.", Item."No.");
+        PurchRcptLine.FindFirst();
+
+        ItemLedgerEntry.SetRange("Document Type", ItemLedgerEntry."Document Type"::"Purchase Receipt");
+        ItemLedgerEntry.SetRange("Document No.", PurchRcptLine."Document No.");
+        ItemLedgerEntry.SetRange("Document Line No.", PurchRcptLine."Line No.");
+        ItemLedgerEntry.FindFirst();
+
+        // [GIVEN] Create transfer order from LocationFrom to LocationTo
+        LibraryWarehouse.CreateTransferHeader(TransferHeader, LocationFrom.Code, LocationTo.Code, LocationInTransit.Code);
+
+        // [WHEN] Run function "Get Receipt Lines" and select the receipt line
+        LibraryVariableStorage.Enqueue(PurchRcptLine."Document No.");
+        LibraryVariableStorage.Enqueue(Item."No.");
+        TransferHeader.GetReceiptLines();
+
+        // [THEN] Transfer line is created with "Appl.-to Item Entry" set to the item ledger entry
+        TransferLine.SetRange("Document No.", TransferHeader."No.");
+        TransferLine.SetRange("Item No.", Item."No.");
+        TransferLine.FindFirst();
+        TransferLine.TestField("Appl.-to Item Entry", ItemLedgerEntry."Entry No.");
+
+        LibraryVariableStorage.AssertEmpty();
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Transfer Get Rcpt Lines");
+        LibraryVariableStorage.Clear();
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Transfer Get Rcpt Lines");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateInventoryPostingSetup();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Transfer Get Rcpt Lines");
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure PostedPurchaseReceiptsModalPageHandler(var PostedPurchaseReceipts: TestPage "Posted Purchase Receipts")
+    var
+        PurchRcptHeader: Record "Purch. Rcpt. Header";
+        DocumentNo: Code[20];
+    begin
+        DocumentNo := CopyStr(LibraryVariableStorage.DequeueText(), 1, MaxStrLen(DocumentNo));
+        PurchRcptHeader.Get(DocumentNo);
+        PostedPurchaseReceipts.GoToRecord(PurchRcptHeader);
+        PostedPurchaseReceipts.OK().Invoke();
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure PostedPurchaseReceiptLinesModalPageHandler(var PostedPurchaseReceiptLines: TestPage "Posted Purchase Receipt Lines")
+    var
+        PurchRcptLine: Record "Purch. Rcpt. Line";
+        ItemNo: Code[20];
+    begin
+        ItemNo := CopyStr(LibraryVariableStorage.DequeueText(), 1, MaxStrLen(ItemNo));
+        PurchRcptLine.SetRange("No.", ItemNo);
+        PurchRcptLine.FindFirst();
+        PostedPurchaseReceiptLines.GoToRecord(PurchRcptLine);
+        PostedPurchaseReceiptLines.OK().Invoke();
+    end;
+}

diff --git a/App/Apps/W1/Shopify/test/Payments/ShpfySuggestPaymentTest.Codeunit.al b/App/Apps/W1/Shopify/test/Payments/ShpfySuggestPaymentTest.Codeunit.al
