--- a/App/Apps/W1/Shopify/test/Payments/ShpfySuggestPaymentTest.Codeunit.al
+++ b/App/Apps/W1/Shopify/test/Payments/ShpfySuggestPaymentTest.Codeunit.al
@@ -273,6 +273,125 @@ codeunit 139648 "Shpfy Suggest Payment Test"
         RefundHeader.Insert();
     end;

+    [Test]
+    procedure UnitTestSuggestPaymentsViaDocLinkToDoc()
+    var
+        Item: Record Item;
+        Customer: Record Customer;
+        OrderTransaction: Record "Shpfy Order Transaction";
+        SuggestPayment: Record "Shpfy Suggest Payment";
+        DocLinkToDoc: Record "Shpfy Doc. Link To Doc.";
+        SuggestPayments: Report "Shpfy Suggest Payments";
+        OrderId: BigInteger;
+        Amount: Decimal;
+        PostedInvoiceNo: Code[20];
+    begin
+        // [SCENARIO] When invoice is created via Get Receipt Lines, the Posted Sales Invoice Header doesn't have the Shpfy Order Id.
+        // In this case, the Suggest Shopify Payments should use the Shpfy Doc. Link To Doc. table to find linked invoices.
+
+        // [GIVEN] Invoice is posted WITHOUT Shpfy Order Id on the header (simulating Get Receipt Lines scenario)
+        Initialize();
+        Amount := Any.IntegerInRange(10000, 99999);
+        OrderId := Any.IntegerInRange(10000, 99999);
+        CreateItem(Item, Amount);
+        LibrarySales.CreateCustomer(Customer);
+        PostedInvoiceNo := CreateAndPostSalesInvoiceWithoutOrderId(Item, Customer, 1);
+
+        // [GIVEN] A Shpfy Doc. Link To Doc. record links the Shopify Order to the Posted Sales Invoice
+        DocLinkToDoc.Init();
+        DocLinkToDoc."Shopify Document Type" := DocLinkToDoc."Shopify Document Type"::"Shopify Shop Order";
+        DocLinkToDoc."Shopify Document Id" := OrderId;
+        DocLinkToDoc."Document Type" := DocLinkToDoc."Document Type"::"Posted Sales Invoice";
+        DocLinkToDoc."Document No." := PostedInvoiceNo;
+        DocLinkToDoc.Insert();
+
+        // [GIVEN] Shopify transaction is imported
+        CreateOrderTransaction(OrderId, Amount, 'manual', OrderTransaction.Type::Sale, OrderTransaction.Status::Success);
+
+        // [WHEN] Get Order Transactions is run
+        OrderTransaction.FindFirst();
+        SuggestPayments.GetOrderTransactions(OrderTransaction);
+
+        // [THEN] Temporary suggest payment records are created with correct amount
+        SuggestPayments.GetTempSuggestPayment(SuggestPayment);
+        SuggestPayment.FindFirst();
+        LibraryAssert.AreEqual(SuggestPayment.Amount, Amount, 'Payment amount should match the invoice amount');
+        LibraryAssert.AreEqual(SuggestPayment."Invoice No.", PostedInvoiceNo, 'Invoice No. should match the posted invoice');
+    end;
+
+    [Test]
+    procedure UnitTestSuggestPaymentsViaDocLinkToDocMultipleOrders()
+    var
+        Item: Record Item;
+        Customer: Record Customer;
+        OrderTransaction: Record "Shpfy Order Transaction";
+        SuggestPayment: Record "Shpfy Suggest Payment";
+        DocLinkToDoc: Record "Shpfy Doc. Link To Doc.";
+        SuggestPayments: Report "Shpfy Suggest Payments";
+        OrderId1: BigInteger;
+        OrderId2: BigInteger;
+        Amount: Decimal;
+        PostedInvoiceNo: Code[20];
+    begin
+        // [SCENARIO] When multiple Shopify orders are combined into a single invoice via Get Receipt Lines,
+        // both order transactions should be suggested for the same invoice.
+
+        // [GIVEN] A single invoice is posted for multiple order quantities (simulating combined orders via Get Receipt Lines)
+        Initialize();
+        Amount := Any.IntegerInRange(10000, 99999);
+        OrderId1 := Any.IntegerInRange(10000, 99999);
+        OrderId2 := Any.IntegerInRange(100000, 199999);
+        CreateItem(Item, Amount);
+        LibrarySales.CreateCustomer(Customer);
+        PostedInvoiceNo := CreateAndPostSalesInvoiceWithoutOrderId(Item, Customer, 2);
+
+        // [GIVEN] Shpfy Doc. Link To Doc. records link both Shopify Orders to the same Posted Sales Invoice
+        DocLinkToDoc.Init();
+        DocLinkToDoc."Shopify Document Type" := DocLinkToDoc."Shopify Document Type"::"Shopify Shop Order";
+        DocLinkToDoc."Shopify Document Id" := OrderId1;
+        DocLinkToDoc."Document Type" := DocLinkToDoc."Document Type"::"Posted Sales Invoice";
+        DocLinkToDoc."Document No." := PostedInvoiceNo;
+        DocLinkToDoc.Insert();
+
+        DocLinkToDoc.Init();
+        DocLinkToDoc."Shopify Document Type" := DocLinkToDoc."Shopify Document Type"::"Shopify Shop Order";
+        DocLinkToDoc."Shopify Document Id" := OrderId2;
+        DocLinkToDoc."Document Type" := DocLinkToDoc."Document Type"::"Posted Sales Invoice";
+        DocLinkToDoc."Document No." := PostedInvoiceNo;
+        DocLinkToDoc.Insert();
+
+        // [GIVEN] Shopify transactions are imported for both orders
+        CreateOrderTransaction(OrderId1, Amount, 'manual', OrderTransaction.Type::Sale, OrderTransaction.Status::Success);
+        CreateOrderTransaction(OrderId2, Amount, 'manual', OrderTransaction.Type::Sale, OrderTransaction.Status::Success);
+
+        // [WHEN] Get Order Transactions is run for both transactions
+        OrderTransaction.SetRange("Shopify Order Id", OrderId1);
+        OrderTransaction.FindFirst();
+        SuggestPayments.GetOrderTransactions(OrderTransaction);
+        OrderTransaction.SetRange("Shopify Order Id", OrderId2);
+        OrderTransaction.FindFirst();
+        SuggestPayments.GetOrderTransactions(OrderTransaction);
+
+        // [THEN] Suggest payment records are created for both transactions pointing to the same invoice
+        SuggestPayments.GetTempSuggestPayment(SuggestPayment);
+        LibraryAssert.RecordCount(SuggestPayment, 2);
+        SuggestPayment.FindSet();
+        repeat
+            LibraryAssert.AreEqual(SuggestPayment."Invoice No.", PostedInvoiceNo, 'Invoice No. should match for combined orders');
+        until SuggestPayment.Next() = 0;
+    end;
+
+    local procedure CreateAndPostSalesInvoiceWithoutOrderId(Item: Record Item; Customer: Record Customer; NumberOfLines: Integer): Code[20]
+    var
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+    begin
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Invoice, Customer."No.");
+        // Note: NOT setting SalesHeader."Shpfy Order Id" to simulate invoice created via Get Receipt Lines
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", NumberOfLines);
+        exit(LibrarySales.PostSalesDocument(SalesHeader, true, true));
+    end;
