+codeunit 139693 "Reconcile Cust/Vend Mult. PG"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Report] [Reconcile Customer and Vendor Accounts] [Multiple Posting Groups]
+    end;
+
+    var
+        LibraryERM: Codeunit "Library - ERM";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryReportDataset: Codeunit "Library - Report Dataset";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        Assert: Codeunit Assert;
+        IsInitialized: Boolean;
+        RowNotFoundErr: Label 'There is no dataset row corresponding to Element Name %1 with value %2.', Comment = '%1=Field Caption,%2=Field Value;';
+
+    [Test]
+    [HandlerFunctions('ReconcileCustandVendAccsRequestPageHandler')]
+    [Scope('OnPrem')]
+    procedure ReconcileCustAccsShowsCorrectAmountsWhenMultiplePostingGroupsUsed()
+    var
+        Customer: Record Customer;
+        CustomerPostingGroup1: Record "Customer Posting Group";
+        CustomerPostingGroup2: Record "Customer Posting Group";
+        GLAccount1: Record "G/L Account";
+        GLAccount2: Record "G/L Account";
+        GenJournalLine: Record "Gen. Journal Line";
+        ReconcileCustAndVendAccs: Report "Reconcile Cust. and Vend. Accs";
+        Amount1: Decimal;
+        Amount2: Decimal;
+    begin
+        // [SCENARIO] Report 33 "Reconcile Customer and Vendor Accounts" shows correct amounts when 
+        // multiple posting groups are used for the same customer - amounts should be grouped by 
+        // posting group at entry level, not customer level.
+        Initialize();
+
+        // [GIVEN] Enable "Allow Multiple Posting Groups" in Sales & Receivables Setup
+        SetSalesAllowMultiplePostingGroups(true);
+
+        // [GIVEN] A customer with "Allow Multiple Posting Groups" enabled
+        LibrarySales.CreateCustomer(Customer);
+        CustomerPostingGroup1.Get(Customer."Customer Posting Group");
+        Customer.Validate("Allow Multiple Posting Groups", true);
+        Customer.Modify(true);
+
+        // [GIVEN] A second customer posting group with a different receivables account
+        LibrarySales.CreateCustomerPostingGroup(CustomerPostingGroup2);
+        LibrarySales.CreateAltCustomerPostingGroup(Customer."Customer Posting Group", CustomerPostingGroup2.Code);
+
+        // [GIVEN] Two payments posted for the same customer using different posting groups
+        Amount1 := LibraryRandom.RandDecInRange(100, 500, 2);
+        Amount2 := LibraryRandom.RandDecInRange(600, 1000, 2);
+
+        // Post first payment with default posting group
+        CreateAndPostGenJournalLineWithPostingGroup(
+            GenJournalLine, Customer."No.", -Amount1, CustomerPostingGroup1.Code);
+
+        // Post second payment with alternate posting group
+        CreateAndPostGenJournalLineWithPostingGroup(
+            GenJournalLine, Customer."No.", -Amount2, CustomerPostingGroup2.Code);
+
+        // [WHEN] Run Report 33 for the first receivables account (CustomerPostingGroup1)
+        Clear(ReconcileCustAndVendAccs);
+        GLAccount1.Get(CustomerPostingGroup1."Receivables Account");
+        GLAccount1.SetRange("No.", GLAccount1."No.");
+        GLAccount1.SetRange("Date Filter", WorkDate());
+        ReconcileCustAndVendAccs.SetTableView(GLAccount1);
+        Commit();
+        ReconcileCustAndVendAccs.Run();
+
+        // [THEN] The report shows only the amount for CustomerPostingGroup1 entries (Amount1), not the total
+        LibraryReportDataset.LoadDataSetFile();
+        LibraryReportDataset.SetRange('ReconCustVendBufferPostingGroup', CustomerPostingGroup1.Code);
+        Assert.IsTrue(
+            LibraryReportDataset.GetNextRow(),
+            StrSubstNo(RowNotFoundErr, 'ReconCustVendBufferPostingGroup', CustomerPostingGroup1.Code));
+        LibraryReportDataset.AssertCurrentRowValueEquals('Amount', -Amount1);
+
+        // [WHEN] Run Report 33 for the second receivables account (CustomerPostingGroup2)
+        Clear(ReconcileCustAndVendAccs);
+        GLAccount2.Get(CustomerPostingGroup2."Receivables Account");
+        GLAccount2.SetRange("No.", GLAccount2."No.");
+        GLAccount2.SetRange("Date Filter", WorkDate());
+        ReconcileCustAndVendAccs.SetTableView(GLAccount2);
+        Commit();
+        ReconcileCustAndVendAccs.Run();
+
+        // [THEN] The report shows only the amount for CustomerPostingGroup2 entries (Amount2), not the total
+        LibraryReportDataset.LoadDataSetFile();
+        LibraryReportDataset.SetRange('ReconCustVendBufferPostingGroup', CustomerPostingGroup2.Code);
+        Assert.IsTrue(
+            LibraryReportDataset.GetNextRow(),
+            StrSubstNo(RowNotFoundErr, 'ReconCustVendBufferPostingGroup', CustomerPostingGroup2.Code));
+        LibraryReportDataset.AssertCurrentRowValueEquals('Amount', -Amount2);
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Reconcile Cust/Vend Mult. PG");
+
+        LibrarySetupStorage.Restore();
+
+        if IsInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Reconcile Cust/Vend Mult. PG");
+
+        LibraryERMCountryData.UpdateSalesReceivablesSetup();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        IsInitialized := true;
+        Commit();
+
+        LibrarySetupStorage.Save(DATABASE::"Sales & Receivables Setup");
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Reconcile Cust/Vend Mult. PG");
+    end;
+
+    local procedure SetSalesAllowMultiplePostingGroups(AllowMultiplePostingGroups: Boolean)
+    var
+        SalesReceivablesSetup: Record "Sales & Receivables Setup";
+    begin
+        SalesReceivablesSetup.Get();
+        SalesReceivablesSetup."Allow Multiple Posting Groups" := AllowMultiplePostingGroups;
+        SalesReceivablesSetup."Check Multiple Posting Groups" := "Posting Group Change Method"::"Alternative Groups";
+        SalesReceivablesSetup.Modify();
+    end;
+
+    local procedure CreateAndPostGenJournalLineWithPostingGroup(var GenJournalLine: Record "Gen. Journal Line"; CustomerNo: Code[20]; Amount: Decimal; PostingGroupCode: Code[20])
+    var
+        GenJournalBatch: Record "Gen. Journal Batch";
+    begin
+        LibraryERM.SelectGenJnlBatch(GenJournalBatch);
+        LibraryERM.ClearGenJournalLines(GenJournalBatch);
+        LibraryERM.CreateGeneralJnlLine(
+            GenJournalLine, GenJournalBatch."Journal Template Name", GenJournalBatch.Name,
+            GenJournalLine."Document Type"::Payment, GenJournalLine."Account Type"::Customer, CustomerNo, Amount);
+        GenJournalLine.Validate("Posting Group", PostingGroupCode);
+        GenJournalLine.Modify(true);
+        LibraryERM.PostGeneralJnlLine(GenJournalLine);
+    end;
+
+    [RequestPageHandler]
+    [Scope('OnPrem')]
+    procedure ReconcileCustandVendAccsRequestPageHandler(var ReconcileCustandVendAccs: TestRequestPage "Reconcile Cust. and Vend. Accs")
+    begin
+        ReconcileCustandVendAccs.SaveAsXml(LibraryReportDataset.GetParametersFileName(), LibraryReportDataset.GetFileName());
+    end;
+}

