+        // [GIVEN] Location with Bin Mandatory = TRUE, Require Pick = FALSE, Prod. Consump. Whse. Handling = "Warehouse Pick (mandatory)"
+        LibraryWarehouse.CreateLocationWMS(Location, true, false, false, false, false);
+        Location.Validate("Prod. Consump. Whse. Handling", Enum::"Prod. Consump. Whse. Handling"::"Warehouse Pick (mandatory)");
+        Location.Modify(true);
+        LibraryWarehouse.CreateBin(Bin, Location.Code, LibraryUtility.GenerateGUID(), '', '');
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, Location.Code, true);
+
+        // [GIVEN] Component Item with replenishment = Purchase
+        LibraryInventory.CreateItem(ComponentItem);
+
+        // [GIVEN] Parent Item with replenishment = Prod. Order and Production BOM containing Component Item
+        LibraryInventory.CreateItem(ParentItem);
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ParentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItem."No.", 1);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+        ParentItem.Validate("Replenishment System", ParentItem."Replenishment System"::"Prod. Order");
+        ParentItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ParentItem.Modify(true);
+
+        // [GIVEN] Positive adjustment of 3 PCS for Component Item to Location with Bin
+        Quantity[1] := 2;
+        Quantity[2] := 1;
+        TotalComponentQty := Quantity[1] + Quantity[2];
+        CreateAndPostItemJournalLine(ComponentItem."No.", TotalComponentQty, Location.Code, Bin.Code);
+
+        // [GIVEN] 2 Released Production Orders for Parent Item (quantities 2 and 1)
+        for i := 1 to 2 do begin
+            LibraryManufacturing.CreateProductionOrder(
