+        // [GIVEN] Reserve the Component Items in both Production Orders against inventory
+        for i := 1 to 2 do begin
+            ProdOrderComponent.SetRange(Status, ProductionOrder[i].Status);
+            ProdOrderComponent.SetRange("Prod. Order No.", ProductionOrder[i]."No.");
+            ProdOrderComponent.SetRange("Item No.", ComponentItem."No.");
+            ProdOrderComponent.FindFirst();
+            ReservationManagement.SetReservSource(ProdOrderComponent);
+            ReservationManagement.AutoReserve(FullReservation, '', ProdOrderComponent."Due Date", Quantity[i], Quantity[i]);
+        end;
+
+        // [GIVEN] Get both Production Orders into Pick Worksheet
+        for i := 1 to 2 do begin
+            WhsePickRequest.Get(WhsePickRequest."Document Type"::Production, ProductionOrder[i].Status, ProductionOrder[i]."No.", Location.Code);
+            LibraryWarehouse.GetWhseDocsPickWorksheet(WhseWorksheetLine, WhsePickRequest, Location.Code);
