+    [Test]
+    [Scope('OnPrem')]
+    procedure CreateContractEntryNoFilterWithNonSequentialLines()
+    var
+        Job: Record Job;
+        JobTask: Record "Job Task";
+        JobPlanningLine: Record "Job Planning Line";
+        JobPlanningLine1: Record "Job Planning Line";
+        JobPlanningLine2: Record "Job Planning Line";
+        JobPlanningLineFiltered: Record "Job Planning Line";
+        Item: Record Item;
+        SelectionFilterMgt: Codeunit SelectionFilterManagement;
+        RecRef: RecordRef;
+        ContractEntryNoFilter: Text;
+        FirstContractEntryNo: Integer;
+        SecondContractEntryNo: Integer;
+    begin
+        // [SCENARIO 000000] CreateContractEntryNoFilter generates valid filter when job planning lines are inserted in non-sequential order
+        // [FEATURE] [Job] [Planning Line] [Purchase Order]
+        // This test verifies the fix for the issue where Create Purchase Order from Project did not work correctly
+        // when job planning lines were added before existing ones, resulting in an invalid filter like "16..15" instead of "15..16".
+
+        // [GIVEN] A Job with a Job Task
+        Initialize();
+        LibraryJob.CreateJob(Job);
+        LibraryJob.CreateJobTask(Job, JobTask);
+        LibraryInventory.CreateItem(Item);
+
+        // [GIVEN] Create first job planning line with Line No. = 20000 (higher Line No.)
+        JobPlanningLine1.Init();
+        JobPlanningLine1.Validate("Job No.", JobTask."Job No.");
+        JobPlanningLine1.Validate("Job Task No.", JobTask."Job Task No.");
+        JobPlanningLine1.Validate("Line No.", 20000);
+        JobPlanningLine1.Insert(true);
+        JobPlanningLine1.Validate("Planning Date", WorkDate());
+        JobPlanningLine1.Validate("Line Type", JobPlanningLine1."Line Type"::Budget);
+        JobPlanningLine1.Validate(Type, JobPlanningLine1.Type::Item);
+        JobPlanningLine1.Validate("No.", Item."No.");
+        JobPlanningLine1.Validate(Quantity, 10);
+        JobPlanningLine1.Modify(true);
+        FirstContractEntryNo := JobPlanningLine1."Job Contract Entry No.";
+
+        // [GIVEN] Create second job planning line with Line No. = 10000 (lower Line No., simulating insert before first line)
+        // The second line will have a higher Job Contract Entry No. because it's created after the first line
+        JobPlanningLine2.Init();
+        JobPlanningLine2.Validate("Job No.", JobTask."Job No.");
+        JobPlanningLine2.Validate("Job Task No.", JobTask."Job Task No.");
+        JobPlanningLine2.Validate("Line No.", 10000);
+        JobPlanningLine2.Insert(true);
+        JobPlanningLine2.Validate("Planning Date", WorkDate());
+        JobPlanningLine2.Validate("Line Type", JobPlanningLine2."Line Type"::Budget);
+        JobPlanningLine2.Validate(Type, JobPlanningLine2.Type::Item);
+        JobPlanningLine2.Validate("No.", Item."No.");
+        JobPlanningLine2.Validate(Quantity, 10);
+        JobPlanningLine2.Modify(true);
+        SecondContractEntryNo := JobPlanningLine2."Job Contract Entry No.";
+
+        // Verify precondition: second line has higher contract entry no but lower line no
+        Assert.IsTrue(SecondContractEntryNo > FirstContractEntryNo,
+            'Test setup error: Second line should have higher Job Contract Entry No.');
+        Assert.IsTrue(JobPlanningLine2."Line No." < JobPlanningLine1."Line No.",
+            'Test setup error: Second line should have lower Line No.');
+
+        // [WHEN] Build the filter using SetCurrentKey("Job Contract Entry No.") - this is the fix
+        JobPlanningLine.SetLoadFields("Job Contract Entry No.");
+        JobPlanningLine.SetRange("Job No.", JobTask."Job No.");
+        JobPlanningLine.SetRange("Job Task No.", JobTask."Job Task No.");
+        JobPlanningLine.SetCurrentKey("Job Contract Entry No.");
+        JobPlanningLine.FindSet();
+        RecRef.GetTable(JobPlanningLine);
+        ContractEntryNoFilter := SelectionFilterMgt.GetSelectionFilter(RecRef, JobPlanningLine.FieldNo("Job Contract Entry No."));
+
+        // [THEN] The filter should be a valid ascending range filter (e.g., "15..16" not "16..15")
+        // Apply the filter and verify both lines are found
+        JobPlanningLineFiltered.SetRange("Job No.", JobTask."Job No.");
+        JobPlanningLineFiltered.SetRange("Job Task No.", JobTask."Job Task No.");
+        JobPlanningLineFiltered.SetFilter("Job Contract Entry No.", ContractEntryNoFilter);
+
+        // Both lines should be found with a valid ascending filter
+        Assert.AreEqual(2, JobPlanningLineFiltered.Count(),
+            'Both job planning lines should be included when filtering by Job Contract Entry No. range. ' +
+            'Filter was: ' + ContractEntryNoFilter);
+
+        // Verify the filter is in ascending order format (lower..higher)
+        Assert.IsTrue(
+            StrPos(ContractEntryNoFilter, Format(FirstContractEntryNo) + '..' + Format(SecondContractEntryNo)) > 0,
+            'Filter should be in ascending format (FirstNo..SecondNo). Actual filter: ' + ContractEntryNoFilter);
+    end;
