+codeunit 137999 "SCM Transfer Variant Mandatory"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Transfer Order] [Variant Mandatory]
+        isInitialized := false;
+    end;
+
+    var
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        Assert: Codeunit Assert;
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure VariantMandatoryBlocksReleasingTransferOrder()
+    var
+        Item: Record Item;
+        ItemVariant: Record "Item Variant";
+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+        FromLocation: Record Location;
+        ToLocation: Record Location;
+        InTransitLocation: Record Location;
+    begin
+        // [FEATURE] [Transfer Order] [Variant Mandatory]
+        // [SCENARIO] When "Variant Mandatory if Exists" is set for an item with variants,
+        // releasing a Transfer Order without a variant should fail
+        Initialize();
+
+        // [GIVEN] Item with available variants and Item."Variant Mandatory if Exists" = Yes
+        CreateMandatoryVariant(Item, ItemVariant);
+
+        // [GIVEN] Transfer Order with specified item and NO variant chosen
+        CreateTransferLocations(FromLocation, ToLocation, InTransitLocation);
+        CreateItemWithPositiveInventory(Item, FromLocation.Code, 10);
+        LibraryInventory.CreateTransferHeader(TransferHeader, FromLocation.Code, ToLocation.Code, InTransitLocation.Code);
+        LibraryInventory.CreateTransferLine(TransferHeader, TransferLine, Item."No.", 1);
+        Commit();
+
+        // [WHEN] User tries to release transfer order
+        asserterror LibraryWarehouse.ReleaseTransferOrder(TransferHeader);
+
+        // [THEN] Error is thrown indicating the Variant Code is missing on the transfer line.
+        Assert.ExpectedError(TransferLine.FieldCaption(TransferLine."Variant Code"));
+
+        TransferHeader.Get(TransferHeader."No.");
+
+        // [GIVEN] Variant is specified
+        TransferLine.Validate("Variant Code", ItemVariant.Code);
+        TransferLine.Modify();
+
+        // [WHEN] User tries to release transfer order
+        LibraryWarehouse.ReleaseTransferOrder(TransferHeader);
+
+        // [THEN] No error is thrown
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Transfer Variant Mandatory");
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Transfer Variant Mandatory");
+
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateInventoryPostingSetup();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Transfer Variant Mandatory");
+    end;
+
+    local procedure CreateMandatoryVariant(var Item: Record Item; var ItemVariant: Record "Item Variant")
+    begin
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Variant Mandatory if Exists", Item."Variant Mandatory if Exists"::Yes);
+        Item.Modify();
+        LibraryInventory.CreateVariant(ItemVariant, Item);
+    end;
+
+    local procedure CreateTransferLocations(var FromLocation: Record Location; var ToLocation: Record Location; var InTransitLocation: Record Location)
+    begin
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(FromLocation);
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(ToLocation);
+        LibraryWarehouse.CreateInTransitLocation(InTransitLocation);
+    end;
+
+    local procedure CreateItemWithPositiveInventory(var Item: Record Item; LocationCode: Code[10]; Qty: Decimal)
+    var
+        ItemJournalLine: Record "Item Journal Line";
+    begin
+        LibraryInventory.CreateItemJournalLineInItemTemplate(ItemJournalLine, Item."No.", LocationCode, '', Qty);
+        LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+    end;
+}

