diff --git a/App/Layers/W1/Tests/ERM/ERMAccountReceivablesKPIs.Codeunit.al b/App/Layers/W1/Tests/ERM/ERMAccountReceivablesKPIs.Codeunit.al
new file mode 100644
index 00000000..ad164c1d
--- /dev/null
+++ b/App/Layers/W1/Tests/ERM/ERMAccountReceivablesKPIs.Codeunit.al
@@ -0,0 +1,124 @@
+codeunit 134961 "ERM Account Receivables KPIs"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Account Receivables KPIs]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryRandom: Codeunit "Library - Random";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure TotalOverdueLCYUsesTodayNotWorkDate()
+    var
+        Customer: Record Customer;
+        CustLedgerEntry: Record "Cust. Ledger Entry";
+        DetailedCustLedgEntry: Record "Detailed Cust. Ledg. Entry";
+        AccountReceivablesKPIs: TestPage "Account Receivables KPIs";
+        OriginalWorkDate: Date;
+        OverdueAmount: Decimal;
+        FutureEntryAmount: Decimal;
+        DisplayedAmount: Decimal;
+    begin
+        // [SCENARIO] The Total Overdue (LCY) cue uses Today() as the filter date, not WorkDate().
+        // This ensures the cue accurately reflects overdue amounts based on the current date,
+        // not a user-configured work date which is intended for data entry purposes.
+        Initialize();
+
+        // [GIVEN] Save and modify WorkDate to be 30 days in the future relative to Today
+        OriginalWorkDate := WorkDate();
+        WorkDate := CalcDate('<+30D>', Today());
+
+        // [GIVEN] A customer with a ledger entry that has an overdue entry (Due Date < Today)
+        LibrarySales.CreateCustomer(Customer);
+        CreateDetailedCustLedgEntryWithDueDate(
+            CustLedgerEntry, DetailedCustLedgEntry, Customer."No.",
+            CalcDate('<-10D>', Today()),  // Due date 10 days ago - OVERDUE relative to Today
+            LibraryRandom.RandDecInRange(100, 200, 2));
+        OverdueAmount := DetailedCustLedgEntry."Amount (LCY)";
+
+        // [GIVEN] Another entry with due date between Today and WorkDate (not overdue relative to Today, but would be if WorkDate was used)
+        FutureEntryAmount := LibraryRandom.RandDecInRange(300, 400, 2);
+        CreateDetailedCustLedgEntryWithDueDate(
+            CustLedgerEntry, DetailedCustLedgEntry, Customer."No.",
+            CalcDate('<+15D>', Today()),  // Due date 15 days from now - NOT overdue relative to Today, but < WorkDate
+            FutureEntryAmount);
+
+        // [WHEN] The Account Receivables KPIs page is opened
+        AccountReceivablesKPIs.OpenView();
+
+        // [THEN] Get the displayed Total Overdue (LCY) value from the page
+        Evaluate(DisplayedAmount, AccountReceivablesKPIs."Sales - Total Overdue (LCY)".Value);
+
+        // [THEN] The Total Overdue (LCY) should include only entries due on or before Today,
+        // not entries due after Today but before WorkDate
+        // If the bug exists (WorkDate used instead of Today), FutureEntryAmount would be included
+        Assert.AreEqual(
+            OverdueAmount,
+            DisplayedAmount,
+            'Total Overdue (LCY) should only include entries overdue relative to Today(), not WorkDate(). ' +
