diff --git a/App/Layers/W1/Tests/VAT/NonDedVATJobCurrency.Codeunit.al b/App/Layers/W1/Tests/VAT/NonDedVATJobCurrency.Codeunit.al
new file mode 100644
index 00000000..73f0eaf7
--- /dev/null
+++ b/App/Layers/W1/Tests/VAT/NonDedVATJobCurrency.Codeunit.al
@@ -0,0 +1,178 @@
+codeunit 134293 "Non Ded. VAT Job Currency"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Non-Deductible VAT] [Job] [Currency]
+    end;
+
+    var
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryJob: Codeunit "Library - Job";
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryJournals: Codeunit "Library - Journals";
+        LibraryNonDeductibleVAT: Codeunit "Library - NonDeductible VAT";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        Assert: Codeunit Assert;
+        isInitialized: Boolean;
+        IncorrectTotalCostLCYErr: Label 'Incorrect Total Cost (LCY) in Job Ledger Entry.';
+        IncorrectUnitCostLCYErr: Label 'Incorrect Unit Cost (LCY) in Job Ledger Entry.';
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure ProjectLedgerEntryWithNonDedVATWhenJobHasForeignCurrency()
+    var
+        Job: Record Job;
+        JobTask: Record "Job Task";
+        JobLedgerEntry: Record "Job Ledger Entry";
+        GenJournalLine: Record "Gen. Journal Line";
+        VATPostingSetup: Record "VAT Posting Setup";
+        GLAccount: Record "G/L Account";
+        CurrencyCode: Code[10];
+        DocumentNo: Code[20];
+        JournalAmount: Decimal;
+        Quantity: Decimal;
+        NonDedVATAmount: Decimal;
+        ConvertedNonDedVATAmountLCY: Decimal;
+        BaseCostAmount: Decimal;
+        BaseTotalCostLCY: Decimal;
+        ExpectedTotalCostLCY: Decimal;
+        JobCurrencyFactor: Decimal;
+        ExchangeRateAmount: Decimal;
+        RelationalExchRateAmount: Decimal;
+        GenPostingType: Enum "General Posting Type";
+    begin
+        // [SCENARIO] Project Ledger Entry shows correct Non-Deductible VAT amount when Job has foreign currency and Gen. Journal Line is in LCY
+        // The fix ensures that Non-Deductible VAT amounts are correctly converted using the job currency factor
+        // when the journal line currency differs from the job currency.
+        // Bug: When posting a Gen. Journal Line in LCY (e.g., DKK) with Non-Deductible VAT to a Project in FCY (e.g., EUR),
+        // the system was incorrectly adding the LCY VAT amount directly to the Project Ledger Entry costs
+        // without currency conversion.
+        Initialize();
+
+        // [GIVEN] Enable "Use For Job Cost" for Non-Deductible VAT
+        LibraryNonDeductibleVAT.SetUseForJobCost();
+
+        // [GIVEN] VAT Posting Setup with Non-Deductible VAT % = 100 and VAT % = 20
+        LibraryNonDeductibleVAT.CreateVATPostingSetupWithNonDeductibleDetail(VATPostingSetup, 20, 100);
+
+        // [GIVEN] G/L Account with the VAT Posting Setup
+        GLAccount.Get(LibraryERM.CreateGLAccountWithVATPostingSetup(VATPostingSetup, GenPostingType::Purchase));
+
+        // [GIVEN] Currency with exchange rate that differs from 1:1 to expose the currency conversion bug
+        // Exchange Rate: 7.5 LCY = 1 FCY (e.g., 7.5 DKK = 1 EUR)
+        // So JobCurrencyFactor = 7.5 / 1 = 7.5
+        ExchangeRateAmount := 7.5;
+        RelationalExchRateAmount := 1;
+        CurrencyCode := LibraryERM.CreateCurrencyWithExchangeRate(WorkDate(), ExchangeRateAmount, RelationalExchRateAmount);
+        JobCurrencyFactor := ExchangeRateAmount / RelationalExchRateAmount;
+
+        // [GIVEN] Job with foreign currency (e.g., EUR)
+        LibraryJob.CreateJob(Job);
+        Job.Validate("Currency Code", CurrencyCode);
+        Job.Modify(true);
+        LibraryJob.CreateJobTask(Job, JobTask);
+
+        // [GIVEN] Create General Journal Line in LCY (no currency code) with Non-Deductible VAT and Job reference
+        // This simulates the scenario: posting a document in LCY (DKK) to a project running in FCY (EUR)
+        JournalAmount := 1000; // Fixed amount for predictable calculation (VAT-inclusive amount)
+        Quantity := 1; // Fixed quantity for simpler verification
+        DocumentNo := CreateGenJnlLineWithJobAndNonDedVAT(GenJournalLine, GLAccount."No.", JournalAmount, Quantity, Job."No.", JobTask."Job Task No.", '');
+
+        // Calculate the Non-Deductible VAT amount (in LCY since journal is in LCY)
+        // With 20% VAT: VAT Amount = Amount - Base, where Amount = Base * 1.20
+        // So VAT Amount = GenJournalLine."VAT Amount"
+        // Non-Deductible VAT Amount = VAT Amount * (Non-Deductible VAT % / 100)
+        NonDedVATAmount := Round(GenJournalLine."VAT Amount" * VATPostingSetup."Non-Deductible VAT %" / 100);
+
+        // Calculate the base cost component (excluding VAT, converted using currency factor)
+        // Base cost in source currency = (Amount - VAT Amount)
+        BaseCostAmount := GenJournalLine.Amount - GenJournalLine."VAT Amount";
+        // Base cost in LCY after conversion = Base * JobCurrencyFactor
+        BaseTotalCostLCY := Round(BaseCostAmount * JobCurrencyFactor);
+
+        // Calculate the converted Non-Deductible VAT amount
+        // The fix recalculates: NonDedVATAmountLCY := Round(GenJnlLine."Non-Deductible VAT Amount" * JobCurrencyFactor)
+        ConvertedNonDedVATAmountLCY := Round(NonDedVATAmount * JobCurrencyFactor);
+
+        // Expected Total Cost (LCY) = Base cost + Converted Non-Ded VAT
+        ExpectedTotalCostLCY := BaseTotalCostLCY + ConvertedNonDedVATAmountLCY;
+
+        // [WHEN] Post the General Journal Line
+        LibraryERM.PostGeneralJnlLine(GenJournalLine);
+
+        // [THEN] Find the Job Ledger Entry
+        JobLedgerEntry.SetRange("Document No.", DocumentNo);
+        JobLedgerEntry.SetRange("Job No.", Job."No.");
+        JobLedgerEntry.SetFilter("Unit Cost", '<%1', 0); // Cost entries have negative unit cost
+        JobLedgerEntry.FindFirst();
+
+        // [THEN] The Total Cost (LCY) should include Non-Deductible VAT amount converted correctly
+        // Without fix: Total Cost (LCY) = BaseTotalCostLCY + NonDedVATAmount (unconverted)
+        // With fix: Total Cost (LCY) = BaseTotalCostLCY + ConvertedNonDedVATAmountLCY
+        // The difference proves the fix is working
+        Assert.AreNotEqual(
+            BaseTotalCostLCY + NonDedVATAmount,
+            ExpectedTotalCostLCY,
+            'Test setup error: Unconverted and converted amounts should differ');
+
+        // Verify the Total Cost (LCY) in Job Ledger Entry uses the correctly converted Non-Deductible VAT amount
+        Assert.AreEqual(
+            ExpectedTotalCostLCY,
+            Abs(JobLedgerEntry."Total Cost (LCY)"),
+            IncorrectTotalCostLCYErr);
+
+        // Verify Unit Cost (LCY) = Total Cost (LCY) / Quantity
+        Assert.AreEqual(
+            Round(ExpectedTotalCostLCY / Quantity),
+            Abs(JobLedgerEntry."Unit Cost (LCY)"),
+            IncorrectUnitCostLCYErr);
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Non Ded. VAT Job Currency");
+        LibrarySetupStorage.Restore();
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Non Ded. VAT Job Currency");
+        LibraryNonDeductibleVAT.EnableNonDeductibleVAT();
+        LibraryERMCountryData.UpdatePurchasesPayablesSetup();
+        LibrarySetupStorage.Save(Database::"VAT Setup");
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Non Ded. VAT Job Currency");
+    end;
+
+    local procedure CreateGenJnlLineWithJobAndNonDedVAT(var GenJournalLine: Record "Gen. Journal Line"; GLAccountNo: Code[20]; Amount: Decimal; Quantity: Decimal; JobNo: Code[20]; JobTaskNo: Code[20]; CurrencyCode: Code[10]): Code[20]
+    var
+        GenJournalBatch: Record "Gen. Journal Batch";
+    begin
+        LibraryJournals.CreateGenJournalBatch(GenJournalBatch);
+        LibraryJournals.CreateGenJournalLine(
+            GenJournalLine,
+            GenJournalBatch."Journal Template Name",
+            GenJournalBatch.Name,
+            GenJournalLine."Document Type"::Invoice,
+            GenJournalLine."Account Type"::"G/L Account",
+            GLAccountNo,
+            GenJournalLine."Account Type"::"G/L Account",
+            '',
+            Amount);
+
+        if CurrencyCode <> '' then
+            GenJournalLine.Validate("Currency Code", CurrencyCode);
+
+        GenJournalLine.Validate("Job No.", JobNo);
+        GenJournalLine.Validate("Job Task No.", JobTaskNo);
+        GenJournalLine.Validate("Job Quantity", Quantity);
+        GenJournalLine.Modify(true);
+
+        exit(GenJournalLine."Document No.");
+    end;
+}

