+        QuantityPerLine: Decimal;
+        ExpectedMaterialCost: Decimal;
+        ExpectedMfgOverhead: Decimal;
+    begin
+        // [FEATURE] [Production Order] [Manufacturing Overhead]
+        // [SCENARIO] Manufacturing overhead is correctly calculated when a production order has multiple lines
+        // [GIVEN] A raw material item with unit cost = 100
