+        RawItem.Validate("Costing Method", RawItem."Costing Method"::FIFO);
+        RawItem.Validate("Unit Cost", RawItemUnitCost);
+        RawItem.Modify(true);
+
+        // [GIVEN] A finished goods item with 10% indirect cost and production BOM with 1 raw item
+        LibraryManufacturing.CreateCertifiedProductionBOM(ProductionBOMHeader, RawItem."No.", 1);
