+        FGItem.Validate("Indirect Cost %", IndirectCostPct);
+        FGItem.Modify(true);
+
+        // [GIVEN] A released production order with two lines for FG item, qty 10 each (total 20)
+        LibraryManufacturing.CreateProductionOrder(
+          ProductionOrder, ProductionOrder.Status::Released, ProductionOrder."Source Type"::Item, FGItem."No.", 0);
+        LibraryManufacturing.CreateProdOrderLine(
+          ProdOrderLine, ProductionOrder.Status, ProductionOrder."No.", FGItem."No.", '', '', QuantityPerLine);
+        LibraryManufacturing.CreateProdOrderLine(
+          ProdOrderLine, ProductionOrder.Status, ProductionOrder."No.", FGItem."No.", '', '', QuantityPerLine);
