+        // [WHEN] Refreshing the production order (without recalculating lines to keep both lines)
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, false, true, true, false);
+
+        // [THEN] Manufacturing overhead should be 10% of total material cost (2000), which is 200
+        ExpectedMaterialCost := 2 * QuantityPerLine * RawItemUnitCost; // 20 * 100 = 2000
+        ExpectedMfgOverhead := ExpectedMaterialCost * IndirectCostPct / 100; // 2000 * 10% = 200
+
+        SelectProdOrderLine(ProdOrderLine, ProductionOrder."No.", ProductionOrder.Status);
+        repeat
