+            MfgCostCalculationMgt.CalcProdOrderLineExpCost(
+              ProdOrderLine, ShareOfTotalCapCost, ExpMatCost, ExpCapDirCost, ExpSubDirCost, ExpCapOvhdCost, ExpMfgOvhdCost);
+        until ProdOrderLine.Next() = 0;
+
+        Assert.AreEqual(ExpectedMaterialCost, ExpMatCost, 'Expected Material Cost should be 2000');
+        Assert.AreEqual(ExpectedMfgOverhead, ExpMfgOvhdCost, 'Expected Manufacturing Overhead should be 200 (10% of 2000), not 300');
