+codeunit 134980 "Reminder Level Comm. Tests"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        Assert: Codeunit Assert;
+        IsInitialized: Boolean;
+
+    local procedure Initialize()
+    begin
+        LibraryVariableStorage.Clear();
+
+        if IsInitialized then
+            exit;
+
+        IsInitialized := true;
+        Commit();
+    end;
+
+    [Test]
+    [HandlerFunctions('ConfirmHandlerNo,LanguagesModalPageHandler')]
+    procedure AddTextForLanguageWithNoExistingAttachmentTexts()
+    var
+        ReminderTerms: Record "Reminder Terms";
+        ReminderLevel: Record "Reminder Level";
+        ReminderAttachmentText: Record "Reminder Attachment Text";
+        ReminderLevelCommunication: TestPage "Reminder Level Communication";
+        LanguageCode: Code[10];
+    begin
+        // [SCENARIO 0001] Adding text for a language in Reminder Level Communication when no attachment texts exist should not error
+        // [FEATURE] [Reminder] [Communication]
+        // Bug Repro: When user says No to the initial prompts for creating default texts, then clicks "Add text for language",
+        // the old code would use stale Rec."Reminder Attachment Text" (which is NULL) causing error 
+        // "A reminder attachment text cannot be created without an ID"
+        Initialize();
+
+        // [GIVEN] A reminder term and level exist without any attachment texts
+        LibraryERM.CreateReminderTerms(ReminderTerms);
+        LibraryERM.CreateReminderLevel(ReminderLevel, ReminderTerms.Code);
+
+        // [GIVEN] The Reminder Level has no attachment text (null GUID)
+        Assert.IsTrue(IsNullGuid(ReminderLevel."Reminder Attachment Text"), 'Reminder Level should have no attachment text initially');
+        Assert.IsTrue(IsNullGuid(ReminderLevel."Reminder Email Text"), 'Reminder Level should have no email text initially');
+
+        // [GIVEN] A valid language code for creating new communication text
+        LanguageCode := GetOrCreateLanguageCode();
+        LibraryVariableStorage.Enqueue(LanguageCode);
+
+        // [WHEN] Opening the Reminder Level Communication page (user says No to default text creation prompts via ConfirmHandlerNo)
+        // [WHEN] Then invoking "Add text for language" action and selecting a language
+        ReminderLevelCommunication.OpenEdit();
+        ReminderLevelCommunication.GoToRecord(ReminderLevel);
+        ReminderLevelCommunication."Add New Language".Invoke();
+
+        // [THEN] No error should occur - previously would error with "A reminder attachment text cannot be created without an ID"
+        // because the old code used stale Rec."Reminder Attachment Text" instead of fetching fresh data from database
+        ReminderLevelCommunication.Close();
+
+        // [THEN] Verify the attachment text was created for the selected language
+        ReminderLevel.Get(ReminderTerms.Code, ReminderLevel."No.");
+        Assert.IsFalse(IsNullGuid(ReminderLevel."Reminder Attachment Text"), 'Reminder Level should now have an attachment text');
+        ReminderAttachmentText.SetRange(Id, ReminderLevel."Reminder Attachment Text");
+        ReminderAttachmentText.SetRange("Language Code", LanguageCode);
+        Assert.IsTrue(ReminderAttachmentText.FindFirst(), 'Reminder Attachment Text should exist for the selected language');
+    end;
+
+    local procedure GetOrCreateLanguageCode(): Code[10]
+    var
+        Language: Record "Language";
+    begin
+        // Try to find an existing language
+        if Language.FindFirst() then
+            exit(Language.Code);
+
+        // Create ENU language if none exists
+        Language.Init();
+        Language.Code := 'ENU';
+        Language."Windows Language ID" := 1033;
+        Language.Name := 'English (United States)';
+        Language.Insert();
+        exit(Language.Code);
+    end;
+
+    [ConfirmHandler]
+    procedure ConfirmHandlerNo(Question: Text[1024]; var Reply: Boolean)
+    begin
+        // Reply No to prompts about creating default attachment/email texts
+        // This simulates the user scenario where they decline the initial prompts
+        Reply := false;
+    end;
+
+    [ModalPageHandler]
+    procedure LanguagesModalPageHandler(var Languages: TestPage "Languages")
+    var
+        LanguageCode: Code[10];
+    begin
+        // Select the language code that was enqueued
+        LanguageCode := CopyStr(LibraryVariableStorage.DequeueText(), 1, 10);
+        Languages.FindFirstField(Code, LanguageCode);
+        Languages.OK().Invoke();
+    end;
+}

