+        DimensionValue: array[3] of Record "Dimension Value";
+        SalespersonPurchaser: Record "Salesperson/Purchaser";
+        DefaultDimension: Record "Default Dimension";
+        Item: Record Item;
+        LocationFrom: Record Location;
+        LocationTo: Record Location;
+        ItemJournalTemplate: Record "Item Journal Template";
+        ItemJournalBatch: Record "Item Journal Batch";
+        ItemJournalLine: Record "Item Journal Line";
+    begin
+        // [SCENARIO] In the Item Reclassification Journal, the "New Dimension Value Code" should not be overwritten 
+        // when a Salesperson Code with a default dimension is added to the line.
+        Initialize();
+
+        // [GIVEN] Create global dimension 1 values "V1", "V2", and "V3".
+        LibraryDimension.CreateDimensionValue(DimensionValue[1], LibraryERM.GetGlobalDimensionCode(1));
+        LibraryDimension.CreateDimensionValue(DimensionValue[2], LibraryERM.GetGlobalDimensionCode(1));
+        LibraryDimension.CreateDimensionValue(DimensionValue[3], LibraryERM.GetGlobalDimensionCode(1));
+
+        // [GIVEN] Create Item.
+        LibraryInventory.CreateItem(Item);
+
+        // [GIVEN] Assign value "V1" to location "FROM".
+        CreateLocationWithDefaultDimension(LocationFrom, DimensionValue[1]);
+
+        // [GIVEN] Assign value "V2" to location "TO".
+        CreateLocationWithDefaultDimension(LocationTo, DimensionValue[2]);
+
+        // [GIVEN] Create Salesperson with default dimension value "V3".
+        LibrarySales.CreateSalesperson(SalespersonPurchaser);
+        LibraryDimension.CreateDefaultDimension(
+            DefaultDimension, Database::"Salesperson/Purchaser", SalespersonPurchaser.Code,
+            DimensionValue[3]."Dimension Code", DimensionValue[3].Code);
+
+        // [GIVEN] Create item reclassification journal line.
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Transfer);
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalTemplate.Type, ItemJournalTemplate.Name);
+        LibraryInventory.CreateItemJnlLineWithNoItem(
+            ItemJournalLine, ItemJournalBatch, ItemJournalTemplate.Name, ItemJournalBatch.Name, "Item Ledger Entry Type"::Transfer);
+        ItemJournalLine.Validate("Item No.", Item."No.");
+
+        // [GIVEN] Set "Location Code" = "FROM" on the item journal line.
+        // [GIVEN] Verify that "Shortcut Dimension 1 Code" = "V1".
+        ItemJournalLine.Validate("Location Code", LocationFrom.Code);
+        ItemJournalLine.TestField("Shortcut Dimension 1 Code", DimensionValue[1].Code);
+
+        // [GIVEN] Set "New Location Code" = "TO".
+        // [GIVEN] Verify that "New Shortcut Dimension 1 Code" = "V2".
+        ItemJournalLine.Validate("New Location Code", LocationTo.Code);
+        ItemJournalLine.TestField("New Shortcut Dimension 1 Code", DimensionValue[2].Code);
+
+        // [WHEN] Add a Salesperson Code with default dimension value "V3" to the line.
+        ItemJournalLine.Validate("Salespers./Purch. Code", SalespersonPurchaser.Code);
+
+        // [THEN] "New Shortcut Dimension 1 Code" should remain "V2" (from New Location), not changed to "V3".
+        ItemJournalLine.TestField("New Shortcut Dimension 1 Code", DimensionValue[2].Code);
+
+        // [THEN] "Shortcut Dimension 1 Code" is updated to "V3" (salesperson dimension takes priority for source dimension).
+        ItemJournalLine.TestField("Shortcut Dimension 1 Code", DimensionValue[3].Code);
+
+        // [THEN] "New Dimension Set ID" includes value "V2".
+        VerifyDimensionValue(ItemJournalLine."New Dimension Set ID", DimensionValue[2]);
+
+        // [THEN] "Dimension Set ID" includes value "V3".
+        VerifyDimensionValue(ItemJournalLine."Dimension Set ID", DimensionValue[3]);
+    end;
+
