+        // [GIVEN] Create Unit of Measure Code.
+        LibraryInventory.CreateUnitOfMeasureCode(UnitOfMeasure);
+
+        // [GIVEN] Create a Component Item.
+        CreateItemWithReorderPolicy(CompItem, UnitOfMeasure, ItemUnitOfMeasure, CompItem."Replenishment System"::Purchase, CompItem."Reordering Policy"::" ");
+
+        // [GIVEN] Create Production Item.
+        CreateItemWithReorderPolicy(ProdItem, UnitOfMeasure, ItemUnitOfMeasure, ProdItem."Replenishment System"::"Prod. Order", ProdItem."Reordering Policy"::Order);
+
+        // [GIVEN] Create Production BOM Header.
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ProdItem."Base Unit of Measure");
+
+        // [GIVEN] Generate distinct Position values.
+        Position1 := 'POS-001';
+        Position2 := 'POS-002';
+
+        // [GIVEN] Create first Production BOM Line for Component Item with Position1.
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader,
+            ProductionBOMLine[1],
+            '',
+            ProductionBOMLine[1].Type::Item,
+            CompItem."No.",
+            1);
+        ProductionBOMLine[1].Validate(Position, Position1);
+        ProductionBOMLine[1].Modify(true);
+
+        // [GIVEN] Create second Production BOM Line for SAME Component Item with Position2.
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader,
+            ProductionBOMLine[2],
+            '',
+            ProductionBOMLine[2].Type::Item,
+            CompItem."No.",
+            1);
+        ProductionBOMLine[2].Validate(Position, Position2);
+        ProductionBOMLine[2].Modify(true);
+
+        // [GIVEN] Create Comment Line for first Production BOM Line (Position1).
+        LibraryManufacturing.CreateProductionBOMCommentLine(ProductionBOMLine[1]);
+        ProductionBOMCommentLine[1].SetRange("Production BOM No.", ProductionBOMHeader."No.");
+        ProductionBOMCommentLine[1].SetRange("BOM Line No.", ProductionBOMLine[1]."Line No.");
+        ProductionBOMCommentLine[1].FindFirst();
+
+        // [GIVEN] Create Comment Line for second Production BOM Line (Position2).
+        LibraryManufacturing.CreateProductionBOMCommentLine(ProductionBOMLine[2]);
+        ProductionBOMCommentLine[2].SetRange("Production BOM No.", ProductionBOMHeader."No.");
+        ProductionBOMCommentLine[2].SetRange("BOM Line No.", ProductionBOMLine[2]."Line No.");
+        ProductionBOMCommentLine[2].FindFirst();
+
+        // [GIVEN] Update Production BOM Status to Certified.
+        LibraryManufacturing.UpdateProductionBOMStatus(ProductionBOMHeader, ProductionBOMHeader.Status::Certified);
+
+        // [GIVEN] Validate Production BOM No. in Production Item.
+        ProdItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ProdItem.Modify(true);
+
+        // [GIVEN] Create Sales Order for the Production Item.
+        CreateSalesOrder(Salesheader, ProdItem);
+        LibrarySales.ReleaseSalesDocument(Salesheader);
+
+        // [GIVEN] Run Calculate Regenerative Plan.
+        RunCalculateRegenerativePlan(ProdItem."No.", '');
+
+        // [GIVEN] Accept Action Message on Requisition Line.
+        AcceptActionMessageOnReqLine(RequisitionLine, ProdItem."No.");
+
+        // [WHEN] Run Carry Out Action Plan to create Planned Prod Order.
+        CarryOutActionPlanForPlannedProdOrder(RequisitionLine);
+
+        // [THEN] Find the two Prod Order Component lines for the same Component Item.
+        ProdOrderComponent.SetRange(Status, ProdOrderComponent.Status::Planned);
+        ProdOrderComponent.SetRange("Item No.", CompItem."No.");
+        Assert.AreEqual(2, ProdOrderComponent.Count(), 'Expected two component lines for the same item with different positions');
+
+        // [THEN] Verify that the component line with Position1 has the comment from BOM Line 1.
+        ProdOrderComponent.SetRange(Position, Position1);
+        ProdOrderComponent.FindFirst();
+        ProdOrderCompCmtLine.SetRange(Status, ProdOrderCompCmtLine.Status::Planned);
+        ProdOrderCompCmtLine.SetRange("Prod. Order No.", ProdOrderComponent."Prod. Order No.");
+        ProdOrderCompCmtLine.SetRange("Prod. Order Line No.", ProdOrderComponent."Prod. Order Line No.");
+        ProdOrderCompCmtLine.SetRange("Prod. Order BOM Line No.", ProdOrderComponent."Line No.");
+        Assert.IsTrue(ProdOrderCompCmtLine.FindFirst(), 'Comment should exist for component line with Position1');
+        Assert.AreEqual(
+            ProductionBOMCommentLine[1].Comment,
+            ProdOrderCompCmtLine.Comment,
+            'Component with Position1 should have comment from BOM Line 1');
+
+        // [THEN] Verify that the component line with Position2 has the comment from BOM Line 2.
+        ProdOrderComponent.SetRange(Position, Position2);
+        ProdOrderComponent.FindFirst();
+        ProdOrderCompCmtLine.SetRange("Prod. Order BOM Line No.", ProdOrderComponent."Line No.");
+        Assert.IsTrue(ProdOrderCompCmtLine.FindFirst(), 'Comment should exist for component line with Position2');
+        Assert.AreEqual(
+            ProductionBOMCommentLine[2].Comment,
+            ProdOrderCompCmtLine.Comment,
+            'Component with Position2 should have comment from BOM Line 2');
+    end;
