+        PostItemJnlLineWithLotAndExpiration(Item."No.", Location.Code, Bin[1].Code, 'LOT01', 434.97616, CalcDate('<+1Y>', WorkDate()));
+        PostItemJnlLineWithLotAndExpiration(Item."No.", Location.Code, Bin[1].Code, 'LOT03', 17.3126, CalcDate('<-3M>', WorkDate()));
+        PostItemJnlLineWithLotAndExpiration(Item."No.", Location.Code, Bin[1].Code, 'LOT06', 17.0373, CalcDate('<-3M>', WorkDate()));
+        PostItemJnlLineWithLotAndExpiration(Item."No.", Location.Code, Bin[2].Code, 'LOT01', 4.13394, CalcDate('<-3M>', WorkDate()));
+        PostItemJnlLineWithLotAndExpiration(Item."No.", Location.Code, Bin[2].Code, 'LOT02', 4.34355, CalcDate('<+1Y>', WorkDate()));
+        PostItemJnlLineWithLotAndExpiration(Item."No.", Location.Code, Bin[2].Code, 'LOT03', 151.33333, CalcDate('<-3M>', WorkDate()));
+        PostItemJnlLineWithLotAndExpiration(Item."No.", Location.Code, Bin[2].Code, 'LOT04', 40.01221, CalcDate('<-6M>', WorkDate()));
+        PostItemJnlLineWithLotAndExpiration(Item."No.", Location.Code, Bin[3].Code, 'LOT02', 1.78787, CalcDate('<-8M>', WorkDate()));
+        PostItemJnlLineWithLotAndExpiration(Item."No.", Location.Code, Bin[3].Code, 'LOT03', 42.73313, CalcDate('<-3M>', WorkDate()));
+        PostItemJnlLineWithLotAndExpiration(Item."No.", Location.Code, Bin[3].Code, 'LOT05', 4.013, CalcDate('<-5M>', WorkDate()));
+
+        // [GIVEN] Sales order for 248 PACK
+        SalesQty := 248;
+        LibrarySales.CreateSalesDocumentWithItem(
+            SalesHeader, SalesLine, SalesHeader."Document Type"::Order, LibrarySales.CreateCustomerNo(),
