+codeunit 137932 "SCM Whse Pick FEFO Reservation"
+{
+    // [FEATURE] [Warehouse Pick] [FEFO] [Reservation] [Item Tracking]
+    // Tests for registering warehouse pick with FEFO and non-specific reservations
+
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        IsInitialized := false;
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryItemTracking: Codeunit "Library - Item Tracking";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        LibraryRandom: Codeunit "Library - Random";
+        IsInitialized: Boolean;
+        TrackingAction: Option SerialNo,LotNo,All,SelectEntries,AssignLotNo;
+
+    [Test]
+    [HandlerFunctions('ItemTrackingPageHandler')]
+    procedure RegisterPickWithFEFOAndNonSpecificReservation()
+    var
+        Location: Record Location;
+        WarehouseEmployee: Record "Warehouse Employee";
+        Item: Record Item;
+        ItemTrackingCode: Record "Item Tracking Code";
+        Bin: array[2] of Record Bin;
+        SalesHeader: array[2] of Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        WarehouseShipmentHeader: Record "Warehouse Shipment Header";
+        WarehouseActivityHeader: Record "Warehouse Activity Header";
+        WarehouseActivityLine: Record "Warehouse Activity Line";
+        LotNo: array[2] of Code[50];
+        Quantity: Decimal;
+    begin
+        // [FEATURE] [Warehouse Pick] [FEFO] [Reservation] [Item Tracking]
+        // [SCENARIO] Register pick for item with FEFO, item tracking, and non-specific reservations should succeed
+        // when another sales order has already reserved from the same inventory without specific lot tracking.
+        Initialize();
+        Quantity := LibraryRandom.RandIntInRange(10, 20);
+
+        // [GIVEN] Location with Pick According to FEFO, Require Shipment, Require Pick and Bin Mandatory
+        CreateLocationWithFEFO(Location);
+        LibraryWarehouse.CreateNumberOfBins(Location.Code, '', '', 3, false);
+        LibraryWarehouse.FindBin(Bin[1], Location.Code, '', 1);
+        LibraryWarehouse.FindBin(Bin[2], Location.Code, '', 2);
+        Location.Validate("Shipment Bin Code", Bin[2].Code);
+        Location.Modify(true);
+
+        WarehouseEmployee.DeleteAll();
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, Location.Code, true);
+
+        // [GIVEN] Item with Item Tracking Code having Lot Tracking and Expiration Dates enabled
+        CreateItemTrackingCodeWithExpiration(ItemTrackingCode);
+        CreateItemWithItemTrackingCode(Item, ItemTrackingCode.Code);
+
+        // [GIVEN] Two lots in inventory with different expiration dates
+        // Lot 1 expires earlier (first to be picked by FEFO)
+        LotNo[1] := LibraryUtility.GenerateGUID();
+        PostItemJournalLineWithLotNoExpiration(
+            Item."No.", Location.Code, Bin[1].Code, LotNo[1], Quantity, CalcDate('<+1Y>', WorkDate()));
+
+        // Lot 2 expires later
+        LotNo[2] := LibraryUtility.GenerateGUID();
+        PostItemJournalLineWithLotNoExpiration(
+            Item."No.", Location.Code, Bin[1].Code, LotNo[2], Quantity, CalcDate('<+2Y>', WorkDate()));
+
+        // [GIVEN] First Sales Order with non-specific reservation (reserved without specifying lot)
+        CreateSalesOrderWithNonSpecificReservation(SalesHeader[1], SalesLine, Item."No.", Location.Code, Quantity);
+
+        // [GIVEN] Second Sales Order with non-specific reservation (reserved without specifying lot)
+        CreateSalesOrderWithNonSpecificReservation(SalesHeader[2], SalesLine, Item."No.", Location.Code, Quantity);
+
+        // [GIVEN] Create Warehouse Shipment from second Sales Order
+        LibraryWarehouse.CreateWhseShipmentFromSO(SalesHeader[2]);
+        FindWarehouseShipmentHeader(WarehouseShipmentHeader, SalesHeader[2]."No.");
+        LibraryWarehouse.ReleaseWarehouseShipment(WarehouseShipmentHeader);
+
+        // [GIVEN] Create Pick from Warehouse Shipment
+        LibraryWarehouse.CreatePick(WarehouseShipmentHeader);
+
+        // [WHEN] Register the warehouse pick
+        FindWarehouseActivityHeader(WarehouseActivityHeader, SalesHeader[2]."No.", WarehouseActivityLine."Activity Type"::Pick);
+
+        // [THEN] Pick registration should succeed without error
+        // Before the fix, this would fail with "Lot No. is not available on inventory or it has already been reserved for another document"
+        LibraryWarehouse.RegisterWhseActivity(WarehouseActivityHeader);
+
+        // [THEN] Verify pick was registered successfully by checking registered warehouse activity line exists
+        VerifyRegisteredWhseActivityExists(SalesHeader[2]."No.", Location.Code, Item."No.");
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Whse Pick FEFO Reservation");
+        LibraryVariableStorage.Clear();
+
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM Whse Pick FEFO Reservation");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        IsInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM Whse Pick FEFO Reservation");
+    end;
+
+    local procedure CreateLocationWithFEFO(var Location: Record Location)
+    begin
+        LibraryWarehouse.CreateLocationWMS(Location, true, false, true, false, true);
+        Location.Validate("Pick According to FEFO", true);
+        Location.Modify(true);
+    end;
+
+    local procedure CreateItemTrackingCodeWithExpiration(var ItemTrackingCode: Record "Item Tracking Code")
+    begin
+        LibraryItemTracking.CreateItemTrackingCodeWithExpirationDate(ItemTrackingCode, false, true);
+    end;
+
+    local procedure CreateItemWithItemTrackingCode(var Item: Record Item; ItemTrackingCodeCode: Code[10])
+    begin
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Item Tracking Code", ItemTrackingCodeCode);
+        Item.Modify(true);
+    end;
+
+    local procedure PostItemJournalLineWithLotNoExpiration(ItemNo: Code[20]; LocationCode: Code[10]; BinCode: Code[20]; LotNo: Code[50]; Qty: Decimal; ExpirationDate: Date)
+    var
+        ItemJournalLine: Record "Item Journal Line";
+        ReservationEntry: Record "Reservation Entry";
+    begin
+        LibraryInventory.CreateItemJournalLineInItemTemplate(ItemJournalLine, ItemNo, LocationCode, BinCode, Qty);
+        LibraryVariableStorage.Enqueue(TrackingAction::AssignLotNo);
+        LibraryVariableStorage.Enqueue(LotNo);
+        LibraryVariableStorage.Enqueue(Qty);
+        ItemJournalLine.OpenItemTrackingLines(false);
+        LibraryVariableStorage.AssertEmpty();
+
+        ReservationEntry.SetRange("Item No.", ItemNo);
+        ReservationEntry.SetRange("Lot No.", LotNo);
+        ReservationEntry.SetRange("Expiration Date", 0D);
+        ReservationEntry.ModifyAll("Expiration Date", ExpirationDate, true);
+
+        LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+    end;
+
+    local procedure CreateSalesOrderWithNonSpecificReservation(var SalesHeader: Record "Sales Header"; var SalesLine: Record "Sales Line"; ItemNo: Code[20]; LocationCode: Code[10]; Quantity: Decimal)
+    begin
+        LibrarySales.CreateSalesDocumentWithItem(
+            SalesHeader, SalesLine, SalesHeader."Document Type"::Order, '', ItemNo, Quantity, LocationCode, 0D);
+        LibrarySales.AutoReserveSalesLine(SalesLine);
+        LibrarySales.ReleaseSalesDocument(SalesHeader);
+    end;
+
+    local procedure FindWarehouseShipmentHeader(var WarehouseShipmentHeader: Record "Warehouse Shipment Header"; SourceNo: Code[20])
+    var
+        WarehouseShipmentLine: Record "Warehouse Shipment Line";
+    begin
