+codeunit 134409 "ERM Sales Inv Bill-to Contact"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Sales] [Bill-to Contact]
+        isInitialized := false;
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        LibraryMarketing: Codeunit "Library - Marketing";
+        LibraryTemplates: Codeunit "Library - Templates";
+        isInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('CustomerLookupPageHandler,ConfirmHandlerYes')]
+    procedure BillToContactInfoUpdatedOnLookupBillToName()
+    var
+        Customer1: Record Customer;
+        Customer2: Record Customer;
+        Contact1: Record Contact;
+        Contact2: Record Contact;
+        SalesHeader: Record "Sales Header";
+        SalesInvoice: TestPage "Sales Invoice";
+    begin
+        // [FEATURE] [UI]
+        // [SCENARIO 534567] When user changes Bill-to customer via lookup on Bill-to Name field, the Bill-to contact phone and email should update
+        Initialize();
+
+        // [GIVEN] Customer "C1" with contact having phone = "111111111", mobile phone = "222222222" and email = "contact1@mail.com"
+        CreateCustomerWithContact(Customer1, Contact1, '111111111', '222222222', 'contact1@mail.com');
+
+        // [GIVEN] Customer "C2" with contact having phone = "333333333", mobile phone = "444444444" and email = "contact2@mail.com"
+        CreateCustomerWithContact(Customer2, Contact2, '333333333', '444444444', 'contact2@mail.com');
+
+        // [GIVEN] Sales Invoice created for Customer "C1"
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Invoice, Customer1."No.");
+
+        // [GIVEN] Sales Invoice page opened
+        SalesInvoice.Trap();
+        Page.Run(Page::"Sales Invoice", SalesHeader);
+
+        // [WHEN] User uses lookup on "Bill-to Name" field and selects Customer "C2"
+        LibraryVariableStorage.Enqueue(Customer2.Name);
+        LibraryVariableStorage.Enqueue(true); // Confirm change
+        SalesInvoice."Bill-to Name".Lookup();
+
+        // [THEN] Bill-to Contact Phone No. shows contact2's phone number "333333333"
+        SalesInvoice.BillToContactPhoneNo.AssertEquals(Contact2."Phone No.");
+
+        // [THEN] Bill-to Contact Mobile Phone No. shows contact2's mobile phone "444444444"
+        SalesInvoice.BillToContactMobilePhoneNo.AssertEquals(Contact2."Mobile Phone No.");
+
+        // [THEN] Bill-to Contact Email shows contact2's email "contact2@mail.com"
+        SalesInvoice.BillToContactEmail.AssertEquals(Contact2."E-Mail");
+
+        LibraryVariableStorage.AssertEmpty();
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"ERM Sales Inv Bill-to Contact");
+        LibraryVariableStorage.Clear();
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"ERM Sales Inv Bill-to Contact");
+
+        LibraryTemplates.EnableTemplatesFeature();
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        isInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"ERM Sales Inv Bill-to Contact");
+    end;
+
+    local procedure CreateCustomerWithContact(var Customer: Record Customer; var Contact: Record Contact; PhoneNo: Text[30]; MobilePhoneNo: Text[30]; Email: Text[80])
+    begin
+        LibraryMarketing.CreateContactWithCustomer(Contact, Customer);
+        Contact.Validate("Phone No.", PhoneNo);
+        Contact.Validate("Mobile Phone No.", MobilePhoneNo);
+        Contact.Validate("E-Mail", Email);
+        Contact.Modify(true);
+        Customer.Validate("Primary Contact No.", Contact."No.");
+        Customer.Modify(true);
+    end;
+
+    [ModalPageHandler]
+    procedure CustomerLookupPageHandler(var CustomerLookup: TestPage "Customer Lookup")
+    begin
+        CustomerLookup.Filter.SetFilter(Name, LibraryVariableStorage.DequeueText());
+        CustomerLookup.OK().Invoke();
+    end;
+
+    [ConfirmHandler]
+    procedure ConfirmHandlerYes(Question: Text[1024]; var Reply: Boolean)
+    begin
+        Reply := LibraryVariableStorage.DequeueBoolean();
+    end;
+}

