+    [Test]
+    procedure ChangingItemNoOnContractLineDisconnectsSubscriptionLine()
+    var
+        Customer: Record Customer;
+        CustomerContract: Record "Customer Subscription Contract";
+        CustomerContractLine: Record "Cust. Sub. Contract Line";
+        SubscriptionLine: Record "Subscription Line";
+        Item1: Record Item;
+        Item2: Record Item;
+        OriginalSubscriptionLineEntryNo: Integer;
+    begin
+        // [SCENARIO] When changing the Item No. on a manually created customer contract line, the connection 
+        // to the contract should be revoked in the subscription line to prevent it from being invoiced.
+        // Since the subscription line was "Created in Contract line", changing the item should delete the old
+        // subscription line and create a new one for the new item.
+
+        // [GIVEN] A Customer Subscription Contract with a manually added contract line for Item1
+        Initialize();
+        ContractTestLibrary.CreateCustomer(Customer);
+        ContractTestLibrary.CreateCustomerContract(CustomerContract, Customer."No.");
+
+        // Create two items with Subscription Option = Service Commitment Item
+        ContractTestLibrary.CreateItemForServiceObject(Item1, false, Enum::"Item Service Commitment Type"::"Service Commitment Item", Enum::"Item Type"::"Non-Inventory");
+        ContractTestLibrary.CreateItemForServiceObject(Item2, false, Enum::"Item Service Commitment Type"::"Service Commitment Item", Enum::"Item Type"::"Non-Inventory");
+
+        // Add a contract line for Item1 manually
+        ContractTestLibrary.InitCustomerContractLine(CustomerContract, CustomerContractLine);
+        CustomerContractLine."Contract Line Type" := CustomerContractLine."Contract Line Type"::Item;
+        CustomerContractLine.Validate("No.", Item1."No.");
+        CustomerContractLine.Insert(false);
+
+        // Verify subscription line is connected to the contract
+        SubscriptionLine.Get(CustomerContractLine."Subscription Line Entry No.");
+        OriginalSubscriptionLineEntryNo := SubscriptionLine."Entry No.";
+        Assert.AreEqual(CustomerContract."No.", SubscriptionLine."Subscription Contract No.", 'Subscription Line should be connected to the contract');
+        Assert.AreEqual(CustomerContractLine."Line No.", SubscriptionLine."Subscription Contract Line No.", 'Subscription Line should reference the contract line');
+        Assert.IsTrue(SubscriptionLine."Created in Contract line", 'Subscription Line should be marked as created in contract line');
+
+        // [WHEN] The Item No. is changed from Item1 to Item2 on the contract line
+        CustomerContractLine.Validate("No.", Item2."No.");
+        CustomerContractLine.Modify(true);
+
+        // [THEN] The original subscription line (for Item1) should be deleted since it was "Created in Contract line"
+        Assert.IsFalse(SubscriptionLine.Get(OriginalSubscriptionLineEntryNo), 'Original Subscription Line for Item1 should be deleted');
+
+        // [THEN] The contract line should now have a new subscription line for Item2
+        CustomerContractLine.Get(CustomerContractLine."Subscription Contract No.", CustomerContractLine."Line No.");
+        Assert.AreNotEqual(0, CustomerContractLine."Subscription Line Entry No.", 'Contract line should have a new Subscription Line Entry No.');
+        Assert.AreNotEqual(OriginalSubscriptionLineEntryNo, CustomerContractLine."Subscription Line Entry No.", 'New Subscription Line should have different Entry No.');
+
+        // Verify the new subscription line is connected to the contract
+        SubscriptionLine.Get(CustomerContractLine."Subscription Line Entry No.");
+        Assert.AreEqual(CustomerContract."No.", SubscriptionLine."Subscription Contract No.", 'New Subscription Line should be connected to the contract');
+        Assert.AreEqual(CustomerContractLine."Line No.", SubscriptionLine."Subscription Contract Line No.", 'New Subscription Line should reference the contract line');
+    end;
+
     #endregion Tests

     #region Procedures

